export type Currency = 'CUP' | 'USD';
export type PaymentMethod = 'Efectivo' | 'Transferencia';
export type ReceptionType = 'Consignación' | 'Compra Directa';

export interface GroupingPrice {
  id: string;
  label: string;
  quantity: number;
  price: number;
  currency: Currency;
  minOrderQuantity?: number;
}

export interface StoreConfig {
  logoUrl: string;
  storeName: string;
  aboutText: string;
  address: string;
  phone: string;
  email: string;
  facebookUrl: string;
  instagramUrl: string;
  websiteUrl: string;
}

export interface ReceptionLot {
  id: string;
  date: string;
  quantityReceived: number;
  currentStock: number;
  unitCost: number;
  transportCost: number;
  totalInvestment: number; 
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  description: string;
  categoryId: string;
  supplierId: string;
  receptionType: ReceptionType;
  unitPrice: number;
  unitCurrency: Currency;
  costPrice: number; 
  groupings: GroupingPrice[];
  stock: number;
  minStock: number;
  expiryDate: string;
  receivedDate: string;
  isOffer?: boolean;
  lots: ReceptionLot[];
}

export interface Contact {
  id: string;
  name: string;
  contactName: string;
  phone: string;
  email: string;
  address: string;
  type: 'Proveedor' | 'Cliente';
  isConsignee?: boolean;
  pendingBalanceCup: number;
  pendingBalanceUsd: number;
  salesHistoryIds?: string[]; // IDs de transacciones asociadas para consignación
}

export interface SaleItem {
  id: string;
  productId: string;
  productName: string;
  groupingId?: string; 
  groupingLabel?: string;
  quantity: number;
  price: number;
  total: number;
  currency: Currency;
  unitQuantity: number;
}

export interface Transaction {
  id: string;
  date: string;
  clientId: string;
  clientName: string;
  items: SaleItem[];
  totalCup: number;
  totalUsd: number;
  paymentMethod: PaymentMethod;
  status: 'Solicitud' | 'Despachado' | 'Anulado';
  invoiceNumber: string;
  isPaidToSupplier?: boolean;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'error' | 'success';
  date: string;
  read: boolean;
}

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  Minus, FileText, History, Info, Facebook, Instagram, Mail, Star, Globe, Settings, ImageIcon, Copy, Share2, TrendingUp, Percent,
  Users, MailCheck, Receipt
} from 'lucide-react';
import { LOGO_URL, STORE_NAME } from './constants';
import { generateSocialMediaPost } from './services/geminiService';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v6_products',
  CONTACTS: 'pati_v6_contacts',
  TRANSACTIONS: 'pati_v6_transactions',
  CONFIG: 'pati_v6_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "https://i.ibb.co/L6S9Dkz/pati-logo.jpg",
  storeName: "PaTí",
  aboutText: "Tienda de excelencia para productos frescos y en consignación. Calidad garantizada PaTí.",
  address: "Calle Real #123, Habana Vieja",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/mercadopati",
  instagramUrl: "https://instagram.com/mercadopati",
  websiteUrl: "https://mercadopati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'reception' | 'edit'}>({show: false, mode: 'reception'});
  const [showContactModal, setShowContactModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [socialPost, setSocialPost] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');
  const [selectedCurrency, setSelectedCurrency] = useState<Currency>('CUP');

  // Persistence
  useEffect(() => {
    const load = () => {
      const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
      const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
      const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
      const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

      if (p) setProducts(JSON.parse(p));
      if (c) setContacts(JSON.parse(c));
      if (t) setTransactions(JSON.parse(t));
      if (cfg) setConfig(JSON.parse(cfg));

      setIsDataReady(true);
    };
    load();
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  // Expiry & Stock Logic
  useEffect(() => {
    const newNotifs: Notification[] = [];
    const sixtyDaysFromNow = new Date();
    sixtyDaysFromNow.setDate(sixtyDaysFromNow.getDate() + 60);

    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Crítico', message: `${p.name} tiene solo ${p.stock} unidades.`, type: 'error', date: new Date().toISOString(), read: false });
      }
      if (p.expiryDate) {
        const exp = new Date(p.expiryDate);
        if (exp <= sixtyDaysFromNow && exp > new Date()) {
          newNotifs.push({ id: `exp-${p.id}`, title: 'Próximo a Vencer', message: `${p.name} vence en menos de 60 días (${p.expiryDate}).`, type: 'warning', date: new Date().toISOString(), read: false });
        }
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // Consignment Settlement Logic
  const settleSupplier = (supplierId: string) => {
    const supplier = contacts.find(c => c.id === supplierId);
    if (!supplier) return;

    // In a real app, this would deduct from a pool of sold items
    const updatedContacts = contacts.map(c => {
      if (c.id === supplierId) {
        return { ...c, pendingBalanceCup: 0, pendingBalanceUsd: 0 };
      }
      return c;
    });
    setContacts(updatedContacts);
    alert(`Se ha liquidado la deuda con ${supplier.name}`);
  };

  const addToCart = (p: Product, grouping?: GroupingPrice) => {
    const price = grouping ? grouping.price : p.unitPrice;
    const currency = grouping ? grouping.currency : p.unitCurrency;
    const label = grouping ? grouping.label : 'Unidad';
    const unitQty = grouping ? grouping.quantity : 1;

    if (p.stock < unitQty) {
      alert("Existencia insuficiente.");
      return;
    }

    const existingIdx = cart.findIndex(i => i.productId === p.id && i.groupingId === grouping?.id);
    if (existingIdx > -1) {
      const newCart = [...cart];
      newCart[existingIdx].quantity += 1;
      newCart[existingIdx].total = newCart[existingIdx].quantity * newCart[existingIdx].price;
      setCart(newCart);
    } else {
      setCart([...cart, {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: label, quantity: 1,
        price, total: price, currency, unitQuantity: unitQty
      }]);
    }
  };

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);

    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(),
      clientId: 'Gral', clientName: 'Consumidor Final', items: [...cart],
      totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'REQ' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };

    setTransactions([newTx, ...transactions]);

    if (status === 'Despachado') {
      const updatedProducts = products.map(p => {
        const soldItems = cart.filter(i => i.productId === p.id);
        const totalSoldUnits = soldItems.reduce((acc, i) => acc + (i.quantity * i.unitQuantity), 0);
        return { ...p, stock: Math.max(0, p.stock - totalSoldUnits) };
      });
      setProducts(updatedProducts);

      // Update supplier balances for consignment
      const updatedContacts = [...contacts];
      cart.forEach(item => {
        const prod = products.find(p => p.id === item.productId);
        if (prod && prod.receptionType === 'Consignación') {
          const suppIdx = updatedContacts.findIndex(c => c.id === prod.supplierId);
          if (suppIdx > -1) {
             const costToSupplier = prod.costPrice * item.unitQuantity * item.quantity;
             if (item.currency === 'CUP') updatedContacts[suppIdx].pendingBalanceCup += costToSupplier;
             // Logic for USD could go here
          }
        }
      });
      setContacts(updatedContacts);
    }
    setCart([]);
    setSelectedInvoice(newTx);
  };

  const ProductFormContent = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', receptionType: 'Consignación', unitCurrency: 'CUP', groupings: [],
      stock: 0, minStock: 5, unitPrice: 0, costPrice: 0, expiryDate: '', lots: []
    });
    const [transportCost, setTransportCost] = useState(0);
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' });

    const margin = useMemo(() => {
      if (!formData.unitPrice || !formData.costPrice || formData.unitPrice <= 0) return 0;
      return ((formData.unitPrice - formData.costPrice) / formData.unitPrice) * 100;
    }, [formData.unitPrice, formData.costPrice]);

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-8 space-y-10 custom-scrollbar">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">Nombre del Producto</label>
              <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" placeholder="Ej: Jabón de Tocador" />
            </div>
            <div className="space-y-2">
               <label className="text-[10px] font-black uppercase text-gray-400">Modalidad</label>
               <select value={formData.receptionType} onChange={e => setFormData({...formData, receptionType: e.target.value as any})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold">
                 <option value="Consignación">Consignación</option>
                 <option value="Compra Directa">Compra Directa</option>
               </select>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">{mode === 'reception' ? 'Cantidad de Entrada' : 'Stock Actual'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
              <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest flex items-center gap-2"><Tag size={14}/> Precios y Costos</h4>
              <div className="space-y-4">
                <div className="flex gap-4">
                  <div className="flex-1">
                    <label className="text-[9px] font-black text-gray-400 uppercase ml-1">Costo Unitario</label>
                    <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                  </div>
                  <div className="flex-1">
                    <label className="text-[9px] font-black text-gray-400 uppercase ml-1">Precio Venta</label>
                    <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                  </div>
                </div>
                <div className="p-4 bg-white rounded-2xl flex justify-between items-center border border-[#D7CCC8]/10">
                  <span className="text-[10px] font-black uppercase text-gray-400">Margen de Utilidad:</span>
                  <span className={`text-lg font-black ${margin > 20 ? 'text-emerald-500' : 'text-rose-400'}`}>{margin.toFixed(1)}%</span>
                </div>
              </div>
            </div>

            <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
               <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest flex items-center gap-2"><Layers size={14}/> Agrupaciones Ilimitadas</h4>
               <div className="grid grid-cols-2 gap-2 mb-4">
                  <input placeholder="Nombre (Caja, Pack...)" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="p-3 bg-white border rounded-xl text-xs font-bold" />
                  <input type="number" placeholder="Precio Final" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="p-3 bg-white border rounded-xl text-xs font-bold" />
                  <input type="number" placeholder="Cant. Unidades" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="p-3 bg-white border rounded-xl text-xs font-bold" />
                  <button onClick={() => {
                    if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
                    setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                    setTempGrouping({id: '', label: '', quantity: 0, price: 0, currency: formData.unitCurrency || 'CUP'});
                  }} className="bg-[#3E2723] text-white rounded-xl font-black text-[9px] uppercase hover:bg-[#AF6E4D]">+ Añadir Formato</button>
               </div>
               <div className="flex flex-wrap gap-2 max-h-32 overflow-y-auto custom-scrollbar">
                  {formData.groupings?.map(g => (
                    <div key={g.id} className="bg-white px-3 py-2 rounded-lg border border-[#D7CCC8]/40 text-[9px] font-black flex items-center gap-2 shadow-sm">
                      {g.label} ({g.price} {g.currency})
                      <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-400 hover:scale-110">×</button>
                    </div>
                  ))}
               </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Fecha de Vencimiento (Aviso a 60d)</label>
                <input type="date" value={formData.expiryDate} onChange={e => setFormData({...formData, expiryDate: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
             </div>
             {mode === 'reception' && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-[#AF6E4D]">Costo de Flete/Transporte de este Lote</label>
                  <input type="number" value={transportCost} onChange={e => setTransportCost(parseFloat(e.target.value))} className="w-full p-4 bg-[#F5F5DC] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                </div>
             )}
          </div>
        </div>
        <div className="p-8 border-t flex justify-end gap-4 bg-white">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs">Cancelar</button>
          <button onClick={() => onSave({...formData} as Product)} className="bg-[#3E2723] text-white px-12 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3 active:scale-95 transition-all"><Save size={18}/> Guardar Registro</button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
            <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario PaTí</h2>
            <div className="flex flex-wrap gap-4 w-full md:w-auto">
              <button onClick={async () => { const post = await generateSocialMediaPost(products); setSocialPost(post); }} className="flex-1 md:flex-none bg-[#AF6E4D] text-white px-8 py-5 rounded-[28px] text-[10px] font-black uppercase shadow-xl flex items-center justify-center gap-3 hover:scale-105 transition-all"><Instagram size={18}/> Generar Ofertas IA</button>
              <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="flex-1 md:flex-none bg-[#3E2723] text-white px-8 py-5 rounded-[28px] font-black text-xs uppercase shadow-xl flex items-center justify-center gap-3 hover:scale-105 transition-all"><Plus size={20}/> Entrada de Mercancía</button>
            </div>
          </div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl overflow-x-auto">
            <table className="w-full text-left min-w-[900px]">
              <thead className="bg-[#F5F5DC]/40 border-b-2 border-[#D7CCC8]/20 text-[10px] uppercase text-[#AF6E4D] font-black">
                <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8">Tipo</th><th className="px-10 py-8 text-center">Stock</th><th className="px-10 py-8">P. Venta</th><th className="px-10 py-8">Vencimiento</th><th className="px-10 py-8 text-right">Acciones</th></tr>
              </thead>
              <tbody className="divide-y text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8">
                       <p className="font-black text-sm uppercase">{p.name}</p>
                       <p className="text-[9px] text-[#D7CCC8] font-bold">SKU: {p.sku}</p>
                    </td>
                    <td className="px-10 py-8"><span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase ${p.receptionType === 'Consignación' ? 'bg-[#AF6E4D]/10 text-[#AF6E4D]' : 'bg-[#3E2723]/10 text-[#3E2723]'}`}>{p.receptionType}</span></td>
                    <td className={`px-10 py-8 text-center text-xl font-black ${p.stock <= p.minStock ? 'text-rose-500' : ''}`}>{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                    <td className="px-10 py-8">
                       <p className="font-black text-xs text-[#AF6E4D]">{p.unitPrice.toLocaleString()} {p.unitCurrency}</p>
                       <p className="text-[9px] text-gray-400 font-bold uppercase">{p.groupings.length} Formatos Adic.</p>
                    </td>
                    <td className="px-10 py-8">
                       <p className="font-bold text-[10px] uppercase">{p.expiryDate || 'Indefinido'}</p>
                       {p.expiryDate && (new Date(p.expiryDate) < new Date(Date.now() + 60*24*60*60*1000)) && <span className="text-[8px] font-black text-rose-400 uppercase">⚠️ Crítico</span>}
                    </td>
                    <td className="px-10 py-8 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'edit'})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#3E2723] hover:text-white transition-all"><Edit2 size={20}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex flex-col lg:flex-row h-auto lg:h-[calc(100vh-140px)] gap-8 animate-in zoom-in-95 duration-500">
           <div className="w-full lg:w-2/3 bg-white rounded-[60px] border border-[#D7CCC8]/20 p-8 md:p-12 flex flex-col shadow-2xl">
              <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-4">
                 <h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Punto de Venta</h2>
                 <div className="relative w-full md:w-80">
                    <Search className="absolute left-5 top-5 text-[#D7CCC8]" size={18}/>
                    <input placeholder="Buscar producto..." className="w-full pl-14 pr-4 py-5 bg-[#FCF9F7] rounded-3xl font-bold border-none shadow-inner" onChange={e => setInventorySearch(e.target.value)} />
                 </div>
              </div>
              <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 gap-6 custom-scrollbar pr-4">
                 {products.filter(p => p.name.toLowerCase().includes(inventorySearch.toLowerCase())).map(p => (
                   <div key={p.id} className="bg-[#FCF9F7] p-8 rounded-[45px] border border-[#D7CCC8]/10 hover:border-[#AF6E4D] transition-all flex flex-col justify-between group h-auto min-h-[320px]">
                      <div>
                         <p className="font-black text-sm uppercase mb-1 group-hover:text-[#AF6E4D] transition-colors">{p.name}</p>
                         <p className="text-[9px] font-black text-[#D7CCC8] uppercase mb-4">Disponible: {p.stock} Unidades</p>
                      </div>
                      <div className="space-y-4">
                         <button onClick={() => addToCart(p)} className="w-full py-5 bg-[#3E2723] text-white rounded-3xl font-black text-[10px] uppercase hover:bg-[#AF6E4D] transition-all shadow-lg active:scale-95">Unidad: {p.unitPrice} {p.unitCurrency}</button>
                         <div className="grid grid-cols-2 gap-2">
                            {p.groupings?.map(g => (
                              <button key={g.id} onClick={() => addToCart(p, g)} className="py-3 px-2 bg-white border border-[#D7CCC8]/30 rounded-2xl text-[8px] font-black uppercase hover:bg-[#3E2723] hover:text-white transition-all shadow-sm truncate">{g.label}</button>
                            ))}
                         </div>
                      </div>
                   </div>
                 ))}
              </div>
           </div>

           <div className="w-full lg:w-1/3 bg-[#3E2723] rounded-[60px] p-8 md:p-12 text-white flex flex-col shadow-2xl relative overflow-hidden">
              <div className="absolute -top-20 -right-20 w-60 h-60 bg-white/5 rounded-full blur-3xl"></div>
              <h3 className="text-xs font-black uppercase tracking-[0.2em] mb-10 text-[#AF6E4D] flex items-center gap-3"><ShoppingCart size={18}/> Detalle del Despacho</h3>

              <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10 min-h-[300px]">
                 {cart.length === 0 ? (
                   <div className="h-full flex flex-col items-center justify-center opacity-20"><ShoppingCart size={60} className="mb-4"/><p className="text-[10px] font-black uppercase">Carrito Vacío</p></div>
                 ) : (
                   cart.map(i => (
                     <div key={i.id} className="bg-white/5 p-6 rounded-[35px] border border-white/10 flex justify-between items-center group">
                        <div className="flex-1 pr-4">
                           <p className="text-[11px] font-black uppercase">{i.productName}</p>
                           <p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{i.groupingLabel} (x{i.quantity})</p>
                        </div>
                        <div className="flex items-center gap-4">
                           <p className="font-black text-xs">{i.total.toLocaleString()} {i.currency}</p>
                           <button onClick={() => setCart(cart.filter(x => x.id !== i.id))} className="text-rose-400 p-2 hover:bg-rose-400/10 rounded-full transition-all"><Trash2 size={16}/></button>
                        </div>
                     </div>
                   ))
                 )}
              </div>

              <div className="pt-8 border-t border-white/10 space-y-6">
                 <div className="flex gap-4">
                    <button onClick={() => setPaymentMethod('Efectivo')} className={`flex-1 py-4 rounded-2xl font-black text-[9px] uppercase border transition-all ${paymentMethod === 'Efectivo' ? 'bg-[#AF6E4D] text-white border-[#AF6E4D]' : 'bg-white/5 text-white/40 border-white/10'}`}>Efectivo</button>
                    <button onClick={() => setPaymentMethod('Transferencia')} className={`flex-1 py-4 rounded-2xl font-black text-[9px] uppercase border transition-all ${paymentMethod === 'Transferencia' ? 'bg-[#AF6E4D] text-white border-[#AF6E4D]' : 'bg-white/5 text-white/40 border-white/10'}`}>Transferencia</button>
                 </div>

                 <div className="flex justify-between items-end">
                    <p className="text-[10px] font-black uppercase opacity-40">Importe Total Acumulado</p>
                    <p className="text-5xl font-black tracking-tighter tabular-nums">{cart.reduce((a,b)=>a+b.total,0).toLocaleString()} <span className="text-sm opacity-20">CUP</span></p>
                 </div>

                 <div className="flex gap-3">
                    <button onClick={() => processTransaction('Solicitud')} disabled={cart.length === 0} className="flex-1 py-6 bg-white/10 text-white rounded-[35px] font-black uppercase text-[10px] hover:bg-white/20 transition-all border border-white/10">Pre-Factura</button>
                    <button onClick={() => processTransaction('Despachado')} disabled={cart.length === 0} className="flex-[2] py-6 bg-white text-[#3E2723] rounded-[35px] font-black uppercase text-[10px] shadow-2xl hover:scale-105 transition-all active:scale-95">Despachar Venta</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'suppliers' && (
        <div className="space-y-12 animate-in fade-in duration-500">
           <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
              <div>
                 <h2 className="text-4xl font-black uppercase text-[#3E2723] tracking-tighter">Directorio Comercial</h2>
                 <p className="text-xs font-bold text-[#AF6E4D] uppercase mt-2">Gestión de Cobros, Pagos y Consignaciones</p>
              </div>
              <button onClick={() => setShowContactModal(true)} className="bg-[#3E2723] text-white px-10 py-6 rounded-[30px] font-black text-xs uppercase shadow-xl flex items-center gap-4 hover:scale-105 transition-all"><Plus size={20}/> Nuevo Socio Estratégico</button>
           </div>
           <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
              {contacts.map(c => (
                <div key={c.id} className="bg-white p-10 rounded-[55px] border border-[#D7CCC8]/20 flex flex-col justify-between shadow-sm hover:shadow-2xl transition-all h-auto min-h-[380px] group">
                   <div className="flex justify-between items-start">
                      <div className="w-20 h-20 bg-[#F5F5DC] rounded-3xl flex items-center justify-center font-black text-3xl text-[#3E2723] shadow-inner group-hover:bg-[#3E2723] group-hover:text-white transition-all">{c.name.charAt(0)}</div>
                      <div className="flex flex-col items-end gap-2">
                        <span className={`text-[9px] font-black uppercase px-4 py-2 rounded-full border ${c.type === 'Proveedor' ? 'bg-amber-50 text-amber-600 border-amber-200' : 'bg-emerald-50 text-emerald-600 border-emerald-200'}`}>{c.type}</span>
                        {c.isConsignee && <span className="text-[8px] font-black bg-[#AF6E4D] text-white px-3 py-1 rounded-full uppercase">Consignatario</span>}
                      </div>
                   </div>
                   <div className="mt-8">
                      <h3 className="font-black text-[#3E2723] text-2xl uppercase mb-3 truncate">{c.name}</h3>
                      <div className="space-y-2">
