                         <p className="text-xs font-bold text-[#8D6E63] flex items-center gap-3"><MapPin size={16} className="text-[#AF6E4D]"/> {c.address}</p>
                      </div>
                   </div>
                   <div className="mt-8 pt-8 border-t border-[#D7CCC8]/10">
                      {c.type === 'Proveedor' && (
                        <div className="flex justify-between items-center mb-6">
                           <div>
                              <p className="text-[9px] font-black uppercase text-gray-400">Saldo Pendiente (Liquidación)</p>
                              <p className="text-xl font-black text-[#3E2723] tracking-tighter">{c.pendingBalanceCup.toLocaleString()} <span className="text-[10px] opacity-40">CUP</span></p>
                           </div>
                           {c.pendingBalanceCup > 0 && (
                             <button onClick={() => settleSupplier(c.id)} className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl hover:bg-emerald-600 hover:text-white transition-all"><CheckCircle2 size={24}/></button>
                           )}
                        </div>
                      )}
                      <button className="w-full py-4 bg-[#FCF9F7] text-[#3E2723] rounded-2xl font-black text-[10px] uppercase border border-[#D7CCC8]/20 hover:bg-[#3E2723] hover:text-white transition-all">Ver Historial Completo</button>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}

      {/* RECEPTION VIEW */}
      {activeTab === 'reception' && (
        <div className="max-w-4xl mx-auto animate-in slide-in-from-bottom-10 duration-500 pb-20">
          <div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 shadow-2xl overflow-hidden">
             <div className="p-12 border-b bg-[#F5F5DC]/30 flex justify-between items-center">
                <h2 className="text-4xl font-black uppercase text-[#3E2723] tracking-tighter flex items-center gap-6">
                   <div className="p-4 bg-[#3E2723] rounded-3xl text-white"><Truck size={40}/></div> 
                   Entrada de Lote
                </h2>
             </div>
             <ProductFormContent 
                mode="reception" 
                onSave={p => {
                  const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
                  let newList = [...products];
                  const lot: ReceptionLot = {
                    id: Math.random().toString(),
                    date: new Date().toISOString(),
                    quantityReceived: p.stock,
                    currentStock: p.stock,
                    unitCost: p.costPrice,
                    transportCost: 0, // Injected logic for transport would go here
                    totalInvestment: (p.stock * p.costPrice)
                  };

                  if (idx > -1) {
                    newList[idx] = { 
                      ...newList[idx], 
                      stock: newList[idx].stock + p.stock, 
                      costPrice: p.costPrice,
                      lots: [...(newList[idx].lots || []), lot]
                    };
                  } else {
                    newList = [{ ...p, id: Math.random().toString(), sku: `PATI-${Date.now().toString().slice(-4)}`, lots: [lot] }, ...newList];
                  }
                  setProducts(newList);
                  alert("¡Lote registrado y añadido al inventario!");
                  setActiveTab('inventory');
                }}
                onCancel={() => setActiveTab('inventory')}
             />
          </div>
        </div>
      )}

      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}

      {activeTab === 'closure' && (
        <div className="max-w-4xl mx-auto py-12 animate-in zoom-in-95">
           <div className="bg-white rounded-[75px] border border-[#D7CCC8]/30 shadow-2xl p-16 md:p-24 flex flex-col items-center">
              <div className="p-10 bg-[#F5F5DC] rounded-full mb-12 shadow-inner"><Wallet size={120} className="text-[#AF6E4D]"/></div>
              <h2 className="text-5xl font-black text-[#3E2723] uppercase mb-16 tracking-tighter text-center">Auditoría y Cierre de Caja</h2>

              <div className="w-full grid grid-cols-1 md:grid-cols-2 gap-8 mb-16">
                 <div className="bg-[#FCF9F7] p-12 rounded-[55px] text-center border border-[#D7CCC8]/20 shadow-sm">
                    <p className="text-[11px] font-black text-gray-400 uppercase mb-4 tracking-[0.2em]">Caja Hoy (CUP)</p>
                    <p className="text-6xl font-black text-[#3E2723] tracking-tighter">
                       {transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').reduce((a, b) => a + b.totalCup, 0).toLocaleString()} 
                       <span className="text-sm opacity-20 ml-2">CUP</span>
                    </p>
                 </div>
                 <div className="bg-[#3E2723] p-12 rounded-[55px] text-center text-white shadow-2xl">
                    <p className="text-[11px] font-black text-[#AF6E4D] uppercase mb-4 tracking-[0.2em]">Operaciones Realizadas</p>
                    <p className="text-7xl font-black tracking-tighter">
                       {transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').length}
                    </p>
                 </div>
              </div>

              <div className="flex flex-col md:flex-row gap-6 w-full">
                 <button onClick={() => window.print()} className="flex-1 bg-[#3E2723] text-white px-12 py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl flex items-center justify-center gap-6 hover:scale-105 transition-all active:scale-95"><Printer size={32}/> Imprimir Reporte de Cierre</button>
                 <button className="flex-1 bg-[#AF6E4D] text-white px-12 py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl flex items-center justify-center gap-6 hover:scale-105 transition-all"><History size={32}/> Historial de Cierres</button>
              </div>
           </div>
        </div>
      )}

      {/* CONFIGURATION VIEW */}
      {activeTab === 'config' && (
        <div className="max-w-4xl mx-auto py-10 animate-in slide-in-from-bottom-6 duration-500">
           <div className="bg-white rounded-[65px] border border-[#D7CCC8]/30 shadow-2xl p-12 md:p-20">
              <h2 className="text-4xl font-black text-[#3E2723] uppercase mb-16 flex items-center gap-8"><Settings size={50} className="text-[#AF6E4D]"/> Configuración del Sistema</h2>
              <div className="space-y-16">
                 <section className="space-y-8">
                    <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase border-b border-[#D7CCC8]/20 pb-4 tracking-widest">Identidad Corporativa</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                       <div className="space-y-3">
                          <label className="text-[10px] font-black uppercase text-gray-400 ml-2">URL del Logo</label>
                          <input value={config.logoUrl} onChange={e => setConfig({...config, logoUrl: e.target.value})} className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[30px] font-bold shadow-inner" />
                       </div>
                       <div className="space-y-3">
                          <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Nombre Comercial</label>
                          <input value={config.storeName} onChange={e => setConfig({...config, storeName: e.target.value})} className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[30px] font-bold shadow-inner" />
                       </div>
                    </div>
                 </section>
                 <section className="space-y-8">
                    <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase border-b border-[#D7CCC8]/20 pb-4 tracking-widest">Canales de Venta</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                       <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 ml-2">Teléfono</label><input value={config.phone} onChange={e => setConfig({...config, phone: e.target.value})} className="w-full p-6 bg-[#FCF9F7] border rounded-[30px] font-bold" /></div>
                       <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 ml-2">Facebook</label><input value={config.facebookUrl} onChange={e => setConfig({...config, facebookUrl: e.target.value})} className="w-full p-6 bg-[#FCF9F7] border rounded-[30px] font-bold" /></div>
                    </div>
                 </section>
                 <button onClick={() => alert("Configuración guardada.")} className="w-full bg-[#3E2723] text-white py-8 rounded-[35px] font-black uppercase text-xs shadow-2xl active:scale-95 transition-all">Sincronizar Cambios Globales</button>
              </div>
           </div>
        </div>
      )}

      {/* MODALES GLOBALES */}
      {productModal.show && (
        <div className="fixed inset-0 bg-black/95 z-[500] flex items-center justify-center p-4 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white rounded-[65px] w-full max-w-5xl shadow-2xl overflow-hidden max-h-[96vh] flex flex-col border-b-[20px] border-[#3E2723] animate-in slide-in-from-bottom-10">
            <div className="p-10 border-b flex justify-between items-center bg-[#F5F5DC]/40">
              <div className="flex items-center gap-6"><Package size={45} className="text-[#AF6E4D]"/><h2 className="text-3xl font-black uppercase text-[#3E2723]">{productModal.mode === 'reception' ? 'Registro de Entrada' : `Ficha: ${productModal.product?.name}`}</h2></div>
              <button onClick={() => setProductModal({show: false, mode: 'reception'})} className="p-4 bg-white rounded-full text-rose-400 hover:rotate-90 hover:bg-rose-50 transition-all shadow-sm"><X size={35} /></button>
            </div>
            <ProductFormContent 
              mode={productModal.mode} initialData={productModal.product} 
              onSave={p => {
                const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
                let list = [...products];
                if (idx > -1) {
                  list[idx] = { ...list[idx], ...p, stock: productModal.mode === 'reception' ? (list[idx].stock + p.stock) : p.stock };
                } else {
                  list = [{ ...p, id: Math.random().toString(), sku: `PATI-${Date.now().toString().slice(-4)}` }, ...list];
                }
                setProducts(list); setProductModal({show: false, mode: 'reception'});
              }}
              onCancel={() => setProductModal({show: false, mode: 'reception'})}
            />
          </div>
        </div>
      )}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/98 z-[600] flex items-center justify-center p-4 no-print backdrop-blur-3xl animate-in fade-in duration-500">
           <div className="bg-white rounded-[80px] w-full max-w-4xl shadow-2xl p-16 md:p-24 flex flex-col animate-in slide-in-from-bottom-20 border-[15px] border-white">
              <div className="flex justify-between items-start mb-24">
                <div className="bg-[#3E2723] p-10 rounded-[45px] shadow-2xl"><img src={config.logoUrl} className="h-28 w-auto brightness-200" /></div>
                <div className="text-right">
                  <p className="text-[12px] font-black uppercase text-gray-400 tracking-[0.3em] mb-2">Comprobante Oficial</p>
                  <p className="text-5xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.invoiceNumber}</p>
                  <p className="text-sm font-black text-[#AF6E4D] uppercase mt-4 px-6 py-2 bg-[#F5F5DC] rounded-full inline-block">{selectedInvoice.status === 'Solicitud' ? 'Cotización / Pre-Factura' : 'Factura de Despacho'}</p>
                </div>
              </div>

              <div className="flex-1 space-y-12 overflow-y-auto custom-scrollbar pr-4">
                 <table className="w-full text-left">
                   <thead><tr className="border-b-4 border-[#3E2723] text-[10px] uppercase font-black text-gray-400"><th className="py-8">Concepto / Formato</th><th className="py-8 text-center">Cant.</th><th className="py-8 text-right">Precio</th><th className="py-8 text-right">Total Item</th></tr></thead>
                   <tbody className="divide-y font-bold uppercase text-sm">
                     {selectedInvoice.items.map((i, idx) => (
                       <tr key={idx} className="hover:bg-gray-50/50">
                         <td className="py-8">
                           <p className="text-[#3E2723] font-black">{i.productName}</p>
                           <p className="text-[10px] text-[#AF6E4D] font-black mt-1">Presentación: {i.groupingLabel}</p>
                         </td>
                         <td className="py-8 text-center text-lg">{i.quantity}</td>
                         <td className="py-8 text-right tabular-nums">{i.price.toLocaleString()}</td>
                         <td className="py-8 text-right tabular-nums font-black">{i.total.toLocaleString()} {i.currency}</td>
                       </tr>
                     ))}
                   </tbody>
                 </table>

                 <div className="pt-12 border-t-8 border-[#3E2723] flex flex-col md:flex-row justify-between items-center md:items-end gap-10">
                    <div className="text-center md:text-left">
                       <p className="text-[10px] font-black text-[#3E2723] uppercase opacity-40 mb-2">Forma de Pago: {selectedInvoice.paymentMethod}</p>
                       <p className="text-[10px] font-black text-[#3E2723] uppercase opacity-40">Fecha: {new Date(selectedInvoice.date).toLocaleString()}</p>
                    </div>
                    <div className="text-center md:text-right">
                       <p className="text-[12px] font-black uppercase text-gray-400 tracking-[0.2em] mb-2">Importe Final a Liquidar</p>
                       <p className="text-8xl font-black text-[#3E2723] tracking-tighter leading-none">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-20 ml-2">CUP</span></p>
                    </div>
                 </div>
              </div>

              <div className="mt-20 flex flex-col md:flex-row justify-center gap-8 no-print">
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-10 rounded-[45px] font-black uppercase text-sm shadow-2xl flex items-center justify-center gap-6 hover:scale-105 transition-all"><Printer size={40}/> Imprimir Factura</button>
                 <button onClick={() => setSelectedInvoice(null)} className="px-14 py-10 font-black uppercase text-sm text-gray-400 hover:text-[#3E2723] transition-all">Cerrar Visor</button>
              </div>
           </div>
        </div>
      )}

      {socialPost && (
        <div className="fixed inset-0 bg-black/95 z-[700] flex items-center justify-center p-4 backdrop-blur-3xl animate-in fade-in duration-500">
           <div className="bg-white rounded-[75px] w-full max-w-2xl shadow-2xl p-16 animate-in zoom-in-95 border-b-[20px] border-[#AF6E4D]">
              <div className="flex justify-between items-center mb-12">
                 <h2 className="text-3xl font-black uppercase text-[#3E2723] flex items-center gap-6"><Instagram size={45} className="text-[#AF6E4D]"/> Marketing IA</h2>
                 <button onClick={() => setSocialPost(null)} className="p-3 bg-[#FCF9F7] rounded-full text-rose-400 hover:rotate-90 transition-all"><X size={35}/></button>
              </div>
              <div className="bg-[#FCF9F7] p-12 rounded-[55px] border-2 border-[#D7CCC8]/30 mb-12 shadow-inner group">
                 <textarea className="w-full h-[450px] bg-transparent font-medium text-xl text-[#3E2723] outline-none leading-relaxed resize-none custom-scrollbar" value={socialPost} readOnly />
              </div>
              <button onClick={() => { navigator.clipboard.writeText(socialPost || ''); alert("Texto copiado para tus redes sociales."); }} className="w-full bg-[#3E2723] text-white py-10 rounded-[40px] font-black uppercase text-sm flex items-center justify-center gap-6 shadow-2xl hover:scale-105 active:scale-95 transition-all"><Copy size={35}/> Copiar y Compartir</button>
           </div>
        </div>
      )}

      {showContactModal && (
        <div className="fixed inset-0 bg-black/95 z-[500] flex items-center justify-center p-4 backdrop-blur-xl">
           <div className="bg-white rounded-[75px] w-full max-w-lg p-16 md:p-20 animate-in zoom-in-95 border-b-[20px] border-[#AF6E4D] shadow-2xl">
              <h2 className="text-4xl font-black uppercase text-[#3E2723] mb-16 flex items-center gap-6"><Users className="text-[#AF6E4D]" size={45}/> Nuevo Aliado</h2>
              <form onSubmit={(e) => { 
                e.preventDefault(); 
                const fd = new FormData(e.currentTarget); 
                const isConsignee = fd.get('type') === 'Proveedor_C';
                const newC: Contact = { 
                  id: Math.random().toString(), 
                  name: fd.get('name') as string, 
                  contactName: fd.get('name') as string, 
                  phone: fd.get('phone') as string, 
                  email: '', 
                  address: fd.get('address') as string, 
                  type: isConsignee ? 'Proveedor' : fd.get('type') as any, 
                  isConsignee: isConsignee,
                  pendingBalanceCup: 0, 
                  pendingBalanceUsd: 0 
                }; 
                setContacts([...contacts, newC]); 
                setShowContactModal(false); 
              }} className="space-y-10">
                 <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em] ml-2">Nombre / Empresa</label><input name="name" required className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[35px] font-bold outline-none shadow-inner" /></div>
                 <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em] ml-2">Contacto Directo</label><input name="phone" required className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[35px] font-bold outline-none shadow-inner" /></div>
                 <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em] ml-2">Dirección Física</label><input name="address" required className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[35px] font-bold outline-none shadow-inner" /></div>
                 <div className="space-y-3">
                   <label className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em] ml-2">Vínculo Comercial</label>
                   <select name="type" className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[35px] font-black uppercase text-xs shadow-inner">
                      <option value="Proveedor_C">Proveedor (Consignación)</option>
                      <option value="Proveedor">Proveedor (Compra Directa)</option>
                      <option value="Cliente">Cliente VIP</option>
                   </select>
                 </div>
                 <div className="pt-6 flex gap-4">
                    <button type="button" onClick={() => setShowContactModal(false)} className="px-10 py-8 font-black uppercase text-xs text-gray-400 hover:text-[#3E2723] transition-all">Cancelar</button>
                    <button type="submit" className="flex-1 bg-[#3E2723] text-white py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl hover:scale-105 active:scale-95 transition-all">Añadir al Directorio</button>
                 </div>
              </form>
           </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

import React, { useMemo } from 'react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer 
} from 'recharts';
import { 
  TrendingUp, Package, DollarSign, Wallet, Activity, Clock, Truck, ShieldCheck, Target, Percent
} from 'lucide-react';
import { Product, Transaction, Contact } from '../types';

interface StatisticsProps {
  products: Product[];
  transactions: Transaction[];
  contacts: Contact[];
}

const Statistics: React.FC<StatisticsProps> = ({ products, transactions, contacts }) => {
  const totalSalesCup = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((acc, t) => acc + t.totalCup, 0), [transactions]);

  const totalTransportCosts = useMemo(() => {
    return products.reduce((acc, p) => acc + (p.lots?.reduce((sum, lot) => sum + lot.transportCost, 0) || 0), 0);
  }, [products]);

  const totalCostOfSales = useMemo(() => {
    let totalCost = 0;
    transactions.filter(t => t.status === 'Despachado').forEach(t => {
      t.items.forEach(item => {
        const product = products.find(p => p.id === item.productId);
        const costPerUnit = product?.costPrice || 0;
        totalCost += (costPerUnit * item.unitQuantity * item.quantity);
      });
    });
    return totalCost;
  }, [transactions, products]);

  const realProfit = totalSalesCup - totalCostOfSales - totalTransportCosts;
  const marginPercentage = totalSalesCup > 0 ? (realProfit / totalSalesCup) * 100 : 0;

  return (
    <div className="space-y-12 animate-in fade-in duration-700 pb-20">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        <div className="bg-white p-10 rounded-[55px] border border-[#D7CCC8]/30 shadow-sm relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full -mr-16 -mt-16 group-hover:scale-125 transition-transform duration-700"></div>
           <div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-[28px] flex items-center justify-center mb-6 shadow-inner"><TrendingUp size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Caja Total (CUP)</p>
           <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{totalSalesCup.toLocaleString()}</p>
        </div>
        <div className="bg-white p-10 rounded-[55px] border border-[#D7CCC8]/30 shadow-sm relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-rose-500/5 rounded-full -mr-16 -mt-16 group-hover:scale-125 transition-transform duration-700"></div>
           <div className="w-16 h-16 bg-rose-50 text-rose-600 rounded-[28px] flex items-center justify-center mb-6 shadow-inner"><Truck size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Logística y Flete</p>
           <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{totalTransportCosts.toLocaleString()}</p>
        </div>
        <div className="bg-[#3E2723] p-10 rounded-[55px] shadow-2xl text-white relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-48 h-48 bg-white/5 rounded-full -mr-24 -mt-24 group-hover:scale-125 transition-transform duration-700"></div>
           <div className="w-16 h-16 bg-white/10 text-[#AF6E4D] rounded-[28px] flex items-center justify-center mb-6"><Activity size={32}/></div>
           <p className="text-[10px] font-black uppercase text-white/40 tracking-widest mb-1">Rentabilidad Neta</p>
           <p className="text-4xl font-black tracking-tighter text-emerald-400">{realProfit.toLocaleString()} <span className="text-xs opacity-30 text-white">CUP</span></p>
        </div>
        <div className="bg-white p-10 rounded-[55px] border border-[#D7CCC8]/30 shadow-sm relative overflow-hidden group">
           <div className="w-16 h-16 bg-[#F5F5DC] text-[#AF6E4D] rounded-[28px] flex items-center justify-center mb-6 shadow-inner"><Percent size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Margen Global</p>
           <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{marginPercentage.toFixed(1)}%</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
         <div className="lg:col-span-2 bg-white p-12 rounded-[65px] border border-[#D7CCC8]/20 shadow-sm">
            <h3 className="text-sm font-black text-[#3E2723] uppercase tracking-widest mb-12 flex items-center gap-6"><Target size={24} className="text-[#AF6E4D]"/> Análisis de Retorno por Lote</h3>
            <div className="space-y-10">
               {products.filter(p => p.lots?.length > 0).slice(0, 6).map(p => {
                 const pTransport = p.lots?.reduce((s, l) => s + l.transportCost, 0) || 0;
                 const pSales = transactions.filter(t => t.status === 'Despachado' && t.items.some(i => i.productId === p.id)).reduce((a, b) => a + b.totalCup, 0);
                 const progress = Math.min((pSales / (pTransport + (p.costPrice * p.stock) || 1)) * 100, 100);

                 return (
                   <div key={p.id} className="space-y-4">
                      <div className="flex justify-between items-end">
                         <div>
                            <p className="text-[11px] font-black text-[#3E2723] uppercase tracking-tight">{p.name}</p>
                            <p className="text-[9px] font-bold text-[#AF6E4D] uppercase">Inversión Lote: {(p.costPrice * p.stock + pTransport).toLocaleString()} CUP</p>
                         </div>
                         <div className="text-right">
                            <p className="text-[10px] font-black text-emerald-500 uppercase">Recuperación: {progress.toFixed(0)}%</p>
                         </div>
                      </div>
                      <div className="w-full h-4 bg-[#FCF9F7] rounded-full overflow-hidden border border-[#D7CCC8]/20 p-1">
                         <div className={`h-full rounded-full transition-all duration-1000 ${progress > 80 ? 'bg-emerald-400' : progress > 40 ? 'bg-amber-400' : 'bg-rose-400'}`} style={{ width: `${progress}%` }}></div>
                      </div>
                   </div>
                 );
               })}
               {products.length === 0 && (
                  <div className="py-24 flex flex-col items-center justify-center opacity-30">
                    <History size={60} className="mb-4"/>
                    <p className="text-[11px] font-black uppercase">Sin datos históricos suficientes</p>
                  </div>
               )}
            </div>
         </div>

         <div className="bg-[#3E2723] p-12 rounded-[65px] text-white flex flex-col justify-between shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-64 h-64 bg-[#AF6E4D]/10 rounded-full blur-3xl"></div>
            <div>
               <h3 className="text-[11px] font-black uppercase tracking-[0.3em] mb-12 text-[#AF6E4D]">Estado Patrimonial</h3>
               <div className="space-y-10">
                  <div className="bg-white/5 p-8 rounded-[40px] border border-white/10">
                     <p className="text-[9px] font-black uppercase text-white/40 mb-2 tracking-widest">Deuda Total Consignatarios</p>
                     <p className="text-4xl font-black tabular-nums tracking-tighter">
                        {contacts.filter(c => c.isConsignee).reduce((a, b) => a + b.pendingBalanceCup, 0).toLocaleString()} 
                        <span className="text-xs opacity-30 ml-2">CUP</span>
                     </p>
                  </div>
                  <div className="bg-white/5 p-8 rounded-[40px] border border-white/10">
                     <p className="text-[9px] font-black uppercase text-white/40 mb-2 tracking-widest">Valorización de Almacén</p>
                     <p className="text-4xl font-black tabular-nums tracking-tighter">
                        {products.reduce((a, b) => a + (b.stock * b.costPrice), 0).toLocaleString()} 
                        <span className="text-xs opacity-30 ml-2">CUP</span>
                     </p>
                  </div>
               </div>
            </div>
            <div className="pt-12">
               <button onClick={() => window.print()} className="w-full py-7 bg-white text-[#3E2723] rounded-[35px] font-black uppercase text-[11px] shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-4">
                  <Download size={20}/> Auditoría Financiera Completa
               </button>
            </div>
         </div>
      </div>
    </div>
  );
};

export default Statistics;

