export type Currency = 'CUP' | 'USD';
export type PaymentMethod = 'Efectivo' | 'Transferencia';
export type ReceptionType = 'Consignación' | 'Compra Directa';

export interface GroupingPrice {
  id: string;
  label: string;
  quantity: number; // Unidades que contiene la agrupación (ej: 12 unidades en una caja)
  price: number;    // Precio por unidad dentro de esta agrupación
  currency: Currency;
  minOrderQuantity: number; // Mínimo de agrupaciones a comprar (ej: mínimo 3 cajas)
}

export interface StoreConfig {
  logoUrl: string;
  storeName: string;
  aboutText: string;
  address: string;
  phone: string;
  email: string;
  facebookUrl: string;
  instagramUrl: string;
  websiteUrl: string;
}

export interface ReceptionLot {
  id: string;
  date: string;
  quantityReceived: number;
  currentStock: number;
  unitCost: number;
  transportCost: number;
  totalInvestment: number; 
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  description: string;
  categoryId: string;
  supplierId: string;
  receptionType: ReceptionType;
  unitPrice: number;
  unitCurrency: Currency;
  costPrice: number; 
  groupings: GroupingPrice[];
  stock: number;
  minStock: number;
  expiryDate: string;
  receivedDate: string;
  isOffer?: boolean;
  lots: ReceptionLot[];
}

export interface Contact {
  id: string;
  name: string;
  contactName: string;
  phone: string;
  email: string;
  address: string;
  type: 'Proveedor' | 'Cliente';
  isConsignee?: boolean;
  pendingBalanceCup: number;
  pendingBalanceUsd: number;
}

export interface SaleItem {
  id: string;
  productId: string;
  productName: string;
  groupingId?: string; 
  groupingLabel?: string;
  quantity: number; // Cantidad de agrupaciones (ej: 3 cajas)
  price: number;    // Precio por unidad
  total: number;    // (quantity * unitsPerGrouping * price)
  currency: Currency;
  unitQuantity: number; // Unidades totales descontadas
}

export interface Transaction {
  id: string;
  date: string;
  clientId: string;
  clientName: string;
  items: SaleItem[];
  totalCup: number;
  totalUsd: number;
  paymentMethod: PaymentMethod;
  status: 'Solicitud' | 'Despachado' | 'Anulado';
  invoiceNumber: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'error' | 'success';
  date: string;
  read: boolean;
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  FileText, History, Info, Facebook, Instagram, Mail, Globe, Settings, Copy, TrendingUp, Percent,
  Users, Receipt, Heart, Share2, ExternalLink
} from 'lucide-react';
import { generateSocialMediaPost } from './services/geminiService';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v6_products',
  CONTACTS: 'pati_v6_contacts',
  TRANSACTIONS: 'pati_v6_transactions',
  CONFIG: 'pati_v6_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "https://i.ibb.co/L6S9Dkz/pati-logo.jpg",
  storeName: "PaTí",
  aboutText: "PaTí nació de la pasión por acercar productos de alta calidad directamente a tu hogar. Somos una tienda boutique especializada en la gestión ética de productos frescos y manufacturas en consignación, garantizando siempre la frescura para el cliente y el trato justo para nuestros proveedores aliados.",
  address: "Calle Real #123, Habana Vieja, Cuba",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/mercadopati",
  instagramUrl: "https://instagram.com/mercadopati",
  websiteUrl: "https://mercadopati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'reception' | 'edit'}>({show: false, mode: 'reception'});
  const [showContactModal, setShowContactModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [socialPost, setSocialPost] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence
  useEffect(() => {
    const load = () => {
      const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
      const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
      const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
      const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

      if (p) setProducts(JSON.parse(p));
      if (c) setContacts(JSON.parse(c));
      if (t) setTransactions(JSON.parse(t));
      if (cfg) setConfig(JSON.parse(cfg));

      setIsDataReady(true);
    };
    load();
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  // Backup & Restore
  const exportData = () => {
    const data = { products, contacts, transactions, config, version: '2.0', timestamp: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PaTi_Backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.products) setProducts(data.products);
        if (data.contacts) setContacts(data.contacts);
        if (data.transactions) setTransactions(data.transactions);
        if (data.config) setConfig(data.config);
        alert("¡Datos restaurados con éxito!");
      } catch (err) {
        alert("Error al procesar el archivo de respaldo.");
      }
    };
    reader.readAsText(file);
  };

  // Cart logic with minOrderQuantity
  const addToCart = (p: Product, grouping?: GroupingPrice) => {
    const unitsPerPack = grouping ? grouping.quantity : 1;
    const minQty = grouping ? grouping.minOrderQuantity : 1;
    const pricePerUnit = grouping ? grouping.price : p.unitPrice;
    const currency = grouping ? grouping.currency : p.unitCurrency;
    const label = grouping ? grouping.label : 'Unidad Suelta';

    if (p.stock < unitsPerPack * minQty) {
      alert(`Existencia insuficiente para el mínimo de ${minQty} ${label}(s).`);
      return;
    }

    const existingIdx = cart.findIndex(i => i.productId === p.id && i.groupingId === (grouping?.id || 'unit'));

    if (existingIdx > -1) {
      const newCart = [...cart];
      newCart[existingIdx].quantity += 1;
      newCart[existingIdx].unitQuantity = newCart[existingIdx].quantity * unitsPerPack;
      newCart[existingIdx].total = newCart[existingIdx].unitQuantity * pricePerUnit;
      setCart(newCart);
    } else {
      setCart([...cart, {
        id: Math.random().toString(),
        productId: p.id,
        productName: p.name,
        groupingId: grouping?.id || 'unit',
        groupingLabel: label,
        quantity: minQty,
        price: pricePerUnit,
        total: minQty * unitsPerPack * pricePerUnit,
        currency,
        unitQuantity: minQty * unitsPerPack
      }]);
    }
  };

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);

    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(),
      clientId: 'Gral', clientName: 'Consumidor Final', items: [...cart],
      totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'REQ' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };

    setTransactions([newTx, ...transactions]);

    if (status === 'Despachado') {
      const updatedProducts = products.map(p => {
        const soldItems = cart.filter(i => i.productId === p.id);
        const totalSoldUnits = soldItems.reduce((acc, i) => acc + i.unitQuantity, 0);
        return { ...p, stock: Math.max(0, p.stock - totalSoldUnits) };
      });
      setProducts(updatedProducts);
    }
    setCart([]);
    setSelectedInvoice(newTx);
  };

  const ProductFormContent = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', receptionType: 'Consignación', unitCurrency: 'CUP', groupings: [],
      stock: 0, minStock: 5, unitPrice: 0, costPrice: 0, expiryDate: ''
    });
    const [transportCost, setTransportCost] = useState(0);
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 1, price: 0, currency: 'CUP', minOrderQuantity: 1 });

    const isReception = mode === 'reception';

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-8 space-y-10 custom-scrollbar">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">Nombre del Producto</label>
              <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" readOnly={!isReception && !!initialData} />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">Costo Unitario (Inversión)</label>
              <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">{isReception ? 'Cantidad Recibida' : 'Existencia Actual'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
            </div>
          </div>

          {!isReception && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-in fade-in">
              <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
                <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest flex items-center gap-2"><Tag size={14}/> Precio de Venta (Unidad)</h4>
                <div className="flex gap-4">
                  <div className="flex-1">
                    <label className="text-[9px] font-black text-gray-400 uppercase">Precio Unitario</label>
                    <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                  </div>
                  <div className="w-32">
                    <label className="text-[9px] font-black text-gray-400 uppercase">Moneda</label>
                    <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as Currency})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold">
                       <option value="CUP">CUP</option>
                       <option value="USD">USD</option>
                    </select>
                  </div>
                </div>
              </div>

              <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
                 <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest flex items-center gap-2"><Layers size={14}/> Formatos Mayoristas</h4>
                 <div className="grid grid-cols-2 gap-3 mb-4">
                    <input placeholder="Ej: Caja, Estuche" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="p-3 bg-white border rounded-xl text-[10px] font-black" />
                    <input type="number" placeholder="P. por unidad" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="p-3 bg-white border rounded-xl text-[10px] font-black" />
                    <input type="number" placeholder="Unid. en agrup." value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="p-3 bg-white border rounded-xl text-[10px] font-black" />
                    <input type="number" placeholder="Min. cajas" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value)})} className="p-3 bg-white border rounded-xl text-[10px] font-black" />
                 </div>
                 <button onClick={() => {
                   if (!tempGrouping.label) return;
                   setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                   setTempGrouping({id: '', label: '', quantity: 1, price: 0, currency: formData.unitCurrency || 'CUP', minOrderQuantity: 1});
                 }} className="w-full bg-[#3E2723] text-white py-3 rounded-xl font-black text-[9px] uppercase">+ Añadir Escala</button>
                 <div className="mt-4 flex flex-wrap gap-2">
                    {formData.groupings?.map(g => (
                      <div key={g.id} className="bg-white px-3 py-2 rounded-lg border border-[#D7CCC8]/40 text-[8px] font-black flex items-center gap-2 shadow-sm uppercase">
                        {g.label} ({g.quantity}u @ ${g.price} min:{g.minOrderQuantity})
                        <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-400">×</button>
                      </div>
                    ))}
                 </div>
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Fecha de Vencimiento</label>
                <input type="date" value={formData.expiryDate} onChange={e => setFormData({...formData, expiryDate: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
             </div>
             {isReception && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-[#AF6E4D]">Costo Logístico de este Lote</label>
                  <input type="number" value={transportCost} onChange={e => setTransportCost(parseFloat(e.target.value))} className="w-full p-4 bg-[#F5F5DC] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                </div>
             )}
          </div>
        </div>
        <div className="p-8 border-t flex justify-end gap-4 bg-white">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs">Cancelar</button>
          <button onClick={() => onSave({...formData} as Product)} className="bg-[#3E2723] text-white px-12 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3 active:scale-95 transition-all"><Save size={18}/> Guardar Registro</button>
        </div>
      </div>
    );
  };

  // Fixed filtering for POS
  const filteredProducts = useMemo(() => {
    return products.filter(p => 
      p.name.toLowerCase().includes(inventorySearch.toLowerCase()) || 
      p.sku.toLowerCase().includes(inventorySearch.toLowerCase())
