              <div className="absolute top-0 right-0 w-80 h-80 bg-[#F5F5DC] rounded-full -mr-40 -mt-40 opacity-50"></div>
              <div className="relative z-10 flex flex-col items-center text-center">
                 <div className="p-10 bg-[#3E2723] rounded-[45px] shadow-2xl mb-12"><img src={config.logoUrl} className="h-28 w-auto brightness-200" /></div>
                 <h2 className="text-5xl font-black text-[#3E2723] uppercase mb-8 tracking-tighter">Nuestra Identidad</h2>
                 <p className="text-2xl font-serif text-[#8D6E63] italic leading-relaxed max-w-2xl mb-12">"Compromiso total con la frescura PaTí"</p>
                 <div className="w-24 h-1 bg-[#AF6E4D] mb-12"></div>
