                 <div className="mt-20 grid grid-cols-3 gap-12 w-full">
                    <div className="flex flex-col items-center"><div className="w-16 h-16 bg-[#FCF9F7] rounded-full flex items-center justify-center text-[#AF6E4D] shadow-sm mb-4"><Heart size={30}/></div><p className="text-[10px] font-black uppercase text-gray-400">Pasión</p></div>
                    <div className="flex flex-col items-center"><div className="w-16 h-16 bg-[#FCF9F7] rounded-full flex items-center justify-center text-[#AF6E4D] shadow-sm mb-4"><ShieldCheck size={30}/></div><p className="text-[10px] font-black uppercase text-gray-400">Calidad</p></div>
                    <div className="flex flex-col items-center"><div className="w-16 h-16 bg-[#FCF9F7] rounded-full flex items-center justify-center text-[#AF6E4D] shadow-sm mb-4"><Globe size={30}/></div><p className="text-[10px] font-black uppercase text-gray-400">Global</p></div>
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'contact' && (
        <div className="max-w-5xl mx-auto py-12 animate-in slide-in-from-bottom-10 duration-700">
           <h2 className="text-4xl font-black text-[#3E2723] uppercase mb-12 tracking-tighter text-center">Canales de Atención</h2>
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="bg-white p-12 rounded-[55px] border border-[#D7CCC8]/30 shadow-xl flex flex-col items-center text-center group hover:bg-[#3E2723] hover:text-white transition-all duration-500">
                 <div className="w-20 h-20 bg-[#F5F5DC] text-[#3E2723] rounded-[30px] flex items-center justify-center mb-8 group-hover:bg-white/10 group-hover:text-white"><Phone size={40}/></div>
                 <p className="text-[10px] font-black uppercase opacity-40 mb-2 tracking-widest">Llámanos</p>
                 <p className="text-3xl font-black">{config.phone}</p>
                 <a href={`tel:${config.phone}`} className="mt-8 px-10 py-4 bg-[#AF6E4D] text-white rounded-full font-black text-[10px] uppercase shadow-lg">Llamar Ahora</a>
              </div>
              <div className="bg-white p-12 rounded-[55px] border border-[#D7CCC8]/30 shadow-xl flex flex-col items-center text-center group hover:bg-[#3E2723] hover:text-white transition-all duration-500">
                 <div className="w-20 h-20 bg-[#F5F5DC] text-[#3E2723] rounded-[30px] flex items-center justify-center mb-8 group-hover:bg-white/10 group-hover:text-white"><Mail size={40}/></div>
                 <p className="text-[10px] font-black uppercase opacity-40 mb-2 tracking-widest">Escríbenos</p>
                 <p className="text-3xl font-black">{config.email}</p>
                 <a href={`mailto:${config.email}`} className="mt-8 px-10 py-4 bg-[#AF6E4D] text-white rounded-full font-black text-[10px] uppercase shadow-lg">Enviar Correo</a>
              </div>
              <div className="md:col-span-2 bg-[#F5F5DC]/40 p-12 rounded-[60px] border border-[#D7CCC8]/20 flex flex-col md:flex-row items-center justify-between gap-10">
                 <div className="flex items-center gap-8">
                    <div className="p-6 bg-white rounded-3xl shadow-sm"><MapPin size={45} className="text-[#3E2723]"/></div>
                    <div>
                       <p className="text-[10px] font-black uppercase text-[#AF6E4D] mb-1">Nuestra Sede</p>
                       <p className="text-2xl font-black text-[#3E2723]">{config.address}</p>
                    </div>
                 </div>
                 <div className="flex gap-4">
                    <button className="p-6 bg-white rounded-full shadow-sm hover:scale-110 transition-transform"><Facebook size={24}/></button>
                    <button className="p-6 bg-white rounded-full shadow-sm hover:scale-110 transition-transform"><Instagram size={24}/></button>
                    <button className="p-6 bg-white rounded-full shadow-sm hover:scale-110 transition-transform"><Globe size={24}/></button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
            <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario PaTí</h2>
            <div className="flex flex-wrap gap-4 w-full md:w-auto">
              <button onClick={async () => { const post = await generateSocialMediaPost(products); setSocialPost(post); }} className="flex-1 md:flex-none bg-[#AF6E4D] text-white px-8 py-5 rounded-[28px] text-[10px] font-black uppercase shadow-xl flex items-center justify-center gap-3 hover:scale-105 transition-all"><Instagram size={18}/> Marketing IA</button>
              <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="flex-1 md:flex-none bg-[#3E2723] text-white px-8 py-5 rounded-[28px] font-black text-xs uppercase shadow-xl flex items-center justify-center gap-3 hover:scale-105 transition-all"><Truck size={20}/> Entrada Lote</button>
            </div>
          </div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl overflow-x-auto">
            <table className="w-full text-left min-w-[900px]">
              <thead className="bg-[#F5F5DC]/40 border-b-2 border-[#D7CCC8]/20 text-[10px] uppercase text-[#AF6E4D] font-black">
                <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8 text-center">Stock</th><th className="px-10 py-8">P. Venta</th><th className="px-10 py-8">Vencimiento</th><th className="px-10 py-8 text-right">Acciones</th></tr>
              </thead>
              <tbody className="divide-y text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8">
                       <p className="font-black text-sm uppercase">{p.name}</p>
                       <p className="text-[9px] text-[#D7CCC8] font-bold">SKU: {p.sku}</p>
                    </td>
                    <td className={`px-10 py-8 text-center text-xl font-black ${p.stock <= p.minStock ? 'text-rose-500' : ''}`}>{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                    <td className="px-10 py-8">
                       <p className="font-black text-xs text-[#AF6E4D]">{p.unitPrice.toLocaleString()} {p.unitCurrency}</p>
                       <p className="text-[9px] text-gray-400 font-bold uppercase">{p.groupings.length} Formatos Adic.</p>
                    </td>
                    <td className="px-10 py-8">
                       <p className="font-bold text-[10px] uppercase">{p.expiryDate || 'Indefinido'}</p>
                    </td>
                    <td className="px-10 py-8 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'edit'})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#3E2723] hover:text-white transition-all"><Edit2 size={20}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex flex-col lg:flex-row h-auto lg:h-[calc(100vh-140px)] gap-8 animate-in zoom-in-95 duration-500">
           <div className="w-full lg:w-2/3 bg-white rounded-[60px] border border-[#D7CCC8]/20 p-8 md:p-12 flex flex-col shadow-2xl overflow-hidden">
              <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-4">
                 <h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal de Venta</h2>
                 <div className="relative w-full md:w-80">
                    <Search className="absolute left-5 top-5 text-[#D7CCC8]" size={18}/>
                    <input 
                      placeholder="Buscar producto o SKU..." 
                      className="w-full pl-14 pr-4 py-5 bg-[#FCF9F7] rounded-3xl font-bold border-none shadow-inner outline-none focus:ring-2 ring-[#AF6E4D]/20 transition-all" 
                      value={inventorySearch}
                      onChange={e => setInventorySearch(e.target.value)} 
                    />
                 </div>
              </div>
              <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 gap-6 custom-scrollbar pr-4 pb-4">
                 {filteredProducts.map(p => (
                   <div key={p.id} className="bg-[#FCF9F7] p-8 rounded-[45px] border border-[#D7CCC8]/10 hover:border-[#AF6E4D] transition-all flex flex-col justify-between group h-auto min-h-[350px]">
                      <div>
                         <p className="font-black text-sm uppercase mb-1 group-hover:text-[#AF6E4D] transition-colors">{p.name}</p>
                         <p className="text-[9px] font-black text-[#D7CCC8] uppercase mb-4">Stock: {p.stock} Unidades</p>
                      </div>
                      <div className="space-y-4">
                         <button onClick={() => addToCart(p)} className="w-full py-5 bg-[#3E2723] text-white rounded-3xl font-black text-[10px] uppercase hover:bg-[#AF6E4D] transition-all shadow-lg active:scale-95">Unidad: {p.unitPrice} {p.unitCurrency}</button>
                         {p.groupings?.length > 0 && (
                           <div className="grid grid-cols-1 gap-2">
                              {p.groupings?.map(g => (
                                <button key={g.id} onClick={() => addToCart(p, g)} className="py-4 px-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-[9px] font-black uppercase hover:bg-[#3E2723] hover:text-white transition-all shadow-sm flex justify-between items-center">
                                   <span>{g.label} <span className="opacity-40 text-[8px]">(Min: {g.minOrderQuantity})</span></span>
                                   <span>${g.price}/u</span>
