                 </div>
                 <div className="flex justify-between items-end">
                    <p className="text-[10px] font-black uppercase opacity-40">Importe Acumulado</p>
                    <p className="text-4xl font-black tracking-tighter tabular-nums">{cart.reduce((a,b)=>a+b.total,0).toLocaleString()} <span className="text-sm opacity-20">CUP</span></p>
                 </div>
