                    <input type="number" placeholder="Unid x Agrup" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="p-3 bg-white border rounded-xl text-[10px] font-bold" />
                    <input type="number" placeholder="Mínimo a vender" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value)})} className="p-3 bg-white border rounded-xl text-[10px] font-bold" />
