              <div className="mt-20 flex justify-center gap-8 no-print">
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-10 rounded-[45px] font-black uppercase text-sm shadow-2xl flex items-center justify-center gap-6"><Printer size={40}/> Imprimir</button>
                 <button onClick={() => setSelectedInvoice(null)} className="px-14 py-10 font-black uppercase text-sm text-gray-400">Cerrar Visor</button>
              </div>
           </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

export type Currency = 'CUP' | 'USD';
export type PaymentMethod = 'Efectivo' | 'Transferencia';
export type ReceptionType = 'Consignación' | 'Compra Directa';

export interface GroupingPrice {
  id: string;
  label: string;
  quantity: number; // Unidades que contiene la agrupación (ej: 12 unidades en una caja)
  price: number;    // Precio por unidad dentro de esta agrupación
  currency: Currency;
  minOrderQuantity: number; // Mínimo de agrupaciones a comprar (ej: mínimo 3 cajas)
}

export interface Offer {
  id: string;
  label: string;
  price: number;
  currency: Currency;
  startDate: string;
  endDate: string;
}

export interface StoreConfig {
  logoUrl: string;
  storeName: string;
  aboutText: string;
  address: string;
  phone: string;
  email: string;
  facebookUrl: string;
  instagramUrl: string;
  websiteUrl: string;
}

export interface ReceptionLot {
  id: string;
  date: string;
  supplierId: string;
  receptionType: ReceptionType;
  quantityReceived: number;
  currentStock: number;
  unitCost: number;
  transportCost: number;
  totalInvestment: number; 
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  description: string;
  categoryId: string;
  supplierId: string;
  receptionType: ReceptionType;
  unitPrice: number;
  unitCurrency: Currency;
  costPrice: number; 
  groupings: GroupingPrice[];
  offers: Offer[];
  stock: number;
  minStock: number;
  expiryDate: string;
  receivedDate: string;
  isOffer?: boolean;
  lots: ReceptionLot[];
}

export interface Contact {
  id: string;
  name: string;
  contactName: string;
  phone: string;
  email: string;
  address: string;
  type: 'Proveedor' | 'Cliente';
  isConsignee?: boolean;
  pendingBalanceCup: number;
  pendingBalanceUsd: number;
}

export interface SaleItem {
  id: string;
  productId: string;
  productName: string;
  groupingId?: string; 
  groupingLabel?: string;
  quantity: number; // Cantidad de agrupaciones (ej: 3 cajas)
  price: number;    // Precio por unidad
  total: number;    // (quantity * unitsPerGrouping * price)
  currency: Currency;
  unitQuantity: number; // Unidades totales descontadas
}

export interface Transaction {
  id: string;
  date: string;
  clientId: string;
  clientName: string;
  items: SaleItem[];
  totalCup: number;
  totalUsd: number;
  paymentMethod: PaymentMethod;
  status: 'Solicitud' | 'Despachado' | 'Anulado';
  invoiceNumber: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'error' | 'success';
  date: string;
  read: boolean;
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
