                  <select value={formData.supplierId} onChange={e => setFormData({...formData, supplierId: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold">
                     <option value="">Seleccione Proveedor</option>
                     {contacts.filter(c => c.type === 'Proveedor').map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-gray-400">Tipo de Compra</label>
                  <select value={formData.receptionType} onChange={e => setFormData({...formData, receptionType: e.target.value as any})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold">
                     <option value="Consignación">Consignación</option>
                     <option value="Compra Directa">Compra Directa</option>
                  </select>
                </div>
              </>
            )}
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">{isReception ? 'Cantidad Recibida' : 'Stock Total'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
