              value={formData.description} 
              onChange={e => {
                setFormData({...formData, description: e.target.value});
                e.target.style.height = 'auto';
                e.target.style.height = e.target.scrollHeight + 'px';
              }} 
              placeholder="Detalles del producto, composición, etc..."
              className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-3xl font-medium min-h-[100px] resize-none overflow-hidden transition-all focus:ring-2 ring-[#AF6E4D]/20 outline-none" 
            />
          </div>

          {!isReception && (
            <div className="space-y-12">
              <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
