                <div className="flex gap-4">
                  <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} placeholder="Precio de venta unitario" className="flex-1 p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                  <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as Currency})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold">
                    <option value="CUP">CUP</option>
                    <option value="USD">USD</option>
