                       className="w-full pl-14 pr-4 py-5 bg-[#FCF9F7] rounded-3xl font-bold border-none outline-none focus:ring-2 ring-[#AF6E4D]/20 transition-all" 
                       value={posSearch}
                       onChange={e => setPosSearch(e.target.value)} 
                    />
                 </div>
              </div>
              <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 gap-6 custom-scrollbar pr-2 pb-4">
                 {filteredProducts.map(p => (
                   <div key={p.id} className="bg-[#FCF9F7] p-8 rounded-[45px] border border-[#D7CCC8]/10 hover:border-[#AF6E4D] transition-all flex flex-col justify-between group min-h-[400px]">
                      <div>
                         <h3 className="font-black text-sm uppercase mb-1 group-hover:text-[#AF6E4D] transition-colors">{p.name}</h3>
                         <p className="text-[9px] font-black text-[#D7CCC8] uppercase mb-4 tracking-widest">Disponible: {p.stock} U.</p>
                         <p className="text-[10px] text-gray-500 font-medium line-clamp-3 mb-6">{p.description || 'Sin descripción detallada.'}</p>
                      </div>
                      <div className="space-y-3">
                         <button onClick={() => addToCart(p)} className="w-full py-5 bg-[#3E2723] text-white rounded-3xl font-black text-[10px] uppercase hover:bg-[#AF6E4D] transition-all shadow-lg active:scale-95">Unidad: ${p.unitPrice} {p.unitCurrency}</button>
                         {p.groupings?.map(g => (
                           <button key={g.id} onClick={() => addToCart(p, g)} className="w-full py-4 px-5 bg-white border border-[#D7CCC8]/30 rounded-2xl text-[9px] font-black uppercase hover:bg-[#3E2723] hover:text-white transition-all flex justify-between items-center shadow-sm">
                              <span>{g.label} <span className="opacity-30 text-[8px]">(Min: {g.minOrderQuantity})</span></span>
                              <span>${g.price}/u</span>
                           </button>
                         ))}
                         {p.offers?.map(o => (
                           <button key={o.id} onClick={() => addToCart(p, o)} className="w-full py-4 px-5 bg-emerald-50 border border-emerald-100 rounded-2xl text-[9px] font-black uppercase text-emerald-600 hover:bg-emerald-600 hover:text-white transition-all flex justify-between items-center shadow-sm">
                              <span className="flex items-center gap-2"><Percent size={12}/> {o.label}</span>
                              <span>${o.price}/u</span>
                           </button>
                         ))}
                      </div>
                   </div>
                 ))}
                 {filteredProducts.length === 0 && <div className="col-span-full py-20 text-center text-[#D7CCC8] font-black uppercase tracking-widest">No se encontraron productos</div>}
              </div>
           </div>

           <div className="w-full lg:w-1/3 bg-[#3E2723] rounded-[60px] p-12 text-white flex flex-col shadow-2xl relative overflow-hidden h-full">
              <h3 className="text-xs font-black uppercase tracking-[0.2em] mb-10 text-[#AF6E4D] flex items-center gap-3"><ShoppingCart size={18}/> Orden de Salida</h3>
              <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10 min-h-[200px] pr-2">
                 {cart.length === 0 ? (
                   <div className="h-full flex flex-col items-center justify-center opacity-20"><ShoppingCart size={60} className="mb-4"/><p className="text-[10px] font-black uppercase">Vacío</p></div>
                 ) : (
                   cart.map(i => (
                     <div key={i.id} className="bg-white/5 p-6 rounded-[35px] border border-white/10 flex justify-between items-center">
                        <div className="flex-1 pr-4">
                           <p className="text-[11px] font-black uppercase">{i.productName}</p>
                           <p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{i.groupingLabel} (x{i.quantity})</p>
                        </div>
                        <div className="flex items-center gap-4">
                           <p className="font-black text-xs text-right tabular-nums">{i.total.toLocaleString()} {i.currency}</p>
                           <button onClick={() => removeFromCart(i.id)} className="text-rose-400 p-2 hover:bg-rose-400/10 rounded-full transition-all"><Trash2 size={16}/></button>
                        </div>
                     </div>
                   ))
                 )}
              </div>
              <div className="pt-8 border-t border-white/10 space-y-6">
                 <div className="flex justify-between items-end">
                    <p className="text-[10px] font-black uppercase opacity-40 tracking-widest">Total a Liquidar</p>
                    <p className="text-5xl font-black tracking-tighter tabular-nums">{cart.reduce((a,b)=>a+b.total,0).toLocaleString()} <span className="text-sm opacity-20 ml-2">CUP</span></p>
                 </div>
                 <div className="flex gap-3">
                    <button onClick={() => processTransaction('Solicitud')} disabled={cart.length === 0} className="flex-1 py-6 bg-white/10 text-white rounded-[35px] font-black uppercase text-[10px] border border-white/10 active:scale-95 transition-all">Pre-Factura</button>
                    <button onClick={() => processTransaction('Despachado')} disabled={cart.length === 0} className="flex-[2] py-6 bg-white text-[#3E2723] rounded-[35px] font-black uppercase text-[10px] shadow-2xl active:scale-95 transition-all">Despachar</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'maintenance' && (
        <div className="max-w-4xl mx-auto py-12 animate-in zoom-in-95">
           <div className="bg-white rounded-[75px] border border-[#D7CCC8]/30 shadow-2xl p-16 md:p-24 flex flex-col items-center">
              <Database size={60} className="text-[#AF6E4D] mb-8"/>
              <h2 className="text-4xl font-black text-[#3E2723] uppercase mb-16 tracking-tighter">Mantenimiento de Datos</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full">
                 <button onClick={exportData} className="p-12 bg-[#FCF9F7] rounded-[50px] border border-[#D7CCC8]/30 flex flex-col items-center text-center group hover:bg-[#3E2723] hover:text-white transition-all">
                    <Download size={40} className="mb-4 text-[#AF6E4D] group-hover:text-white"/>
                    <span className="font-black uppercase text-[12px]">Exportar Respaldo</span>
                 </button>
                 <button onClick={() => fileInputRef.current?.click()} className="p-12 bg-[#FCF9F7] rounded-[50px] border border-[#D7CCC8]/30 flex flex-col items-center text-center group hover:bg-[#3E2723] hover:text-white transition-all">
                    <Upload size={40} className="mb-4 text-[#AF6E4D] group-hover:text-white"/>
                    <span className="font-black uppercase text-[12px]">Importar Respaldo</span>
                 </button>
                 <input type="file" ref={fileInputRef} onChange={importData} accept=".json" className="hidden" />
              </div>
           </div>
        </div>
      )}

      {/* MODAL PRODUCTO (MAESTRO) */}
      {productModal.show && (
        <div className="fixed inset-0 bg-black/95 z-[500] flex items-center justify-center p-4 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[65px] w-full max-w-5xl shadow-2xl overflow-hidden max-h-[96vh] flex flex-col border-b-[20px] border-[#3E2723] animate-in slide-in-from-bottom-10 relative">
            <div className="p-10 border-b flex justify-between items-center bg-[#F5F5DC]/40 sticky top-0 z-20">
              <div className="flex items-center gap-6"><Package size={45} className="text-[#AF6E4D]"/><h2 className="text-3xl font-black uppercase text-[#3E2723]">{productModal.mode === 'catalog' ? 'Ficha Maestra' : 'Entrada Lote'}</h2></div>
              <button onClick={() => setProductModal({show: false, mode: 'catalog'})} className="p-4 bg-white rounded-full text-rose-400 hover:rotate-90 transition-all shadow-sm"><X size={35} /></button>
            </div>
            <ProductForm 
              mode={productModal.mode} initialData={productModal.product} 
              onSave={p => {
                const idx = products.findIndex(x => (x.id === p.id) || (x.name.toLowerCase() === p.name.toLowerCase()));
                let list = [...products];
                if (idx > -1) {
                  list[idx] = { ...list[idx], ...p };
                } else {
                  list = [{ ...p, id: Math.random().toString(), sku: `PATI-${Date.now().toString().slice(-4)}` }, ...list];
                }
                setProducts(list); setProductModal({show: false, mode: 'catalog'});
              }}
              onCancel={() => setProductModal({show: false, mode: 'catalog'})}
            />
          </div>
        </div>
      )}

      {/* VISOR FACTURA */}
      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/98 z-[600] flex items-center justify-center p-4 no-print backdrop-blur-3xl">
           <div className="bg-white rounded-[80px] w-full max-w-4xl shadow-2xl p-16 md:p-24 flex flex-col animate-in slide-in-from-bottom-20">
              <div className="flex justify-between items-start mb-24">
                <img src={config.logoUrl} className="h-28 w-auto bg-[#3E2723] p-6 rounded-[35px]" />
                <div className="text-right">
                  <p className="text-[12px] font-black uppercase text-gray-400 tracking-[0.3em] mb-2">Comprobante</p>
                  <p className="text-5xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.invoiceNumber}</p>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar pr-4">
                 <table className="w-full text-left">
                   <thead><tr className="border-b-4 border-[#3E2723] text-[10px] uppercase font-black text-gray-400"><th className="py-8">Concepto</th><th className="py-8 text-center">Cant.</th><th className="py-8 text-right">Subtotal</th></tr></thead>
                   <tbody className="divide-y font-bold uppercase text-sm">
                     {selectedInvoice.items.map((i, idx) => (
                       <tr key={idx}><td className="py-8"><p className="text-[#3E2723] font-black">{i.productName}</p><p className="text-[10px] text-[#AF6E4D] font-black">{i.groupingLabel}</p></td><td className="py-8 text-center text-lg">{i.quantity}</td><td className="py-8 text-right tabular-nums">{i.total.toLocaleString()} {i.currency}</td></tr>
                     ))}
                   </tbody>
                 </table>
                 <div className="pt-12 border-t-8 border-[#3E2723] flex justify-between items-end mt-12">
                    <p className="text-[12px] font-black uppercase text-gray-400 tracking-[0.2em]">Total</p>
                    <p className="text-7xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-20 ml-2">CUP</span></p>
                 </div>
              </div>
              <div className="mt-20 flex justify-center gap-8 no-print">
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-10 rounded-[45px] font-black uppercase text-sm shadow-2xl flex items-center justify-center gap-6"><Printer size={40}/> Imprimir</button>
                 <button onClick={() => setSelectedInvoice(null)} className="px-14 py-10 font-black uppercase text-sm text-gray-400">Cerrar</button>
              </div>
           </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot, Offer 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  FileText, History, Info, Facebook, Instagram, Mail, Globe, Settings, Copy, TrendingUp, Percent,
  Users, Receipt, Heart, Share2, ExternalLink, Eye, BarChart, Calendar, ChevronRight
} from 'lucide-react';
import { generateSocialMediaPost } from './services/geminiService';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v7_products',
  CONTACTS: 'pati_v7_contacts',
  TRANSACTIONS: 'pati_v7_transactions',
  CONFIG: 'pati_v7_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "https://i.ibb.co/L6S9Dkz/pati-logo.jpg",
  storeName: "PaTí",
  aboutText: "PaTí es compromiso total con la comunidad. Nos enorgullece ser el puente entre los mejores productores y su hogar, ofreciendo una selección curada que abarca desde alimentos frescos del campo y productos de aseo de alta gama hasta artículos de ferretería y hogar. Creemos en el comercio justo, la transparencia en la gestión de consignaciones y, sobre todo, en brindar soluciones cotidianas con la calidad que usted y su familia merecen.",
  address: "Calle Real #123, Habana Vieja, Cuba",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/mercadopati",
  instagramUrl: "https://instagram.com/mercadopati",
  websiteUrl: "https://mercadopati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'catalog' | 'reception'}>({show: false, mode: 'catalog'});
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [socialPost, setSocialPost] = useState<string | null>(null);
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence
  useEffect(() => {
    const load = () => {
      const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
      const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
      const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
      const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

      if (p) setProducts(JSON.parse(p));
      if (c) setContacts(JSON.parse(c));
      if (t) setTransactions(JSON.parse(t));
      if (cfg) setConfig(JSON.parse(cfg));

      setIsDataReady(true);
    };
    load();
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  const exportData = () => {
    const data = { products, contacts, transactions, config, backupDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `PaTi_Respaldo_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const data = JSON.parse(evt.target?.result as string);
        if (data.products) setProducts(data.products);
        if (data.contacts) setContacts(data.contacts);
        if (data.transactions) setTransactions(data.transactions);
        if (data.config) setConfig(data.config);
        alert("¡Base de datos restaurada!");
      } catch (err) {
        alert("Error al procesar el archivo.");
      }
    };
    reader.readAsText(file);
  };

  const filteredProducts = useMemo(() => {
    const query = posSearch.toLowerCase().trim();
    return products.filter(p => 
      p.name.toLowerCase().includes(query) || 
      p.sku.toLowerCase().includes(query)
    );
  }, [products, posSearch]);

  const addToCart = (p: Product, variant?: GroupingPrice | Offer) => {
    const isOffer = variant && 'startDate' in variant;
    const isGrouping = variant && 'quantity' in variant && !isOffer;

    const unitsPerPack = isGrouping ? (variant as GroupingPrice).quantity : 1;
    const minToBuy = isGrouping ? (variant as GroupingPrice).minOrderQuantity : 1;
    const pricePerUnit = variant ? variant.price : p.unitPrice;

    if (p.stock < unitsPerPack * minToBuy) {
      alert(`Existencia insuficiente en almacén.`);
      return;
    }

    const variantId = variant ? variant.id : 'unit';
    const itemId = `${p.id}-${variantId}`;
    const existing = cart.find(i => i.id === itemId);

    if (existing) {
      const newCart = cart.map(item => {
        if (item.id === itemId) {
          const newQty = item.quantity + 1;
          const newTotalUnits = newQty * unitsPerPack;
          return { ...item, quantity: newQty, unitQuantity: newTotalUnits, total: newTotalUnits * pricePerUnit };
        }
        return item;
      });
      setCart(newCart);
    } else {
      const initialTotalUnits = minToBuy * unitsPerPack;
      setCart([...cart, {
        id: itemId, productId: p.id, productName: p.name, groupingId: variantId,
        groupingLabel: variant?.label || 'Unidad Suelta', quantity: minToBuy, price: pricePerUnit,
        total: initialTotalUnits * pricePerUnit, currency: variant?.currency || p.unitCurrency,
        unitQuantity: initialTotalUnits
      }]);
    }
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);
    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Consumidor Final',
      items: [...cart], totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'SOL' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };
    if (status === 'Despachado') {
      const updatedProducts = products.map(p => {
        const soldUnits = cart.filter(i => i.productId === p.id).reduce((acc, i) => acc + i.unitQuantity, 0);
        return { ...p, stock: Math.max(0, p.stock - soldUnits) };
      });
      setProducts(updatedProducts);
    }
    setTransactions([newTx, ...transactions]);
    setCart([]);
    setSelectedInvoice(newTx);
  };

  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'catalog' | 'reception', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', description: '', stock: 0, costPrice: 0, unitPrice: 0, unitCurrency: 'CUP', groupings: [], offers: [], lots: [], supplierId: '', receptionType: 'Consignación'
    });

    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 1, price: 0, currency: 'CUP', minOrderQuantity: 1 });
    const [tempOffer, setTempOffer] = useState<Offer>({ id: '', label: '', price: 0, currency: 'CUP', startDate: '', endDate: '' });

    const isReception = mode === 'reception';

    return (
      <div className="flex flex-col h-full bg-white overflow-hidden">
        <div className="flex-1 overflow-y-auto p-6 md:p-10 space-y-12 custom-scrollbar pb-32">

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="space-y-2 md:col-span-2">
              <label className="text-[11px] font-black uppercase text-gray-400">Nombre del Producto</label>
              <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-2xl font-bold text-lg" />
            </div>
            {isReception && (
              <>
                <div className="space-y-2">
                  <label className="text-[11px] font-black uppercase text-gray-400">Proveedor</label>
                  <select value={formData.supplierId} onChange={e => setFormData({...formData, supplierId: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-2xl font-bold">
                     <option value="">Seleccione...</option>
                     {contacts.filter(c => c.type === 'Proveedor').map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[11px] font-black uppercase text-gray-400">Tipo de Gestión</label>
                  <select value={formData.receptionType} onChange={e => setFormData({...formData, receptionType: e.target.value as any})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-2xl font-bold">
                     <option value="Consignación">Consignación</option>
                     <option value="Compra Directa">Compra Directa</option>
                  </select>
                </div>
              </>
            )}
            <div className="space-y-2">
              <label className="text-[11px] font-black uppercase text-gray-400">{isReception ? 'Cantidad de Entrada' : 'Stock en Almacén'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-2xl font-bold text-xl" />
            </div>
            <div className="space-y-2">
              <label className="text-[11px] font-black uppercase text-gray-400">Costo de Inversión (Unidad)</label>
              <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-2xl font-bold text-xl" />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[11px] font-black uppercase text-gray-400">Descripción Detallada (Autoajustable)</label>
            <textarea 
              value={formData.description} 
              onChange={e => {
                setFormData({...formData, description: e.target.value});
                e.target.style.height = 'auto';
                e.target.style.height = e.target.scrollHeight + 'px';
              }} 
              placeholder="Escriba aquí los detalles, beneficios y categorías del producto..."
              className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-3xl font-medium text-lg min-h-[120px] resize-none overflow-hidden transition-all focus:ring-4 ring-[#AF6E4D]/10 outline-none" 
            />
          </div>

          {!isReception && (
            <div className="space-y-12">
              <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
                <h4 className="text-[11px] font-black uppercase text-[#AF6E4D] mb-6 flex items-center gap-2 tracking-widest"><DollarSign size={16}/> Definición de Precios</h4>
                <div className="flex gap-4">
                  <div className="flex-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase">Precio Unidad Suelta</label>
                    <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="w-full p-5 bg-white border border-[#D7CCC8]/40 rounded-2xl font-bold text-xl" />
                  </div>
                  <div className="w-32">
                    <label className="text-[10px] font-black text-gray-400 uppercase">Moneda</label>
                    <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as Currency})} className="w-full p-5 bg-white border border-[#D7CCC8]/40 rounded-2xl font-bold text-xl">
                      <option value="CUP">CUP</option>
                      <option value="USD">USD</option>
                    </select>
                  </div>
                </div>
              </div>

