                    <input type="number" placeholder="Unidades x Pack" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-xl text-xs font-bold" />
