                    <input placeholder="Nombre Oferta..." value={tempOffer.label} onChange={e => setTempOffer({...tempOffer, label: e.target.value})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-xl text-xs font-bold col-span-2" />
                    <input type="number" placeholder="Precio Unidad" value={tempOffer.price || ''} onChange={e => setTempOffer({...tempOffer, price: parseFloat(e.target.value)})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-xl text-xs font-bold" />
