                        <button onClick={() => setFormData({...formData, offers: formData.offers?.filter(x => x.id !== o.id)})} className="text-rose-400 p-2 hover:bg-rose-50 rounded-full transition-all">×</button>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
        <div className="p-8 border-t flex justify-end gap-6 bg-white z-20 absolute bottom-0 left-0 right-0 shadow-[0_-20px_50px_rgba(0,0,0,0.05)]">
