                    <div className="flex flex-col items-center"><div className="w-20 h-20 bg-[#FCF9F7] rounded-[30px] flex items-center justify-center text-[#AF6E4D] shadow-sm mb-6"><Package size={40}/></div><p className="text-[12px] font-black uppercase text-gray-400 tracking-[0.2em]">Excelencia</p></div>
                 </div>
              </div>
           </div>
        </div>
