                         <div className="w-14 h-14 bg-[#F5F5DC] rounded-2xl flex items-center justify-center text-[#AF6E4D]"><Tag size={24}/></div>
                         <p className="text-[10px] font-black text-gray-400 bg-gray-50 px-4 py-2 rounded-full uppercase">SKU: {p.sku}</p>
