              </thead>
              <tbody className="divide-y text-[#3E2723]">
                {products.length === 0 ? (
                  <tr><td colSpan={6} className="py-40 text-center text-gray-300 font-black uppercase tracking-[0.3em]">No hay existencias registradas</td></tr>
