                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-12 py-10 max-w-[400px]">
                       <p className="font-black uppercase text-lg">{p.name}</p>
                       <p className="text-[11px] text-gray-400 font-medium line-clamp-1 mt-1">{p.description || 'Sin descripción.'}</p>
