                    <td className="px-10 py-10 text-center font-black text-[#AF6E4D] text-lg">${p.unitPrice.toLocaleString()}</td>
                    <td className="px-10 py-10 text-center font-black text-emerald-500 text-lg">${(p.unitPrice - p.costPrice).toLocaleString()}</td>
                    <td className="px-12 py-10 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="p-5 bg-[#F5F5DC] rounded-3xl hover:bg-[#3E2723] hover:text-white transition-all"><BarChart size={24}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="max-w-5xl mx-auto py-12">
           <div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 shadow-2xl overflow-hidden relative">
