                 <div>
                    <h2 className="text-5xl font-black text-[#3E2723] uppercase tracking-tighter">Entrada de Mercancía</h2>
                    <p className="text-lg font-bold text-[#8D6E63] mt-2">Registrar lotes de proveedores en consignación o compra.</p>
                 </div>
              </div>
              <ProductForm 
                 mode="reception" 
                 onSave={p => {
                    const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
                    let list = [...products];
                    const lot: ReceptionLot = {
                      id: Math.random().toString(), date: new Date().toISOString(), supplierId: p.supplierId || 'Anónimo', receptionType: p.receptionType,
                      quantityReceived: p.stock, currentStock: p.stock, unitCost: p.costPrice, transportCost: 0, totalInvestment: (p.stock * p.costPrice)
                    };
                    if (idx > -1) {
                       list[idx] = { ...list[idx], stock: list[idx].stock + p.stock, costPrice: p.costPrice, lots: [...(list[idx].lots || []), lot] };
                    } else {
                       list = [{ ...p, id: Math.random().toString(), sku: `PATI-${Date.now().toString().slice(-4)}`, groupings: [], offers: [], lots: [lot] }, ...list];
                    }
                    setProducts(list);
                    alert("¡Lote registrado correctamente!");
                    setActiveTab('inventory');
                 }}
                 onCancel={() => setActiveTab('catalog')}
              />
           </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex flex-col lg:flex-row h-auto lg:h-[calc(100vh-140px)] gap-10 animate-in zoom-in-95 max-w-[1800px] mx-auto">
