import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot, Offer 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  FileText, History, Info, Facebook, Instagram, Mail, Globe, Settings, Copy, TrendingUp, Percent,
  Users, Receipt, Heart, Share2, ExternalLink, Eye, BarChart, Calendar, ChevronRight
} from 'lucide-react';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v8_products',
  CONTACTS: 'pati_v8_contacts',
  TRANSACTIONS: 'pati_v8_transactions',
  CONFIG: 'pati_v8_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "logo.jpeg",
  storeName: "PaTí",
  aboutText: "PaTí es compromiso total con la comunidad. Nos enorgullece ser el puente entre los mejores productores y su hogar, ofreciendo una selección curada que abarca desde alimentos frescos del campo y productos de aseo de alta gama hasta artículos de ferretería y hogar. Creemos en el comercio justo, la transparencia en la gestión de consignaciones y, sobre todo, en brindar soluciones cotidianas con la calidad que usted y su familia merecen.",
  address: "Calle Real #123, Habana Vieja, Cuba",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/mercadopati",
  instagramUrl: "https://instagram.com/mercadopati",
  websiteUrl: "https://mercadopati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'catalog' | 'reception'}>({show: false, mode: 'catalog'});
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence logic
  useEffect(() => {
    const load = () => {
      const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
      const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
      const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
      const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

      if (p) setProducts(JSON.parse(p));
      if (c) setContacts(JSON.parse(c));
      if (t) setTransactions(JSON.parse(t));
      if (cfg) setConfig(JSON.parse(cfg));

      setIsDataReady(true);
    };
    load();
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  // Daily Closure Calculations
  const todayTransactions = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    return transactions.filter(t => t.date.split('T')[0] === today && t.status === 'Despachado');
  }, [transactions]);

  const dailyTotals = useMemo(() => {
    return todayTransactions.reduce((acc, t) => {
      acc.cup += t.totalCup;
      acc.usd += t.totalUsd;
      if (t.paymentMethod === 'Efectivo') acc.efectivo += t.totalCup;
      else acc.transferencia += t.totalCup;
      return acc;
    }, { cup: 0, usd: 0, efectivo: 0, transferencia: 0 });
  }, [todayTransactions]);

  const exportData = () => {
    const data = { products, contacts, transactions, config, backupDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `PaTi_Master_Backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const data = JSON.parse(evt.target?.result as string);
        if (data.products) setProducts(data.products);
        if (data.contacts) setContacts(data.contacts);
        if (data.transactions) setTransactions(data.transactions);
        if (data.config) setConfig(data.config);
        alert("Sincronización completa. Datos restaurados.");
      } catch (err) { alert("Error de formato de archivo."); }
    };
    reader.readAsText(file);
  };

  const filteredProducts = useMemo(() => {
    const query = posSearch.toLowerCase().trim();
    return products.filter(p => p.name.toLowerCase().includes(query) || p.sku.toLowerCase().includes(query));
  }, [products, posSearch]);

  const addToCart = (p: Product, variant?: GroupingPrice | Offer) => {
    const isOffer = variant && 'startDate' in variant;
    const isGrouping = variant && 'quantity' in variant && !isOffer;
    const unitsPerPack = isGrouping ? (variant as GroupingPrice).quantity : 1;
    const minToBuy = isGrouping ? (variant as GroupingPrice).minOrderQuantity : 1;
    const pricePerUnit = variant ? variant.price : p.unitPrice;

    if (p.stock < unitsPerPack * minToBuy) { alert("Stock insuficiente."); return; }

    const vId = variant ? variant.id : 'unit';
    const itemId = `${p.id}-${vId}`;
    const existing = cart.find(i => i.id === itemId);

    if (existing) {
      setCart(cart.map(item => item.id === itemId ? { ...item, quantity: item.quantity + 1, unitQuantity: (item.quantity + 1) * unitsPerPack, total: (item.quantity + 1) * unitsPerPack * pricePerUnit } : item));
    } else {
      const initUnits = minToBuy * unitsPerPack;
      setCart([...cart, {
        id: itemId, productId: p.id, productName: p.name, groupingId: vId,
        groupingLabel: variant?.label || 'Unidad', quantity: minToBuy, price: pricePerUnit,
        total: initUnits * pricePerUnit, currency: variant?.currency || p.unitCurrency,
        unitQuantity: initUnits
      }]);
    }
  };

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);
    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Consumidor Final',
      items: [...cart], totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'SOL' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };
    if (status === 'Despachado') {
      setProducts(products.map(p => {
        const sold = cart.filter(i => i.productId === p.id).reduce((a, b) => a + b.unitQuantity, 0);
        return { ...p, stock: Math.max(0, p.stock - sold) };
      }));
    }
    setTransactions([newTx, ...transactions]);
    setCart([]);
    setSelectedInvoice(newTx);
  };

  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'catalog' | 'reception', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', description: '', stock: 0, costPrice: 0, unitPrice: 0, unitCurrency: 'CUP', groupings: [], offers: [], supplierId: '', receptionType: 'Consignación'
    });
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 1, price: 0, currency: 'CUP', minOrderQuantity: 1 });
    const [tempOffer, setTempOffer] = useState<Offer>({ id: '', label: '', price: 0, currency: 'CUP', startDate: '', endDate: '' });

    // Reception Auto-complete
    const handleNameChange = (name: string) => {
      setFormData({ ...formData, name });
      if (mode === 'reception') {
        const existing = products.find(p => p.name.toLowerCase() === name.toLowerCase());
        if (existing) setFormData({ ...formData, name: existing.name, description: existing.description, sku: existing.sku, supplierId: existing.supplierId, costPrice: existing.costPrice });
      }
    };

    return (
      <div className="flex flex-col h-full bg-white relative">
        <div className="flex-1 overflow-y-auto p-10 space-y-12 custom-scrollbar pb-40">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            <div className="md:col-span-2 space-y-3">
              <label className="text-xs font-black uppercase text-gray-400">Nombre del Producto</label>
              <input value={formData.name} onChange={e => handleNameChange(e.target.value)} className="w-full p-6 bg-[#FCF9F7] border-2 border-[#D7CCC8]/40 rounded-3xl font-black text-2xl outline-none focus:border-[#AF6E4D]" list="existing-products" />
              <datalist id="existing-products">{products.map(p => <option key={p.id} value={p.name} />)}</datalist>
            </div>
            {mode === 'reception' && (
              <div className="space-y-3">
                <label className="text-xs font-black uppercase text-gray-400">Proveedor Origen</label>
                <select value={formData.supplierId} onChange={e => setFormData({ ...formData, supplierId: e.target.value })} className="w-full p-6 bg-[#FCF9F7] border-2 border-[#D7CCC8]/40 rounded-3xl font-bold text-xl">
                  <option value="">Seleccionar...</option>
                  {contacts.filter(c => c.type === 'Proveedor').map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>
            )}
            <div className="space-y-3">
              <label className="text-xs font-black uppercase text-gray-400">{mode === 'reception' ? 'Ingreso Unidades' : 'Total Unidades'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({ ...formData, stock: parseInt(e.target.value) })} className="w-full p-6 bg-[#FCF9F7] border-2 border-[#D7CCC8]/40 rounded-3xl font-black text-2xl" />
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-xs font-black uppercase text-gray-400">Descripción Maestra</label>
            <textarea 
              value={formData.description} 
              onChange={e => { setFormData({ ...formData, description: e.target.value }); e.target.style.height = 'auto'; e.target.style.height = e.target.scrollHeight + 'px'; }} 
              className="w-full p-8 bg-[#FCF9F7] border-2 border-[#D7CCC8]/40 rounded-[40px] font-medium text-xl min-h-[150px] resize-none outline-none focus:border-[#AF6E4D]" 
            />
          </div>

          {mode === 'catalog' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="bg-[#FCF9F7] p-10 rounded-[50px] border-2 border-[#D7CCC8]/20">
                <h4 className="text-xs font-black uppercase text-[#AF6E4D] mb-8 flex items-center gap-3"><DollarSign size={20}/> Precios por Escala</h4>
                <div className="grid grid-cols-2 gap-4 mb-6">
                  <input placeholder="Nombre (Bulto, Caja...)" value={tempGrouping.label} onChange={e => setTempGrouping({ ...tempGrouping, label: e.target.value })} className="p-4 bg-white border rounded-2xl font-bold" />
                  <input type="number" placeholder="Precio Unidad" value={tempGrouping.price || ''} onChange={e => setTempGrouping({ ...tempGrouping, price: parseFloat(e.target.value) })} className="p-4 bg-white border rounded-2xl font-bold" />
                  <input type="number" placeholder="Unid x Escala" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({ ...tempGrouping, quantity: parseInt(e.target.value) })} className="p-4 bg-white border rounded-2xl font-bold" />
                  <input type="number" placeholder="Mínimo Venta" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({ ...tempGrouping, minOrderQuantity: parseInt(e.target.value) })} className="p-4 bg-white border rounded-2xl font-bold" />
                </div>
                <button onClick={() => { if (!tempGrouping.label) return; setFormData({ ...formData, groupings: [...(formData.groupings || []), { ...tempGrouping, id: Math.random().toString() }] }); setTempGrouping({ id: '', label: '', quantity: 1, price: 0, currency: 'CUP', minOrderQuantity: 1 }); }} className="w-full py-5 bg-[#3E2723] text-white rounded-2xl font-black uppercase text-xs shadow-xl">+ Añadir Escala</button>
                <div className="mt-10 space-y-4">
                  {formData.groupings?.map(g => (
                    <div key={g.id} className="bg-white p-6 rounded-3xl flex justify-between items-center shadow-sm">
                      <div className="text-xs font-black uppercase"><p>{g.label}</p><p className="text-gray-400 mt-1">{g.quantity}u | Min {g.minOrderQuantity} packs | ${g.price}/u</p></div>
                      <button onClick={() => setFormData({ ...formData, groupings: formData.groupings?.filter(x => x.id !== g.id) })} className="text-rose-400 text-2xl font-black px-4">×</button>
                    </div>
                  ))}
                </div>
              </div>
              <div className="bg-[#FCF9F7] p-10 rounded-[50px] border-2 border-[#D7CCC8]/20">
                <h4 className="text-xs font-black uppercase text-[#AF6E4D] mb-8 flex items-center gap-3"><Percent size={20}/> Ofertas Activas</h4>
                <div className="grid grid-cols-2 gap-4 mb-6">
                  <input placeholder="Campaña..." value={tempOffer.label} onChange={e => setTempOffer({ ...tempOffer, label: e.target.value })} className="p-4 bg-white border rounded-2xl font-bold col-span-2" />
                  <input type="number" placeholder="Precio" value={tempOffer.price || ''} onChange={e => setTempOffer({ ...tempOffer, price: parseFloat(e.target.value) })} className="p-4 bg-white border rounded-2xl font-bold" />
                  <div className="grid grid-cols-2 gap-2 col-span-2">
                    <input type="date" value={tempOffer.startDate} onChange={e => setTempOffer({ ...tempOffer, startDate: e.target.value })} className="p-3 bg-white border rounded-xl text-xs font-bold" />
                    <input type="date" value={tempOffer.endDate} onChange={e => setTempOffer({ ...tempOffer, endDate: e.target.value })} className="p-3 bg-white border rounded-xl text-xs font-bold" />
                  </div>
                </div>
                <button onClick={() => { if (!tempOffer.label) return; setFormData({ ...formData, offers: [...(formData.offers || []), { ...tempOffer, id: Math.random().toString() }] }); setTempOffer({ id: '', label: '', price: 0, currency: 'CUP', startDate: '', endDate: '' }); }} className="w-full py-5 bg-[#AF6E4D] text-white rounded-2xl font-black uppercase text-xs shadow-xl">+ Activar Oferta</button>
                <div className="mt-10 space-y-4">
                  {formData.offers?.map(o => (
                    <div key={o.id} className="bg-white p-6 rounded-3xl flex justify-between items-center shadow-sm border border-emerald-100">
                      <div className="text-xs font-black uppercase"><p>{o.label} - ${o.price}</p><p className="text-emerald-500 mt-1">Del {o.startDate} al {o.endDate}</p></div>
                      <button onClick={() => setFormData({ ...formData, offers: formData.offers?.filter(x => x.id !== o.id) })} className="text-rose-400 text-2xl font-black px-4">×</button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
        <div className="p-10 border-t bg-white flex justify-end gap-6 shadow-[0_-20px_50px_rgba(0,0,0,0.05)] absolute bottom-0 left-0 right-0 z-30">
          <button onClick={onCancel} className="px-12 py-6 text-gray-400 font-black uppercase text-xs tracking-widest">Descartar</button>
          <button onClick={() => onSave({ ...formData } as Product)} className="bg-[#3E2723] text-white px-20 py-6 rounded-3xl font-black uppercase text-xs shadow-2xl tracking-widest flex items-center gap-4"><Save size={24}/> Sincronizar Ficha</button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n))}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'about' && (
        <div className="h-full flex items-center justify-center p-10 animate-in fade-in duration-1000">
          <div className="bg-white rounded-[80px] border border-[#D7CCC8]/30 shadow-2xl p-24 text-center max-w-7xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-96 h-96 bg-[#F5F5DC] rounded-full -mr-48 -mt-48 opacity-40 blur-3xl"></div>
            <img src={config.logoUrl} className="h-40 w-auto bg-[#3E2723] p-10 rounded-[50px] mx-auto mb-16 shadow-2xl" />
            <h2 className="text-7xl font-black text-[#3E2723] uppercase mb-12 tracking-tighter leading-none">PaTí es compromiso total con la comunidad</h2>
            <p className="text-4xl font-serif text-[#AF6E4D] italic mb-20">"Calidad y servicio cercano en cada rincón."</p>
            <div className="w-40 h-2 bg-[#3E2723] mx-auto mb-20 rounded-full"></div>
            <p className="text-2xl text-[#3E2723] font-medium leading-relaxed text-justify max-w-5xl mx-auto">{config.aboutText}</p>
          </div>
        </div>
      )}

      {activeTab === 'catalog' && (
        <div className="space-y-12 animate-in fade-in max-w-none">
          <div className="flex justify-between items-end bg-white p-12 rounded-[50px] shadow-sm">
            <div><h2 className="text-6xl font-black text-[#3E2723] uppercase tracking-tighter">Catálogo Maestro</h2><p className="text-2xl text-gray-400 font-bold mt-4">Definición estratégica de productos y escalas.</p></div>
            <button onClick={() => setProductModal({ show: true, mode: 'catalog' })} className="bg-[#3E2723] text-white px-16 py-8 rounded-[35px] font-black text-sm uppercase shadow-2xl flex items-center gap-6 hover:scale-105 transition-all"><Plus size={32}/> Nueva Ficha</button>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-10">
            {products.map(p => (
              <div key={p.id} className="bg-white p-12 rounded-[60px] border border-[#D7CCC8]/20 hover:shadow-2xl transition-all group flex flex-col justify-between min-h-[500px]">
                <div>
                  <div className="flex justify-between items-start mb-8"><div className="w-16 h-16 bg-[#F5F5DC] rounded-2xl flex items-center justify-center text-[#AF6E4D]"><Tag size={32}/></div><p className="text-xs font-black text-gray-400 uppercase tracking-widest">{p.sku}</p></div>
                  <h3 className="text-3xl font-black text-[#3E2723] uppercase leading-none group-hover:text-[#AF6E4D] transition-colors mb-6">{p.name}</h3>
                  <p className="text-lg text-gray-500 font-medium line-clamp-4 leading-relaxed">{p.description || 'Sin descripción técnica.'}</p>
                </div>
                <div className="mt-10 pt-10 border-t-2 border-dashed border-[#D7CCC8]/40 space-y-4">
                  <div className="flex justify-between items-center text-xs font-black uppercase text-[#3E2723]"><span>Precio Base</span><span className="text-3xl tracking-tighter">${p.unitPrice}</span></div>
                  <button onClick={() => setProductModal({ show: true, product: p, mode: 'catalog' })} className="w-full py-6 bg-[#3E2723] text-white rounded-[30px] font-black text-xs uppercase shadow-xl flex items-center justify-center gap-4">Editar Catálogo <ChevronRight size={20}/></button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-12 animate-in fade-in max-w-none">
          <div className="flex justify-between items-end bg-white p-12 rounded-[50px] shadow-sm">
            <div><h2 className="text-6xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario Físico</h2><p className="text-2xl text-gray-400 font-bold mt-4">Control de existencias y valorización de almacén.</p></div>
            <div className="p-10 bg-[#3E2723] rounded-[40px] text-white text-center shadow-2xl min-w-[400px]">
              <p className="text-xs font-black uppercase opacity-50 mb-3 tracking-widest">Valor de Almacén (CUP)</p>
              <p className="text-5xl font-black tracking-tighter">{products.reduce((acc, p) => acc + (p.stock * p.costPrice), 0).toLocaleString()} <span className="text-xl opacity-30 ml-2">CUP</span></p>
            </div>
          </div>
          <div className="bg-white rounded-[60px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b-4 border-[#D7CCC8]/30 text-xs font-black uppercase text-[#AF6E4D]">
                <tr><th className="px-14 py-12">Detalle de Producto</th><th className="px-10 py-12 text-center">Existencia</th><th className="px-10 py-12 text-center">Costo Unit</th><th className="px-10 py-12 text-center">Venta Base</th><th className="px-10 py-12 text-center">Margen</th><th className="px-14 py-12 text-right">Ficha</th></tr>
              </thead>
              <tbody className="divide-y text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors font-bold text-xl">
                    <td className="px-14 py-12"><p className="font-black uppercase text-2xl">{p.name}</p><p className="text-sm text-gray-400 mt-2 line-clamp-1">{p.description}</p></td>
                    <td className={`px-10 py-12 text-center text-5xl font-black ${p.stock <= p.minStock ? 'text-rose-500' : ''}`}>{p.stock}</td>
                    <td className="px-10 py-12 text-center text-gray-400">${p.costPrice.toLocaleString()}</td>
                    <td className="px-10 py-12 text-center text-[#AF6E4D]">${p.unitPrice.toLocaleString()}</td>
                    <td className="px-10 py-12 text-center text-emerald-500 font-black">${(p.unitPrice - p.costPrice).toLocaleString()}</td>
                    <td className="px-14 py-12 text-right"><button onClick={() => setProductModal({ show: true, product: p, mode: 'catalog' })} className="p-6 bg-[#F5F5DC] rounded-3xl hover:bg-[#3E2723] hover:text-white transition-all shadow-md"><BarChart size={30}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="max-w-7xl mx-auto py-12">
          <div className="bg-white rounded-[80px] border border-[#D7CCC8]/30 shadow-2xl overflow-hidden">
            <div className="p-16 bg-[#F5F5DC]/30 border-b flex items-center gap-12">
              <div className="p-10 bg-[#3E2723] rounded-[45px] text-white shadow-2xl"><Truck size={60}/></div>
              <div><h2 className="text-6xl font-black text-[#3E2723] uppercase tracking-tighter">Ingreso de Mercancía</h2><p className="text-2xl font-bold text-[#8D6E63] mt-4">Actualizar stock o crear nuevos productos por lotes.</p></div>
            </div>
            <ProductForm mode="reception" onSave={p => {
              const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
              let list = [...products];
              if (idx > -1) list[idx] = { ...list[idx], stock: list[idx].stock + p.stock, costPrice: p.costPrice };
              else list = [{ ...p, id: Math.random().toString(), sku: `PATI-${Date.now().toString().slice(-4)}`, groupings: [], offers: [] }, ...list];
              setProducts(list); alert("Mercancía ingresada correctamente."); setActiveTab('inventory');
            }} onCancel={() => setActiveTab('catalog')} />
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex h-full gap-12 animate-in zoom-in-95 max-w-none">
          <div className="flex-1 bg-white rounded-[60px] border p-12 flex flex-col shadow-2xl">
            <div className="flex justify-between items-center mb-16 gap-10">
              <div><h2 className="text-5xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal PaTí</h2><p className="text-xl font-bold text-gray-400 mt-2 uppercase tracking-widest">Selección y Despacho</p></div>
              <div className="relative w-full max-w-xl"><Search className="absolute left-8 top-8 text-[#D7CCC8]" size={30}/><input placeholder="Buscar producto..." className="w-full pl-20 pr-10 py-8 bg-[#FCF9F7] rounded-[40px] font-black border-none outline-none focus:ring-4 ring-[#AF6E4D]/10 text-2xl shadow-inner" value={posSearch} onChange={e => setPosSearch(e.target.value)} /></div>
            </div>
            <div className="flex-1 overflow-y-auto grid grid-cols-1 md:grid-cols-2 gap-10 custom-scrollbar pr-6 pb-6">
              {filteredProducts.map(p => (
                <div key={p.id} className="bg-[#FCF9F7] p-12 rounded-[60px] border-2 border-[#D7CCC8]/10 hover:border-[#AF6E4D] transition-all flex flex-col justify-between min-h-[500px] shadow-sm">
                  <div><h3 className="text-3xl font-black uppercase text-[#3E2723] mb-4">{p.name}</h3><p className="text-xs font-black text-gray-400 uppercase tracking-widest mb-6">Stock: {p.stock} U.</p><p className="text-xl text-gray-500 font-medium leading-relaxed line-clamp-3">{p.description}</p></div>
                  <div className="mt-12 space-y-5">
                    <button onClick={() => addToCart(p)} className="w-full py-7 bg-[#3E2723] text-white rounded-[35px] font-black text-lg uppercase shadow-xl hover:bg-[#AF6E4D] transition-all">Unidad: ${p.unitPrice}</button>
                    {p.groupings?.map(g => (
                      <button key={g.id} onClick={() => addToCart(p, g)} className="w-full py-6 px-8 bg-white border-2 border-[#D7CCC8]/30 rounded-[35px] text-xs font-black uppercase hover:bg-[#3E2723] hover:text-white transition-all flex justify-between items-center shadow-sm"><span>{g.label} (Min {g.minOrderQuantity})</span><span>${g.price}/u</span></button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-[500px] bg-[#3E2723] rounded-[60px] p-12 text-white flex flex-col shadow-2xl relative">
            <h3 className="text-xs font-black uppercase tracking-[0.3em] mb-12 text-[#AF6E4D] flex items-center gap-4"><ShoppingCart size={30}/> Carrito de Venta</h3>
            <div className="flex-1 overflow-y-auto space-y-6 custom-scrollbar pr-4">
              {cart.map(i => (
                <div key={i.id} className="bg-white/5 p-8 rounded-[40px] border border-white/10 flex justify-between items-center animate-in slide-in-from-right-10">
                  <div className="flex-1 pr-6"><p className="text-lg font-black uppercase">{i.productName}</p><p className="text-xs font-bold text-[#AF6E4D] uppercase mt-2">{i.groupingLabel} (x{i.quantity})</p></div>
                  <div className="flex items-center gap-6"><p className="font-black text-2xl tracking-tighter">{i.total.toLocaleString()}</p><button onClick={() => removeFromCart(i.id)} className="text-rose-400 p-4 hover:bg-rose-400/10 rounded-full transition-all"><Trash2 size={24}/></button></div>
                </div>
              ))}
            </div>
            <div className="pt-12 border-t border-white/10 space-y-10">
              <div className="flex justify-between items-end"><p className="text-xs font-black uppercase opacity-40 tracking-[0.3em]">Total CUP</p><p className="text-7xl font-black tracking-tighter">{cart.reduce((a, b) => a + b.total, 0).toLocaleString()} <span className="text-xl opacity-20 ml-2">CUP</span></p></div>
              <div className="flex flex-col gap-4">
                <button onClick={() => setPaymentMethod(paymentMethod === 'Efectivo' ? 'Transferencia' : 'Efectivo')} className="py-5 bg-white/10 rounded-[30px] font-black uppercase text-xs border border-white/10">{paymentMethod}</button>
                <div className="flex gap-4">
                  <button onClick={() => processTransaction('Solicitud')} disabled={cart.length === 0} className="flex-1 py-7 bg-white/10 rounded-[35px] font-black uppercase text-xs border border-white/10">Solicitud</button>
