      {activeTab === 'maintenance' && (
        <div className="h-full flex items-center justify-center p-10">
          <div className="bg-white p-32 rounded-[80px] border border-[#D7CCC8]/30 shadow-2xl text-center flex flex-col items-center max-w-5xl">
            <Database size={120} className="text-[#AF6E4D] mb-12" />
            <h2 className="text-6xl font-black text-[#3E2723] uppercase mb-16 tracking-tighter">Bases de Datos</h2>
            <div className="grid grid-cols-2 gap-12 w-full">
              <button onClick={exportData} className="p-20 bg-[#FCF9F7] border-2 border-[#D7CCC8]/30 rounded-[60px] flex flex-col items-center gap-6 group hover:bg-[#3E2723] hover:text-white transition-all shadow-xl"><Download size={80} className="group-hover:scale-110 transition-transform"/><span className="text-xs font-black uppercase tracking-widest">Descargar Respaldo</span></button>
              <button onClick={() => fileInputRef.current?.click()} className="p-20 bg-[#FCF9F7] border-2 border-[#D7CCC8]/30 rounded-[60px] flex flex-col items-center gap-6 group hover:bg-[#3E2723] hover:text-white transition-all shadow-xl"><Upload size={80} className="group-hover:scale-110 transition-transform"/><span className="text-xs font-black uppercase tracking-widest">Importar Respaldo</span></button>
              <input type="file" ref={fileInputRef} onChange={importData} accept=".json" className="hidden" />
            </div>
          </div>
        </div>
      )}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/98 z-[500] flex items-center justify-center p-10 backdrop-blur-3xl animate-in fade-in">
          <div className="bg-white rounded-[80px] w-full h-full max-w-none shadow-2xl overflow-hidden flex flex-col border-b-[30px] border-[#3E2723] relative animate-in slide-in-from-bottom-20">
            <div className="p-16 border-b flex justify-between items-center bg-[#F5F5DC]/40 sticky top-0 z-40">
              <div className="flex items-center gap-10"><Package size={70} className="text-[#AF6E4D]"/><h2 className="text-5xl font-black uppercase text-[#3E2723] tracking-tighter">{productModal.mode === 'catalog' ? 'Edición de Catálogo' : 'Registro de Entrada'}</h2></div>
              <button onClick={() => setProductModal({ show: false, mode: 'catalog' })} className="p-6 bg-white rounded-full text-rose-400 hover:rotate-90 hover:scale-110 transition-all shadow-xl"><X size={50} /></button>
            </div>
            <ProductForm mode={productModal.mode} initialData={productModal.product} onSave={p => {
              const idx = products.findIndex(x => (x.id === p.id) || (x.name.toLowerCase() === p.name.toLowerCase()));
              let list = [...products];
              if (idx > -1) list[idx] = { ...list[idx], ...p };
              else list = [{ ...p, id: Math.random().toString(), sku: `PATI-${Date.now().toString().slice(-4)}` }, ...list];
              setProducts(list); setProductModal({ show: false, mode: 'catalog' });
            }} onCancel={() => setProductModal({ show: false, mode: 'catalog' })} />
          </div>
        </div>
      )}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/98 z-[600] flex items-center justify-center p-10 backdrop-blur-3xl animate-in fade-in">
          <div className="bg-white rounded-[80px] w-full max-w-5xl shadow-2xl p-24 animate-in slide-in-from-bottom-24">
            <div className="flex justify-between items-start mb-24">
              <div className="bg-[#3E2723] p-12 rounded-[50px] shadow-2xl"><img src={config.logoUrl} className="h-32 w-auto brightness-200" /></div>
              <div className="text-right"><p className="text-xs font-black uppercase text-gray-400 tracking-[0.4em] mb-4">Número de Operación</p><p className="text-7xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.invoiceNumber}</p></div>
            </div>
            <div className="max-h-[500px] overflow-y-auto custom-scrollbar pr-10">
              <table className="w-full text-left">
                <thead className="border-b-8 border-[#3E2723] text-xs uppercase font-black text-gray-400 tracking-widest"><tr><th className="py-10">Detalle</th><th className="py-10 text-center">Cant.</th><th className="py-10 text-right">Subtotal</th></tr></thead>
                <tbody className="divide-y font-bold text-2xl uppercase">
                  {selectedInvoice.items.map((i, idx) => (
                    <tr key={idx}><td className="py-10"><p className="font-black text-[#3E2723]">{i.productName}</p><p className="text-xs text-[#AF6E4D] mt-2">{i.groupingLabel}</p></td><td className="py-10 text-center text-4xl">{i.quantity}</td><td className="py-10 text-right tabular-nums">{i.total.toLocaleString()} {i.currency}</td></tr>
                  ))}
                </tbody>
              </table>
              <div className="pt-20 border-t-8 border-[#3E2723] flex justify-between items-end mt-20">
                <p className="text-xl font-black uppercase text-gray-400 tracking-[0.3em]">Importe Final Liquidado</p>
                <p className="text-9xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-2xl opacity-20 ml-4">CUP</span></p>
              </div>
            </div>
            <div className="mt-24 flex justify-center gap-12">
              <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-32 py-10 rounded-[50px] font-black uppercase text-sm shadow-2xl flex items-center justify-center gap-8 hover:scale-105 transition-all"><Printer size={50}/> Imprimir Factura</button>
              <button onClick={() => setSelectedInvoice(null)} className="px-20 py-10 font-black uppercase text-sm text-gray-400 hover:text-[#3E2723] transition-all">Cerrar Visor</button>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot, Offer 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  FileText, History, Info, Facebook, Instagram, Mail, Globe, Settings, Copy, TrendingUp, Percent,
  Users, Receipt, Heart, Share2, ExternalLink, Eye, BarChart, Calendar, ChevronRight
} from 'lucide-react';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v9_products',
  CONTACTS: 'pati_v9_contacts',
  TRANSACTIONS: 'pati_v9_transactions',
  CONFIG: 'pati_v9_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "logo.jpeg",
  storeName: "PaTí",
  aboutText: "Compromiso total con la comunidad. Gestión transparente de consignaciones y ventas directas.",
  address: "Calle Real #123, Habana Vieja, Cuba",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "", instagramUrl: "", websiteUrl: ""
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'catalog' | 'reception'}>({show: false, mode: 'catalog'});
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (cfg) setConfig(JSON.parse(cfg));

    setIsDataReady(true);
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  const filteredProducts = useMemo(() => {
    const query = posSearch.toLowerCase().trim();
    return products.filter(p => p.name.toLowerCase().includes(query) || p.sku.toLowerCase().includes(query));
  }, [products, posSearch]);

  const addToCart = (p: Product, variant?: GroupingPrice | Offer) => {
    const isOffer = variant && 'startDate' in variant;
    const isGrouping = variant && 'quantity' in variant && !isOffer;
    const unitsPerPack = isGrouping ? (variant as GroupingPrice).quantity : 1;
    const minToBuy = isGrouping ? (variant as GroupingPrice).minOrderQuantity : 1;
    const pricePerUnit = variant ? variant.price : p.unitPrice;

    if (p.stock < unitsPerPack * minToBuy) {
      alert("Stock insuficiente en inventario.");
      return;
    }

    const vId = variant ? variant.id : 'unit';
    const itemId = `${p.id}-${vId}`;
    const existing = cart.find(i => i.id === itemId);

    if (existing) {
      setCart(cart.map(item => item.id === itemId ? { 
        ...item, 
        quantity: item.quantity + 1, 
        unitQuantity: (item.quantity + 1) * unitsPerPack, 
        total: (item.quantity + 1) * unitsPerPack * pricePerUnit 
      } : item));
    } else {
      const initUnits = minToBuy * unitsPerPack;
      setCart([...cart, {
        id: itemId, productId: p.id, productName: p.name, groupingId: vId,
        groupingLabel: variant?.label || 'Unidad Suelta', quantity: minToBuy, price: pricePerUnit,
        total: initUnits * pricePerUnit, currency: variant?.currency || p.unitCurrency,
        unitQuantity: initUnits
      }]);
    }
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);
    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Consumidor Final',
      items: [...cart], totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'SOL' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };
    if (status === 'Despachado') {
      setProducts(prev => prev.map(p => {
        const sold = cart.filter(i => i.productId === p.id).reduce((a, b) => a + b.unitQuantity, 0);
        return { ...p, stock: Math.max(0, p.stock - sold) };
      }));
    }
    setTransactions(prev => [newTx, ...prev]);
    setCart([]);
    setSelectedInvoice(newTx);
  };

  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'catalog' | 'reception', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', description: '', stock: 0, costPrice: 0, unitPrice: 0, unitCurrency: 'CUP', groupings: [], offers: [], supplierId: '', receptionType: 'Consignación'
    });
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 1, price: 0, currency: 'CUP', minOrderQuantity: 1 });

    const handleNameChange = (name: string) => {
      setFormData({ ...formData, name });
      if (mode === 'reception') {
        const existing = products.find(p => p.name.toLowerCase() === name.toLowerCase());
        if (existing) {
          setFormData({ 
            ...formData, 
            name: existing.name, 
            description: existing.description, 
            sku: existing.sku, 
            unitPrice: existing.unitPrice, 
            costPrice: existing.costPrice,
            groupings: existing.groupings,
            unitCurrency: existing.unitCurrency
          });
        }
      }
    };

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="md:col-span-2">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Nombre del Producto</label>
              <input 
                value={formData.name} 
                onChange={e => handleNameChange(e.target.value)} 
                className="w-full p-2 border border-gray-300 rounded focus:ring-1 ring-[#3E2723] outline-none font-bold"
                placeholder="Ej: Aceite de Girasol"
                list="product-list"
              />
              <datalist id="product-list">{products.map(p => <option key={p.id} value={p.name} />)}</datalist>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Stock Actual / Entrada</label>
              <input 
                type="number" 
                value={formData.stock || ''} 
                onChange={e => setFormData({ ...formData, stock: parseInt(e.target.value) || 0 })} 
                className="w-full p-2 border border-gray-300 rounded"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Costo Unitario</label>
              <input 
                type="number" 
                value={formData.costPrice || ''} 
                onChange={e => setFormData({ ...formData, costPrice: parseFloat(e.target.value) || 0 })} 
                className="w-full p-2 border border-gray-300 rounded font-bold"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Descripción</label>
            <textarea 
              value={formData.description} 
              onChange={e => setFormData({ ...formData, description: e.target.value })} 
              className="w-full p-2 border border-gray-300 rounded min-h-[80px]"
              placeholder="Detalles del producto..."
            />
          </div>

          <div className="border-t pt-4">
            <h4 className="text-sm font-bold text-[#3E2723] uppercase mb-4">Configuración Comercial</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="p-4 bg-gray-50 border rounded">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Precio Unitario de Venta</label>
                <div className="flex gap-2">
                  <input 
                    type="number" 
                    value={formData.unitPrice || ''} 
                    onChange={e => setFormData({ ...formData, unitPrice: parseFloat(e.target.value) || 0 })} 
                    className="flex-1 p-2 border border-gray-300 rounded font-bold text-lg"
                  />
                  <select 
                    value={formData.unitCurrency} 
                    onChange={e => setFormData({ ...formData, unitCurrency: e.target.value as Currency })} 
                    className="p-2 border border-gray-300 rounded font-bold"
                  >
                    <option value="CUP">CUP</option>
                    <option value="USD">USD</option>
                  </select>
                </div>
              </div>

              <div className="p-4 bg-gray-50 border rounded">
                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Añadir Agrupación (Mayorista)</label>
                <div className="grid grid-cols-2 gap-2 mb-2">
                  <input placeholder="Nombre (Caja, Pack)" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="p-2 text-xs border rounded" />
                  <input type="number" placeholder="Precio x Unidad" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value) || 0})} className="p-2 text-xs border rounded" />
                  <input type="number" placeholder="Unidades en Agrupación" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 1})} className="p-2 text-xs border rounded" />
                  <input type="number" placeholder="Mínimo de Compra" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value) || 1})} className="p-2 text-xs border rounded" />
                </div>
                <button 
                  onClick={() => {
                    if (!tempGrouping.label) return;
                    setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                    setTempGrouping({id: '', label: '', quantity: 1, price: 0, currency: formData.unitCurrency || 'CUP', minOrderQuantity: 1});
                  }} 
                  className="w-full py-2 bg-[#AF6E4D] text-white text-xs font-bold uppercase rounded"
                >+ Agregar Agrupación</button>
              </div>
            </div>
          </div>

          {formData.groupings && formData.groupings.length > 0 && (
            <div className="mt-4">
              <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Agrupaciones Registradas</label>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                {formData.groupings.map(g => (
                  <div key={g.id} className="flex justify-between items-center p-2 bg-white border rounded text-xs">
                    <span>{g.label} - {g.quantity} Unidades - Min: {g.minOrderQuantity} - <b>${g.price}/u</b></span>
                    <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-red-500 font-bold px-2">X</button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="p-4 border-t bg-gray-50 flex justify-end gap-3">
          <button onClick={onCancel} className="px-4 py-2 text-gray-500 font-bold uppercase text-xs">Cancelar</button>
