            onClick={() => onSave(formData as Product)} 
            className="px-6 py-2 bg-[#3E2723] text-white font-bold uppercase text-xs rounded shadow flex items-center gap-2"
          ><Save size={16}/> {initialData ? 'Actualizar Ficha' : 'Guardar Nuevo Producto'}</button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n))}>

