          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {products.length === 0 ? (
              <div className="col-span-full py-20 text-center text-gray-300 font-bold uppercase">No hay productos en el catálogo</div>
            ) : products.map(p => (
              <div key={p.id} className="bg-white border rounded p-4 flex flex-col justify-between hover:shadow-md transition-shadow">
                <div>
                  <div className="flex justify-between items-start mb-2">
                    <span className="text-[10px] bg-gray-100 px-2 py-1 rounded font-bold text-gray-500">{p.sku || 'SIN SKU'}</span>
                    <button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="text-[#AF6E4D] hover:text-[#3E2723]"><Edit2 size={16}/></button>
                  </div>
                  <h3 className="font-bold text-[#3E2723] uppercase truncate mb-1">{p.name}</h3>
                  <p className="text-xs text-gray-500 line-clamp-2 mb-4">{p.description}</p>
                </div>
                <div className="border-t pt-2 mt-auto">
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400 font-bold">P. Unitario:</span>
                    <span className="font-black text-[#3E2723]">${p.unitPrice} {p.unitCurrency}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-6 animate-in fade-in">
          <div className="flex justify-between items-center border-b pb-4">
            <h2 className="text-xl font-bold text-[#3E2723] uppercase">Inventario de Almacén</h2>
            <div className="text-right">
              <p className="text-[10px] text-gray-400 font-bold uppercase">Inversión Total</p>
              <p className="text-lg font-black text-[#3E2723]">${products.reduce((a, b) => a + (b.stock * b.costPrice), 0).toLocaleString()} CUP</p>
            </div>
          </div>
          <div className="bg-white border rounded overflow-hidden">
            <table className="w-full text-left border-collapse">
              <thead className="bg-gray-50 border-b text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                <tr>
                  <th className="p-4">Producto</th>
                  <th className="p-4 text-center">Stock</th>
                  <th className="p-4 text-center">Costo Unit.</th>
                  <th className="p-4 text-center">Venta Unit.</th>
                  <th className="p-4 text-center">Margen</th>
                  <th className="p-4 text-right">Acción</th>
                </tr>
              </thead>
              <tbody className="divide-y text-xs font-medium">
                {products.length === 0 ? (
                  <tr><td colSpan={6} className="p-10 text-center text-gray-300 font-bold uppercase">Inventario vacío</td></tr>
                ) : products.map(p => (
                  <tr key={p.id} className="hover:bg-gray-50">
                    <td className="p-4 uppercase font-bold text-[#3E2723]">{p.name}</td>
                    <td className={`p-4 text-center font-black text-lg ${p.stock <= p.minStock ? 'text-red-500' : 'text-gray-700'}`}>{p.stock}</td>
                    <td className="p-4 text-center text-gray-400">${p.costPrice.toLocaleString()}</td>
                    <td className="p-4 text-center text-[#AF6E4D] font-bold">${p.unitPrice.toLocaleString()}</td>
                    <td className="p-4 text-center text-emerald-600 font-bold">${(p.unitPrice - p.costPrice).toLocaleString()}</td>
                    <td className="p-4 text-right">
                      <button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="text-gray-400 hover:text-[#3E2723]"><Edit2 size={16}/></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="max-w-3xl mx-auto py-6">
          <div className="bg-white border rounded shadow-sm overflow-hidden">
            <div className="p-4 bg-gray-50 border-b flex items-center gap-3">
              <Truck className="text-[#3E2723]" />
              <h2 className="font-bold text-[#3E2723] uppercase">Recepción de Mercancía</h2>
            </div>
            <ProductForm mode="reception" onSave={p => {
              const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
              let list = [...products];
              if (idx > -1) {
                list[idx] = { ...list[idx], ...p, stock: list[idx].stock + p.stock };
              } else {
                list = [{ ...p, id: Math.random().toString(), sku: `PA-${Date.now().toString().slice(-4)}`, groupings: p.groupings || [], offers: [] }, ...list];
              }
              setProducts(list);
              alert("Mercancía sincronizada correctamente.");
              setActiveTab('inventory');
            }} onCancel={() => setActiveTab('catalog')} />
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex h-[calc(100vh-140px)] gap-6 animate-in zoom-in-95">
          <div className="flex-1 bg-white border rounded p-6 flex flex-col shadow-sm">
