              <h2 className="text-lg font-bold text-[#3E2723] uppercase">Terminal de Ventas</h2>
              <div className="relative w-64">
                <Search className="absolute left-3 top-2.5 text-gray-400" size={16}/>
                <input 
                  placeholder="Buscar..." 
                  className="w-full pl-10 pr-4 py-2 bg-gray-50 border rounded text-sm" 
                  value={posSearch} 
                  onChange={e => setPosSearch(e.target.value)} 
                />
              </div>
            </div>
            <div className="flex-1 overflow-y-auto grid grid-cols-1 md:grid-cols-2 gap-4 pr-2">
              {filteredProducts.map(p => (
                <div key={p.id} className="border rounded p-4 flex flex-col justify-between hover:border-[#3E2723] transition-colors bg-gray-50">
                  <div>
                    <h3 className="font-bold text-[#3E2723] uppercase text-sm mb-1">{p.name}</h3>
                    <p className="text-[10px] font-bold text-gray-400 uppercase mb-2">Stock: {p.stock}</p>
                  </div>
                  <div className="space-y-2 mt-4">
                    <button onClick={() => addToCart(p)} className="w-full py-2 bg-[#3E2723] text-white rounded text-[10px] font-bold uppercase">Unidad: ${p.unitPrice}</button>
                    {p.groupings?.map(g => (
                      <button key={g.id} onClick={() => addToCart(p, g)} className="w-full py-1.5 bg-white border border-gray-300 text-gray-600 rounded text-[9px] font-bold uppercase flex justify-between px-3">
                        <span>{g.label} (x{g.quantity})</span>
                        <span>${g.price}/u</span>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-80 bg-[#3E2723] rounded p-6 text-white flex flex-col shadow-lg">
            <h3 className="text-[10px] font-bold uppercase tracking-widest mb-6 opacity-60">Carrito de Compra</h3>
            <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
              {cart.map(i => (
                <div key={i.id} className="bg-white/10 p-3 rounded border border-white/10 flex justify-between items-center text-xs">
                  <div className="flex-1 pr-2">
                    <p className="font-bold uppercase truncate">{i.productName}</p>
                    <p className="text-[9px] opacity-60 uppercase">{i.groupingLabel} x{i.quantity}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <p className="font-black">${i.total.toLocaleString()}</p>
                    <button onClick={() => removeFromCart(i.id)} className="text-red-400"><Trash2 size={14}/></button>
                  </div>
                </div>
              ))}
            </div>
            <div className="pt-6 border-t border-white/10 mt-4 space-y-4">
              <div className="flex justify-between items-end">
                <p className="text-[10px] font-bold uppercase opacity-40">Total CUP</p>
                <p className="text-4xl font-black tabular-nums tracking-tighter">{cart.reduce((a, b) => a + b.total, 0).toLocaleString()}</p>
              </div>
              <div className="space-y-2">
                <button onClick={() => setPaymentMethod(prev => prev === 'Efectivo' ? 'Transferencia' : 'Efectivo')} className="w-full py-2 bg-white/10 rounded text-[10px] font-bold uppercase border border-white/10">{paymentMethod}</button>
                <div className="flex gap-2">
                  <button onClick={() => processTransaction('Solicitud')} disabled={cart.length === 0} className="flex-1 py-3 bg-white/20 rounded text-[10px] font-bold uppercase">Solicitud</button>
                  <button onClick={() => processTransaction('Despachado')} disabled={cart.length === 0} className="flex-[2] py-3 bg-white text-[#3E2723] rounded font-bold uppercase text-[10px]">Facturar</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'closure' && (
        <div className="max-w-4xl mx-auto py-6 space-y-6 animate-in fade-in">
          <div className="bg-white p-8 border rounded shadow-sm">
            <h2 className="text-xl font-bold text-[#3E2723] uppercase mb-8 border-b pb-4">Cierre de Operaciones Diario</h2>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
              <div className="p-4 bg-gray-50 border rounded text-center">
                <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Ventas del Día</p>
                <p className="text-2xl font-black text-[#3E2723]">{transactions.filter(t => t.date.split('T')[0] === new Date().toISOString().split('T')[0] && t.status === 'Despachado').length}</p>
              </div>
              <div className="p-4 bg-gray-50 border rounded text-center">
                <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Recaudación CUP</p>
                <p className="text-2xl font-black text-[#3E2723]">${transactions.filter(t => t.date.split('T')[0] === new Date().toISOString().split('T')[0] && t.status === 'Despachado').reduce((a, b) => a + b.totalCup, 0).toLocaleString()}</p>
              </div>
            </div>
            <button onClick={() => window.print()} className="w-full py-4 bg-[#3E2723] text-white rounded font-bold uppercase text-xs flex items-center justify-center gap-2"><Printer size={16}/> Imprimir Reporte de Caja</button>
          </div>
        </div>
      )}

      {activeTab === 'config' && (
        <div className="max-w-2xl mx-auto py-6 animate-in slide-in-from-bottom-6">
          <div className="bg-white p-8 border rounded shadow-sm">
            <h2 className="text-xl font-bold text-[#3E2723] uppercase mb-8 border-b pb-4">Configuración de la Tienda</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Nombre Comercial</label>
                <input value={config.storeName} onChange={e => setConfig({ ...config, storeName: e.target.value })} className="w-full p-2 border rounded font-bold" />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">URL del Logo (Actual: logo.jpeg)</label>
                <input value={config.logoUrl} onChange={e => setConfig({ ...config, logoUrl: e.target.value })} className="w-full p-2 border rounded" />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Teléfono</label>
                <input value={config.phone} onChange={e => setConfig({ ...config, phone: e.target.value })} className="w-full p-2 border rounded font-bold" />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Sobre Nosotros</label>
                <textarea value={config.aboutText} onChange={e => setConfig({ ...config, aboutText: e.target.value })} className="w-full p-2 border rounded h-32" />
              </div>
            </div>
            <button onClick={() => { localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config)); alert("Configuración guardada."); }} className="w-full mt-6 py-3 bg-[#3E2723] text-white rounded font-bold uppercase text-xs">Guardar Perfil</button>
          </div>
        </div>
      )}

      {activeTab === 'maintenance' && (
        <div className="flex h-full items-center justify-center p-6 animate-in fade-in">
          <div className="bg-white p-12 border rounded shadow-sm text-center max-w-md w-full">
            <Database size={60} className="text-[#AF6E4D] mx-auto mb-6" />
            <h2 className="text-xl font-bold text-[#3E2723] uppercase mb-10">Mantenimiento de Datos</h2>
            <div className="grid grid-cols-2 gap-4">
              <button onClick={() => {
                const data = { products, contacts, transactions, config, date: new Date().toISOString() };
                const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = `PaTi_Backup_${new Date().toISOString().split('T')[0]}.json`;
                link.click();
              }} className="p-6 bg-gray-50 border rounded flex flex-col items-center gap-3 hover:bg-[#3E2723] hover:text-white transition-all group">
                <Download size={32} className="group-hover:scale-110 transition-transform"/>
                <span className="text-[10px] font-bold uppercase">Exportar</span>
              </button>
              <button onClick={() => fileInputRef.current?.click()} className="p-6 bg-gray-50 border rounded flex flex-col items-center gap-3 hover:bg-[#3E2723] hover:text-white transition-all group">
                <Upload size={32} className="group-hover:scale-110 transition-transform"/>
                <span className="text-[10px] font-bold uppercase">Importar</span>
              </button>
              <input type="file" ref={fileInputRef} onChange={e => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (evt) => {
                  try {
                    const data = JSON.parse(evt.target?.result as string);
                    if (data.products) setProducts(data.products);
                    if (data.contacts) setContacts(data.contacts);
                    if (data.transactions) setTransactions(data.transactions);
                    if (data.config) setConfig(data.config);
                    alert("Datos restaurados.");
                  } catch (err) { alert("Archivo inválido."); }
                };
                reader.readAsText(file);
              }} accept=".json" className="hidden" />
            </div>
          </div>
        </div>
      )}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/50 z-[500] flex items-center justify-center p-6 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white rounded w-full max-w-4xl h-[90vh] shadow-2xl overflow-hidden flex flex-col relative animate-in slide-in-from-bottom-10">
            <div className="p-4 border-b flex justify-between items-center bg-white sticky top-0 z-40">
              <h2 className="text-sm font-black uppercase text-[#3E2723] tracking-widest">{productModal.mode === 'catalog' ? 'Ficha de Producto' : 'Entrada de Mercancía'}</h2>
              <button onClick={() => setProductModal({ show: false, mode: 'catalog' })} className="text-gray-400 hover:text-red-500 transition-colors"><X size={24} /></button>
            </div>
            <ProductForm mode={productModal.mode} initialData={productModal.product} onSave={p => {
              const idx = products.findIndex(x => (x.id === p.id) || (x.name.toLowerCase() === p.name.toLowerCase()));
              let list = [...products];
              if (idx > -1) {
                list[idx] = { ...list[idx], ...p };
              } else {
                list = [{ ...p, id: Math.random().toString(), sku: `PA-${Date.now().toString().slice(-4)}` }, ...list];
              }
              setProducts(list);
              setProductModal({ show: false, mode: 'catalog' });
            }} onCancel={() => setProductModal({ show: false, mode: 'catalog' })} />
          </div>
        </div>
      )}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/80 z-[600] flex items-center justify-center p-6 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white rounded w-full max-w-2xl shadow-2xl p-8 animate-in slide-in-from-bottom-10">
            <div className="flex justify-between items-start mb-8 border-b pb-6">
              <img src={config.logoUrl} className="h-16 w-auto bg-[#3E2723] p-2 rounded" />
              <div className="text-right">
                <p className="text-[10px] font-bold text-gray-400 uppercase mb-1">Comprobante</p>
                <p className="text-2xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.invoiceNumber}</p>
                <p className="text-[10px] font-bold text-[#AF6E4D] uppercase mt-2">{selectedInvoice.status}</p>
              </div>
            </div>
            <div className="max-h-64 overflow-y-auto pr-4 mb-8">
              <table className="w-full text-left text-xs uppercase font-bold">
                <thead><tr className="border-b text-gray-400"><th className="py-2">Concepto</th><th className="py-2 text-center">Cant.</th><th className="py-2 text-right">Total</th></tr></thead>
                <tbody className="divide-y">
                  {selectedInvoice.items.map((i, idx) => (
                    <tr key={idx}><td className="py-3"><p>{i.productName}</p><p className="text-[9px] text-[#AF6E4D]">{i.groupingLabel}</p></td><td className="py-3 text-center">{i.quantity}</td><td className="py-3 text-right">${i.total.toLocaleString()}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="pt-6 border-t flex justify-between items-end mb-10">
              <p className="text-sm font-bold uppercase text-gray-400">Total a Pagar</p>
              <p className="text-5xl font-black text-[#3E2723] tracking-tighter">${selectedInvoice.totalCup.toLocaleString()} <span className="text-xs opacity-20 ml-2 font-bold">CUP</span></p>
            </div>
            <div className="flex justify-center gap-4 no-print">
              <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-10 py-3 rounded font-bold uppercase text-xs flex items-center gap-2 shadow-lg"><Printer size={16}/> Imprimir Factura</button>
              <button onClick={() => setSelectedInvoice(null)} className="px-6 py-3 font-bold uppercase text-xs text-gray-400 hover:text-[#3E2723]">Cerrar</button>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  Home,
  Info,
  PhoneCall,
  Package, 
  Truck, 
  ShoppingCart, 
  Database, 
  BarChart3, 
  Bell,
  Menu,
  X,
  Wallet,
  Settings,
  Tag
} from 'lucide-react';
import { Notification, StoreConfig } from '../types';

const STORAGE_KEYS = {
  CONFIG: 'pati_v6_config'
};

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  notifications: Notification[];
  onNotificationRead: (id: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, notifications, onNotificationRead }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isNotifOpen, setIsNotifOpen] = useState(false);
  const [config, setConfig] = useState<StoreConfig>({ 
    logoUrl: "logo.jpeg", 
    storeName: "PaTí",
    aboutText: "", address: "", phone: "", email: "", facebookUrl: "", instagramUrl: "", websiteUrl: ""
  });

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CONFIG);
    if (saved) setConfig(JSON.parse(saved));
  }, [activeTab]);

  const unreadCount = notifications.filter(n => !n.read).length;

  const menuItems = [
    { id: 'home', label: 'Monitor', icon: Home, section: 'Control' },
    { id: 'about', label: 'Historia', icon: Info, section: 'Control' },
    { id: 'catalog', label: 'Catálogo', icon: Tag, section: 'Gestión' },
    { id: 'reception', label: 'Recepción', icon: Truck, section: 'Gestión' },
    { id: 'inventory', label: 'Inventario', icon: Package, section: 'Gestión' },
    { id: 'sales', label: 'Ventas', icon: ShoppingCart, section: 'Operaciones' },
    { id: 'closure', label: 'Caja', icon: Wallet, section: 'Operaciones' },
    { id: 'statistics', label: 'Análisis', icon: BarChart3, section: 'Reportes' },
    { id: 'config', label: 'Ajustes', icon: Settings, section: 'Sistema' },
    { id: 'maintenance', label: 'Backup', icon: Database, section: 'Sistema' },
  ];

  const sections = Array.from(new Set(menuItems.map(item => item.section)));

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden font-sans">
      {!isSidebarOpen && (
        <div className="fixed inset-0 bg-black/40 z-20 md:hidden" onClick={() => setIsSidebarOpen(true)} />
      )}

      <aside className={`${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} fixed md:relative z-30 w-64 h-full bg-[#3E2723] text-white transition-transform duration-200 shrink-0`}>
        <div className="flex flex-col h-full">
          <div className="p-6 border-b border-white/10 flex flex-col items-center">
            <img 
              src="./logo.jpeg" 
              alt="Logo PaTí" 
              className="h-20 w-auto object-contain rounded"
              onError={(e) => (e.currentTarget.src = "https://via.placeholder.com/150?text=PaTí")}
            />
            <h1 className="mt-3 text-sm font-black uppercase tracking-widest text-[#AF6E4D]">{config.storeName}</h1>
          </div>

          <nav className="flex-1 overflow-y-auto py-6 px-4 space-y-6">
            {sections.map(section => (
              <div key={section} className="space-y-1">
                <p className="px-4 text-[9px] font-bold text-white/30 uppercase tracking-widest mb-2">{section}</p>
                {menuItems.filter(item => item.section === section).map((item) => (
                  <button
                    key={item.id}
                    onClick={() => {
                      setActiveTab(item.id);
                      if (window.innerWidth < 768) setIsSidebarOpen(false);
                    }}
                    className={`w-full flex items-center px-4 py-2.5 text-[11px] font-bold uppercase rounded transition-colors
                      ${activeTab === item.id 
                        ? 'bg-[#AF6E4D] text-white shadow' 
                        : 'text-white/60 hover:bg-white/5 hover:text-white'}
                    `}
                  >
                    <item.icon className={`w-4 h-4 mr-3 ${activeTab === item.id ? 'text-white' : 'text-[#AF6E4D]'}`} />
                    {item.label}
                  </button>
                ))}
              </div>
            ))}
          </nav>
        </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0">
        <header className="h-16 bg-white border-b flex items-center justify-between px-6 shrink-0 no-print">
          <button className="md:hidden p-2 text-[#3E2723]" onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
            {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
          </button>

          <div className="flex-1 px-4">
            <h1 className="text-lg font-bold text-[#3E2723] uppercase">
              {menuItems.find(m => m.id === activeTab)?.label}
            </h1>
          </div>

          <div className="flex items-center space-x-6">
            <button className={`p-2 rounded relative ${unreadCount > 0 ? 'text-[#AF6E4D]' : 'text-gray-400'}`} onClick={() => setIsNotifOpen(!isNotifOpen)}>
              <Bell className="w-6 h-6" />
              {unreadCount > 0 && <span className="absolute top-0 right-0 w-4 h-4 bg-red-500 text-white text-[9px] font-black flex items-center justify-center rounded-full">{unreadCount}</span>}
            </button>
            <div className="hidden md:block border-l pl-6 h-8 flex items-center">
               <span className="text-[10px] font-black text-emerald-500 uppercase flex items-center gap-2">Online</span>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-6 bg-gray-100">
          <div className="max-w-none mx-auto h-full">{children}</div>
        </main>
      </div>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot, Offer 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  FileText, History, Info, Facebook, Instagram, Mail, Globe, Settings, Copy, TrendingUp, Percent,
  Users, Receipt, Heart, Share2, ExternalLink, Eye, BarChart, Calendar, ChevronRight
} from 'lucide-react';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v10_products',
  CONTACTS: 'pati_v10_contacts',
  TRANSACTIONS: 'pati_v10_transactions',
  CONFIG: 'pati_v10_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "logo.jpeg",
  storeName: "PaTí",
  aboutText: "Compromiso total con la comunidad. Gestión transparente de inventario y ventas.",
  address: "Calle Real #123, Habana Vieja, Cuba",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "", instagramUrl: "", websiteUrl: ""
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'catalog' | 'reception'}>({show: false, mode: 'catalog'});
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence
  useEffect(() => {
    const load = () => {
      const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
      const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
      const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
      const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

      if (p) setProducts(JSON.parse(p));
      if (c) setContacts(JSON.parse(c));
      if (t) setTransactions(JSON.parse(t));
      if (cfg) setConfig(JSON.parse(cfg));

      setIsDataReady(true);
    };
    load();
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  // Daily Calculations for Closure
  const today = new Date().toISOString().split('T')[0];
  const todayTransactions = transactions.filter(t => t.date.split('T')[0] === today && t.status === 'Despachado');

  const closureStats = useMemo(() => {
    const itemsSoldMap = new Map<string, { name: string, qty: number, total: number }>();
    let totalItemsSold = 0;

    todayTransactions.forEach(t => {
      t.items.forEach(item => {
        const current = itemsSoldMap.get(item.productId) || { name: item.productName, qty: 0, total: 0 };
        current.qty += item.unitQuantity;
        current.total += item.total;
        itemsSoldMap.set(item.productId, current);
        totalItemsSold += item.unitQuantity;
      });
    });

    return {
      itemsSold: Array.from(itemsSoldMap.values()),
      totalUnits: totalItemsSold,
      recapCup: todayTransactions.reduce((a, b) => a + b.totalCup, 0),
      count: todayTransactions.length
    };
  }, [todayTransactions]);

  const filteredProducts = useMemo(() => {
    const query = posSearch.toLowerCase().trim();
    return products.filter(p => p.name.toLowerCase().includes(query) || p.sku.toLowerCase().includes(query));
  }, [products, posSearch]);

  const addToCart = (p: Product, variant?: GroupingPrice | Offer) => {
    const isOffer = variant && 'startDate' in variant;
    const isGrouping = variant && 'quantity' in variant && !isOffer;
    const unitsPerPack = isGrouping ? (variant as GroupingPrice).quantity : 1;
    const minToBuy = isGrouping ? (variant as GroupingPrice).minOrderQuantity : 1;
    const pricePerUnit = variant ? variant.price : p.unitPrice;

    if (p.stock < unitsPerPack * minToBuy) {
      alert("No hay suficiente stock.");
      return;
    }

    const vId = variant ? variant.id : 'unit';
    const itemId = `${p.id}-${vId}`;
    const existing = cart.find(i => i.id === itemId);

    if (existing) {
      setCart(cart.map(item => item.id === itemId ? { 
        ...item, 
        quantity: item.quantity + 1, 
        unitQuantity: (item.quantity + 1) * unitsPerPack, 
        total: (item.quantity + 1) * unitsPerPack * pricePerUnit 
      } : item));
    } else {
      const initUnits = minToBuy * unitsPerPack;
      setCart([...cart, {
        id: itemId, productId: p.id, productName: p.name, groupingId: vId,
        groupingLabel: variant?.label || 'Unidad', quantity: minToBuy, price: pricePerUnit,
        total: initUnits * pricePerUnit, currency: variant?.currency || p.unitCurrency,
        unitQuantity: initUnits
      }]);
    }
  };

  const removeFromCart = (id: string) => setCart(cart.filter(item => item.id !== id));

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);
    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Consumidor Final',
      items: [...cart], totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'SOL' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };
    if (status === 'Despachado') {
      setProducts(prev => prev.map(p => {
        const sold = cart.filter(i => i.productId === p.id).reduce((a, b) => a + b.unitQuantity, 0);
        return { ...p, stock: Math.max(0, p.stock - sold) };
      }));
    }
    setTransactions(prev => [newTx, ...prev]);
    setCart([]);
    setSelectedInvoice(newTx);
  };

  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'catalog' | 'reception', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', description: '', stock: 0, costPrice: 0, unitPrice: 0, unitCurrency: 'CUP', groupings: [], offers: []
    });
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 1, price: 0, currency: 'CUP', minOrderQuantity: 1 });

    const isCatalog = mode === 'catalog';

    const handleNameSearch = (name: string) => {
      setFormData(prev => ({ ...prev, name }));
      if (mode === 'reception') {
        const match = products.find(p => p.name.toLowerCase() === name.toLowerCase());
        if (match) {
          setFormData(prev => ({ 
            ...prev, 
            description: match.description, 
            sku: match.sku, 
            unitPrice: match.unitPrice, 
            costPrice: match.costPrice,
            unitCurrency: match.unitCurrency,
            groupings: match.groupings
          }));
        }
      }
    };

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="md:col-span-2">
              <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Nombre del Producto</label>
              <input 
                value={formData.name} 
                onChange={e => handleNameSearch(e.target.value)} 
                className="w-full p-2 border border-gray-300 rounded text-sm font-bold"
                list="p-list"
              />
              <datalist id="p-list">{products.map(p => <option key={p.id} value={p.name}/>)}</datalist>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">{mode === 'reception' ? 'Cantidad Recibida' : 'Stock Actual'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})} className="w-full p-2 border border-gray-300 rounded text-sm"/>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Costo Unitario</label>
              <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value) || 0})} className="w-full p-2 border border-gray-300 rounded text-sm"/>
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Descripción / Ficha Técnica</label>
            <textarea value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-2 border border-gray-300 rounded text-sm h-20" />
          </div>

          {isCatalog && (
            <div className="border-t pt-4 space-y-4">
              <h4 className="text-xs font-black text-[#3E2723] uppercase">Configuración Comercial y Agrupaciones</h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="p-3 bg-gray-50 border rounded">
                  <label className="block text-[10px] font-bold text-gray-500 uppercase mb-2">Precio Unitario de Venta</label>
                  <div className="flex gap-2">
                    <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value) || 0})} className="flex-1 p-2 border border-gray-300 rounded text-lg font-black"/>
                    <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as Currency})} className="p-2 border border-gray-300 rounded font-bold text-xs">
                      <option value="CUP">CUP</option>
                      <option value="USD">USD</option>
                    </select>
                  </div>
                </div>
                <div className="p-3 bg-gray-50 border rounded">
                  <label className="block text-[10px] font-bold text-gray-500 uppercase mb-2">Crear Nueva Agrupación</label>
                  <div className="grid grid-cols-2 gap-2 mb-2">
                    <input placeholder="Etiqueta (Caja, Pack)" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="p-2 border rounded text-[10px]"/>
                    <input type="number" placeholder="Precio x Unidad" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value) || 0})} className="p-2 border rounded text-[10px]"/>
                    <input type="number" placeholder="Unidades por Pack" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 1})} className="p-2 border rounded text-[10px]"/>
                    <input type="number" placeholder="Mínimo de Compra (Packs)" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value) || 1})} className="p-2 border rounded text-[10px]"/>
                  </div>
                  <button onClick={() => { if(!tempGrouping.label) return; setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]}); setTempGrouping({id:'', label:'', quantity:1, price:0, currency:'CUP', minOrderQuantity:1}); }} className="w-full py-2 bg-[#AF6E4D] text-white text-[10px] font-black uppercase rounded shadow-sm">+ Añadir Agrupación</button>
                </div>
              </div>
              <div className="space-y-2">
                {formData.groupings?.map(g => (
                  <div key={g.id} className="flex justify-between items-center p-2 bg-white border border-gray-200 rounded text-[10px]">
                    <span className="font-bold uppercase text-gray-700">{g.label} - {g.quantity} Unid. - Mín: {g.minOrderQuantity} packs - <b className="text-[#3E2723]">${g.price}/u</b></span>
                    <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-red-500 font-bold px-2">Quitar</button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
        <div className="p-4 border-t bg-gray-50 flex justify-end gap-3">
          <button onClick={onCancel} className="px-4 py-2 text-gray-400 font-bold uppercase text-[10px]">Cancelar</button>
          <button onClick={() => onSave(formData as Product)} className="px-6 py-2 bg-[#3E2723] text-white font-black uppercase text-[10px] rounded shadow-lg flex items-center gap-2">
            <Save size={14}/> {initialData ? 'Actualizar Ficha' : 'Guardar en Catálogo'}
          </button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n))}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'catalog' && (
        <div className="space-y-4 animate-in fade-in">
          <div className="flex justify-between items-center border-b border-[#D7CCC8] pb-2">
            <h2 className="text-lg font-black text-[#3E2723] uppercase">Catálogo de Productos</h2>
            <button onClick={() => setProductModal({ show: true, mode: 'catalog' })} className="bg-[#3E2723] text-white px-4 py-2 rounded font-black text-[10px] uppercase flex items-center gap-2"><Plus size={14}/> Nuevo Producto</button>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-4">
            {products.map(p => (
              <div key={p.id} className="bg-white border rounded shadow-sm p-3 hover:border-[#AF6E4D] transition-colors relative flex flex-col justify-between h-48">
                <div>
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-[8px] font-bold text-gray-400 uppercase tracking-widest">{p.sku || 'N/A'}</span>
                    <button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="text-gray-300 hover:text-[#3E2723]"><Edit2 size={12}/></button>
                  </div>
                  <h3 className="font-black text-[#3E2723] uppercase text-xs truncate">{p.name}</h3>
                  <p className="text-[10px] text-gray-500 line-clamp-3 leading-tight mt-1">{p.description}</p>
                </div>
                <div className="border-t pt-2 mt-auto">
                  <p className="text-[9px] font-bold text-gray-400 uppercase">Precio Unitario</p>
                  <p className="text-sm font-black text-[#3E2723]">${p.unitPrice} {p.unitCurrency}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-4 animate-in fade-in">
          <div className="flex justify-between items-center border-b border-[#D7CCC8] pb-2">
            <h2 className="text-lg font-black text-[#3E2723] uppercase">Inventario de Almacén</h2>
            <div className="text-right">
              <p className="text-[9px] font-bold text-gray-400 uppercase">Valorización Total</p>
              <p className="text-md font-black text-[#3E2723]">${products.reduce((a,b)=>a+(b.stock*b.costPrice),0).toLocaleString()} CUP</p>
            </div>
          </div>
          <div className="bg-white border rounded shadow-sm overflow-hidden">
            <table className="w-full text-left border-collapse">
              <thead className="bg-gray-50 border-b text-[9px] font-black text-gray-400 uppercase tracking-widest">
                <tr>
                  <th className="p-3">Producto</th>
                  <th className="p-3 text-center">Existencia</th>
                  <th className="p-3 text-center">Costo Unit.</th>
                  <th className="p-3 text-center">Venta Unit.</th>
                  <th className="p-3 text-center">Margen xU</th>
                  <th className="p-3 text-right">Acción</th>
                </tr>
              </thead>
              <tbody className="divide-y text-xs font-bold">
                {products.length === 0 ? <tr><td colSpan={6} className="p-10 text-center text-gray-300 uppercase">Sin existencias</td></tr> : products.map(p => (
                  <tr key={p.id} className="hover:bg-gray-50">
                    <td className="p-3 uppercase text-[#3E2723]">{p.name}</td>
                    <td className={`p-3 text-center text-lg ${p.stock <= p.minStock ? 'text-red-500' : 'text-gray-700'}`}>{p.stock}</td>
                    <td className="p-3 text-center text-gray-400">${p.costPrice.toLocaleString()}</td>
                    <td className="p-3 text-center text-[#AF6E4D]">${p.unitPrice.toLocaleString()}</td>
                    <td className="p-3 text-center text-emerald-600">${(p.unitPrice - p.costPrice).toLocaleString()}</td>
                    <td className="p-3 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="text-gray-300 hover:text-[#3E2723]"><Edit2 size={14}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="max-w-2xl mx-auto py-6">
          <div className="bg-white border rounded shadow-lg overflow-hidden">
            <div className="p-3 bg-[#3E2723] text-white flex items-center gap-2">
              <Truck size={16}/>
              <h2 className="text-xs font-black uppercase">Recepción de Mercancía</h2>
            </div>
            <ProductForm mode="reception" onSave={p => {
              const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
              let list = [...products];
              if (idx > -1) {
                list[idx] = { ...list[idx], stock: list[idx].stock + p.stock, costPrice: p.costPrice };
              } else {
                list = [{ ...p, id: Math.random().toString(), sku: `PA-${Date.now().toString().slice(-4)}`, groupings: [], offers: [] }, ...list];
              }
              setProducts(list);
              alert("Lote recibido y actualizado.");
              setActiveTab('inventory');
            }} onCancel={() => setActiveTab('catalog')} />
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex h-[calc(100vh-140px)] gap-4">
          <div className="flex-1 bg-white border rounded shadow-sm p-4 flex flex-col">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-md font-black text-[#3E2723] uppercase">Punto de Venta</h2>
              <div className="relative w-64">
                <Search className="absolute left-2 top-2 text-gray-300" size={14}/>
                <input placeholder="Buscar producto..." className="w-full pl-8 pr-4 py-1.5 border rounded text-xs bg-gray-50 outline-none focus:border-[#AF6E4D]" value={posSearch} onChange={e => setPosSearch(e.target.value)} />
              </div>
            </div>
            <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-3 pr-2 custom-scrollbar">
              {filteredProducts.map(p => (
                <div key={p.id} className="border rounded p-3 bg-gray-50 hover:border-[#AF6E4D] transition-colors flex flex-col justify-between">
                  <div>
                    <h3 className="text-xs font-black text-[#3E2723] uppercase truncate">{p.name}</h3>
