        <div className="bg-white p-6 border rounded shadow-sm">
           <div className="w-10 h-10 bg-amber-50 text-amber-600 rounded flex items-center justify-center mb-4"><BarChart3 size={20}/></div>
           <p className="text-[9px] font-black uppercase text-gray-400 mb-1">Valor Inventario</p>
           <p className="text-2xl font-black text-[#3E2723]">${inventoryValue.toLocaleString()}</p>
