        <div className="bg-white p-6 border rounded shadow-sm">
           <div className="w-10 h-10 bg-[#AF6E4D] text-white rounded flex items-center justify-center mb-4"><Target size={20}/></div>
           <p className="text-[9px] font-black uppercase text-gray-400 mb-1">Productos en Catálogo</p>
           <p className="text-2xl font-black text-[#3E2723]">{products.length}</p>
