      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
         <div className="bg-white p-6 border rounded shadow-sm">
            <h3 className="text-xs font-black text-[#3E2723] uppercase mb-6 flex items-center gap-3 border-b pb-4"><Activity size={18} className="text-[#AF6E4D]"/> Top Productos Vendidos</h3>
            <div className="space-y-4">
               {products.map(p => {
                 const sold = despachadas.reduce((acc, t) => acc + t.items.filter(i => i.productId === p.id).reduce((s, i) => s + i.unitQuantity, 0), 0);
                 if (sold === 0) return null;
                 return (
                   <div key={p.id} className="flex justify-between items-center text-xs border-b border-gray-50 pb-2">
                      <span className="font-bold uppercase text-gray-600">{p.name}</span>
                      <span className="font-black text-[#3E2723]">{sold} Unidades</span>
                   </div>
                 );
               })}
               {totalUnitsSold === 0 && <p className="text-[10px] text-center text-gray-300 uppercase py-20">Sin datos de ventas</p>}
            </div>
         </div>

         <div className="bg-[#3E2723] p-8 rounded text-white shadow-lg">
