import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot, Offer 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  FileText, History, Info, Facebook, Instagram, Mail, Globe, Settings, Copy, TrendingUp, Percent,
  Users, Receipt, Heart, Share2, ExternalLink, Eye, BarChart, Calendar, ChevronRight
} from 'lucide-react';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v11_products',
  CONTACTS: 'pati_v11_contacts',
  TRANSACTIONS: 'pati_v11_transactions',
  RECEPTIONS: 'pati_v11_receptions',
  CONFIG: 'pati_v11_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "logo.jpeg",
  storeName: "PaTí",
  aboutText: "Compromiso total con la comunidad. Gestión transparente de inventario y ventas.",
  address: "Calle Real #123, Habana Vieja, Cuba",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "", instagramUrl: "", websiteUrl: ""
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [receptionHistory, setReceptionHistory] = useState<any[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'catalog' | 'reception'}>({show: false, mode: 'catalog'});
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const rh = localStorage.getItem(STORAGE_KEYS.RECEPTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (rh) setReceptionHistory(JSON.parse(rh));
    if (cfg) setConfig(JSON.parse(cfg));

    setIsDataReady(true);
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.RECEPTIONS, JSON.stringify(receptionHistory));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, receptionHistory, config, isDataReady]);

  // Daily Calculations for Closure
  const today = new Date().toISOString().split('T')[0];

  const closureStats = useMemo(() => {
    const todayTransactions = transactions.filter(t => t.date.split('T')[0] === today && t.status === 'Despachado');
    const todayReceptions = receptionHistory.filter(r => r.date.split('T')[0] === today);

    const itemsSoldMap = new Map<string, { name: string, qty: number, total: number }>();
    let totalItemsSold = 0;

    todayTransactions.forEach(t => {
      t.items.forEach(item => {
        const current = itemsSoldMap.get(item.productId) || { name: item.productName, qty: 0, total: 0 };
        current.qty += item.unitQuantity;
        current.total += item.total;
        itemsSoldMap.set(item.productId, current);
        totalItemsSold += item.unitQuantity;
      });
    });

    return {
      itemsSold: Array.from(itemsSoldMap.values()),
      receptions: todayReceptions,
      totalUnits: totalItemsSold,
      recapCup: todayTransactions.reduce((a, b) => a + b.totalCup, 0),
      count: todayTransactions.length,
      inventoryValue: products.reduce((a,b) => a + (b.stock * b.costPrice), 0)
    };
  }, [transactions, receptionHistory, products, today]);

  const filteredProducts = useMemo(() => {
    const query = posSearch.toLowerCase().trim();
    return products.filter(p => p.name.toLowerCase().includes(query) || p.sku.toLowerCase().includes(query));
  }, [products, posSearch]);

  const addToCart = (p: Product, variant?: GroupingPrice | Offer) => {
    const isOffer = variant && 'startDate' in variant;
    const isGrouping = variant && 'quantity' in variant && !isOffer;
    const unitsPerPack = isGrouping ? (variant as GroupingPrice).quantity : 1;
    const minToBuy = isGrouping ? (variant as GroupingPrice).minOrderQuantity : 1;
    const pricePerUnit = variant ? variant.price : p.unitPrice;

    if (p.stock < unitsPerPack * minToBuy) {
      alert("No hay suficiente stock.");
      return;
    }

    const vId = variant ? variant.id : 'unit';
    const itemId = `${p.id}-${vId}`;
    const existing = cart.find(i => i.id === itemId);

    if (existing) {
      setCart(cart.map(item => item.id === itemId ? { 
        ...item, 
        quantity: item.quantity + 1, 
        unitQuantity: (item.quantity + 1) * unitsPerPack, 
        total: (item.quantity + 1) * unitsPerPack * pricePerUnit 
      } : item));
    } else {
      const initUnits = minToBuy * unitsPerPack;
      setCart([...cart, {
        id: itemId, productId: p.id, productName: p.name, groupingId: vId,
        groupingLabel: variant?.label || 'Unidad Suelta', quantity: minToBuy, price: pricePerUnit,
        total: initUnits * pricePerUnit, currency: variant?.currency || p.unitCurrency,
        unitQuantity: initUnits
      }]);
    }
  };

  const removeFromCart = (id: string) => setCart(cart.filter(item => item.id !== id));

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);
    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Consumidor Final',
      items: [...cart], totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'SOL' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };
    if (status === 'Despachado') {
      setProducts(prev => prev.map(p => {
        const sold = cart.filter(i => i.productId === p.id).reduce((a, b) => a + b.unitQuantity, 0);
        return { ...p, stock: Math.max(0, p.stock - sold) };
      }));
    }
    setTransactions(prev => [newTx, ...prev]);
    setCart([]);
    setSelectedInvoice(newTx);
  };

  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'catalog' | 'reception', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', description: '', stock: 0, costPrice: 0, unitPrice: 0, unitCurrency: 'CUP', groupings: [], offers: []
    });
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 1, price: 0, currency: 'CUP', minOrderQuantity: 1 });

    const isCatalog = mode === 'catalog';

    const handleNameSearch = (name: string) => {
      setFormData(prev => ({ ...prev, name }));
      if (mode === 'reception') {
        const match = products.find(p => p.name.toLowerCase() === name.toLowerCase());
        if (match) {
          setFormData(prev => ({ 
            ...prev, 
            description: match.description, 
            sku: match.sku, 
            unitPrice: match.unitPrice, 
            costPrice: match.costPrice,
            unitCurrency: match.unitCurrency,
            groupings: match.groupings
          }));
        }
      }
    };

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="md:col-span-2">
              <label className="block text-xs font-black text-gray-700 uppercase mb-2 tracking-wide">Nombre del Producto</label>
              <input 
                value={formData.name} 
                onChange={e => handleNameSearch(e.target.value)} 
                className="w-full p-3.5 border border-gray-400 rounded-md text-base font-bold text-gray-900 focus:ring-2 ring-[#3E2723] outline-none"
                placeholder="Nombre oficial..."
                list="p-list"
              />
              <datalist id="p-list">{products.map(p => <option key={p.id} value={p.name}/>)}</datalist>
            </div>
            <div>
              <label className="block text-xs font-black text-gray-700 uppercase mb-2 tracking-wide">{mode === 'reception' ? 'Cantidad Recibida' : 'Stock Actual'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})} className="w-full p-3.5 border border-gray-400 rounded-md text-base font-bold text-gray-900"/>
            </div>
            <div>
              <label className="block text-xs font-black text-gray-700 uppercase mb-2 tracking-wide">Costo Unitario (CUP)</label>
              <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value) || 0})} className="w-full p-3.5 border border-gray-400 rounded-md text-base font-bold text-gray-900"/>
            </div>
          </div>

          <div>
            <label className="block text-xs font-black text-gray-700 uppercase mb-2 tracking-wide">Descripción Detallada / Ficha Técnica</label>
            <textarea value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full p-3.5 border border-gray-400 rounded-md text-base font-medium h-28 text-gray-900" placeholder="Escriba aquí los detalles..." />
          </div>

          {isCatalog && (
            <div className="border-t-2 border-gray-100 pt-8 space-y-6">
              <h4 className="text-sm font-black text-[#3E2723] uppercase flex items-center gap-2"><DollarSign size={18}/> Precios y Agrupaciones Mayoristas</h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="p-5 bg-gray-50 border-2 border-gray-200 rounded-lg">
                  <label className="block text-xs font-black text-gray-800 uppercase mb-3">Precio Unitario de Venta</label>
                  <div className="flex gap-3">
                    <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value) || 0})} className="flex-1 p-3.5 border border-gray-400 rounded-md text-xl font-black text-[#3E2723]"/>
                    <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as Currency})} className="p-3.5 border border-gray-400 rounded-md font-black text-sm uppercase">
                      <option value="CUP">CUP</option>
                      <option value="USD">USD</option>
                    </select>
                  </div>
                  <p className="mt-2 text-[10px] font-bold text-gray-400 uppercase">Margen por unidad: <span className="text-emerald-600">${((formData.unitPrice || 0) - (formData.costPrice || 0)).toFixed(2)}</span></p>
                </div>

                <div className="p-5 bg-[#F5F5DC]/40 border-2 border-[#D7CCC8] rounded-lg">
                  <label className="block text-xs font-black text-[#3E2723] uppercase mb-4">Nueva Escala de Precios</label>
                  <div className="grid grid-cols-2 gap-4 mb-4">
                    <div className="col-span-2">
                      <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Nombre (Ej: Caja 12u, Saco 50lb)</label>
                      <input placeholder="Etiqueta" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="w-full p-2 border border-gray-300 rounded font-bold text-sm"/>
                    </div>
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Precio x Unidad</label>
                      <input type="number" placeholder="0.00" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value) || 0})} className="w-full p-2 border border-gray-300 rounded font-bold text-sm"/>
                    </div>
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Unid. en Agrupación</label>
                      <input type="number" placeholder="1" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 1})} className="w-full p-2 border border-gray-300 rounded font-black text-sm bg-white"/>
                    </div>
                    <div className="col-span-2">
                      <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Mínimo de Compra (En paquetes/packs)</label>
                      <input type="number" placeholder="1" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value) || 1})} className="w-full p-2 border border-gray-300 rounded font-black text-sm bg-white"/>
                    </div>
                  </div>
                  <button onClick={() => { if(!tempGrouping.label) return; setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]}); setTempGrouping({id:'', label:'', quantity:1, price:0, currency: formData.unitCurrency || 'CUP', minOrderQuantity:1}); }} className="w-full py-3 bg-[#AF6E4D] text-white text-xs font-black uppercase rounded shadow-sm hover:bg-[#3E2723] transition-colors">Añadir Escala al Catálogo</button>
                </div>
              </div>

              <div className="space-y-3">
                {formData.groupings && formData.groupings.length > 0 && <p className="text-xs font-black text-gray-400 uppercase tracking-widest">Escalas Configuradas:</p>}
                {formData.groupings?.map(g => (
                  <div key={g.id} className="flex justify-between items-center p-3 bg-white border border-gray-300 rounded-md shadow-sm">
                    <div className="flex flex-col">
                      <span className="font-black uppercase text-sm text-[#3E2723]">{g.label}</span>
                      <span className="text-[10px] font-bold text-gray-500 uppercase">Contiene: {g.quantity}u | Pedido Mín: {g.minOrderQuantity} packs</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="font-black text-lg text-[#AF6E4D]">${g.price} <small className="text-[10px] opacity-40">/u</small></span>
                      <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="p-2 text-rose-500 hover:bg-rose-50 rounded-full transition-colors"><Trash2 size={16}/></button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
        <div className="p-6 border-t bg-gray-50 flex justify-end gap-4 shadow-[0_-10px_30px_rgba(0,0,0,0.03)]">
          <button onClick={onCancel} className="px-6 py-3 text-gray-400 font-black uppercase text-xs tracking-widest hover:text-gray-600">Descartar</button>
          <button onClick={() => onSave(formData as Product)} className="px-10 py-3 bg-[#3E2723] text-white font-black uppercase text-xs rounded shadow-xl flex items-center gap-3 tracking-widest hover:scale-105 transition-all">
            <Save size={18}/> {initialData ? 'Actualizar Ficha Maestro' : 'Guardar Nuevo Producto'}
          </button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n))}>

