                  <div className="flex justify-between items-start mb-2">
                    <span className="text-[10px] font-black text-gray-300 uppercase bg-gray-50 px-2 py-1 rounded tracking-widest">{p.sku || 'N/A'}</span>
                    <button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="text-gray-400 hover:text-[#3E2723] transition-colors"><Edit2 size={18}/></button>
                  </div>
                  <h3 className="font-black text-[#3E2723] uppercase text-sm leading-tight mb-2 line-clamp-2">{p.name}</h3>
                  <p className="text-xs text-gray-500 font-medium line-clamp-3 leading-relaxed mb-4">{p.description}</p>
                </div>
                <div className="border-t pt-3 mt-auto flex justify-between items-end">
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase mb-1">Precio Unitario</p>
                    <p className="text-xl font-black text-[#3E2723] tracking-tighter">${p.unitPrice} <small className="text-[10px] font-bold text-[#AF6E4D] uppercase">{p.unitCurrency}</small></p>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-gray-400 uppercase mb-1">Stock</p>
                    <p className={`text-lg font-black ${p.stock <= p.minStock ? 'text-rose-500' : 'text-gray-900'}`}>{p.stock}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-6 animate-in fade-in">
          <div className="flex justify-between items-center border-b-4 border-[#3E2723] pb-4">
            <h2 className="text-2xl font-black text-[#3E2723] uppercase tracking-tighter">Control de Existencias</h2>
            <div className="bg-[#3E2723] text-white px-8 py-3 rounded-lg text-right shadow-xl border-l-8 border-[#AF6E4D]">
              <p className="text-[10px] font-black uppercase opacity-60 tracking-widest">Valorización Total Almacén</p>
              <p className="text-2xl font-black tracking-tighter">${products.reduce((a,b)=>a+(b.stock*b.costPrice),0).toLocaleString()} <span className="text-xs opacity-30">CUP</span></p>
            </div>
          </div>
          <div className="bg-white border rounded shadow-sm overflow-hidden">
            <table className="w-full text-left border-collapse">
              <thead className="bg-gray-50 border-b-2 text-[10px] font-black text-gray-500 uppercase tracking-widest">
                <tr>
                  <th className="p-4">Descripción Producto</th>
                  <th className="p-4 text-center">En Existencia</th>
                  <th className="p-4 text-center">Costo Unitario</th>
                  <th className="p-4 text-center">Venta Unitario</th>
                  <th className="p-4 text-center">Margen Neto</th>
                  <th className="p-4 text-right">Ficha</th>
                </tr>
              </thead>
              <tbody className="divide-y text-sm font-bold text-[#3E2723]">
                {products.length === 0 ? <tr><td colSpan={6} className="p-20 text-center text-gray-300 font-black uppercase tracking-[0.3em]">No hay datos de inventario</td></tr> : products.map(p => (
                  <tr key={p.id} className="hover:bg-gray-50 transition-colors">
                    <td className="p-4"><p className="font-black uppercase">{p.name}</p><p className="text-[10px] font-medium text-gray-400 mt-1 line-clamp-1">{p.description}</p></td>
                    <td className={`p-4 text-center text-2xl font-black ${p.stock <= p.minStock ? 'text-rose-500' : 'text-gray-700'}`}>{p.stock}</td>
                    <td className="p-4 text-center text-gray-400 font-black">${p.costPrice.toLocaleString()}</td>
                    <td className="p-4 text-center text-[#AF6E4D] font-black">${p.unitPrice.toLocaleString()}</td>
                    <td className="p-4 text-center text-emerald-600 font-black">${(p.unitPrice - p.costPrice).toLocaleString()}</td>
                    <td className="p-4 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="p-3 text-gray-400 hover:text-[#3E2723] hover:bg-gray-100 rounded-full transition-all"><Edit2 size={18}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="max-w-3xl mx-auto py-8">
          <div className="bg-white border-2 border-[#D7CCC8] rounded shadow-2xl overflow-hidden">
            <div className="p-5 bg-[#3E2723] text-white flex items-center justify-between">
              <div className="flex items-center gap-3">
                <Truck size={24} className="text-[#AF6E4D]"/>
                <h2 className="text-sm font-black uppercase tracking-widest">Recepción Logística de Mercancía</h2>
              </div>
              <div className="text-[10px] font-black opacity-40 uppercase">Registro de Lote</div>
            </div>
            <ProductForm mode="reception" onSave={p => {
              const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
              let list = [...products];
              let updatedProduct: Product;
              if (idx > -1) {
                updatedProduct = { ...list[idx], stock: list[idx].stock + p.stock, costPrice: p.costPrice };
                list[idx] = updatedProduct;
              } else {
                updatedProduct = { ...p, id: Math.random().toString(), sku: `PA-${Date.now().toString().slice(-4)}`, groupings: [], offers: [] } as Product;
                list = [updatedProduct, ...list];
              }
              setProducts(list);
              setReceptionHistory(prev => [{
                id: Math.random().toString(),
                date: new Date().toISOString(),
                productName: updatedProduct.name,
                quantity: p.stock,
                cost: p.costPrice
              }, ...prev]);
              alert("Mercancía recibida y catálogo actualizado correctamente.");
              setActiveTab('inventory');
            }} onCancel={() => setActiveTab('catalog')} />
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex h-[calc(100vh-140px)] gap-6 animate-in zoom-in-95">
          <div className="flex-1 bg-white border rounded shadow-sm p-6 flex flex-col">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal PaTí</h2>
              <div className="relative w-80">
                <Search className="absolute left-3 top-2.5 text-gray-400" size={18}/>
                <input placeholder="Buscar producto por nombre o SKU..." className="w-full pl-10 pr-4 py-2 border-2 border-gray-100 rounded text-sm font-bold bg-gray-50 focus:border-[#AF6E4D] outline-none" value={posSearch} onChange={e => setPosSearch(e.target.value)} />
              </div>
            </div>
            <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4 pr-2 custom-scrollbar">
              {filteredProducts.map(p => (
                <div key={p.id} className="border-2 border-gray-100 rounded p-4 bg-gray-50 hover:border-[#AF6E4D] transition-colors flex flex-col justify-between">
                  <div>
                    <h3 className="text-sm font-black text-[#3E2723] uppercase truncate leading-tight mb-1">{p.name}</h3>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Disponible: {p.stock} Unid.</p>
                  </div>
                  <div className="space-y-2 mt-2">
                    <button onClick={() => addToCart(p)} className="w-full py-2 bg-[#3E2723] text-white rounded font-black uppercase text-[10px] shadow-sm active:scale-95 transition-all">Unidad Suelta: ${p.unitPrice}</button>
                    {p.groupings?.map(g => (
                      <button key={g.id} onClick={() => addToCart(p, g)} className="w-full py-2 bg-white border-2 border-[#D7CCC8] text-[#3E2723] rounded text-[9px] font-black uppercase flex justify-between px-3 hover:bg-[#3E2723] hover:text-white transition-all">
                        <span>{g.label} (x{g.quantity})</span>
                        <span className="text-[#AF6E4D] group-hover:text-white">${g.price}/u</span>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-80 bg-[#3E2723] rounded-lg p-6 text-white flex flex-col shadow-2xl relative">
            <h3 className="text-[10px] font-black uppercase tracking-[0.3em] mb-6 flex items-center gap-3 border-b border-white/10 pb-4"><ShoppingCart size={18} className="text-[#AF6E4D]"/> Resumen de Venta</h3>
            <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
              {cart.map(i => (
                <div key={i.id} className="bg-white/5 p-3 rounded border border-white/10 flex justify-between items-center text-[11px] animate-in slide-in-from-right-4">
                  <div className="flex-1 pr-2">
                    <p className="font-black uppercase truncate">{i.productName}</p>
                    <p className="text-[9px] opacity-40 font-bold uppercase">{i.groupingLabel} x{i.quantity}</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <p className="font-black text-base tabular-nums tracking-tighter">${i.total.toLocaleString()}</p>
                    <button onClick={() => removeFromCart(i.id)} className="text-rose-400 p-1 hover:bg-rose-400/10 rounded transition-all"><Trash2 size={14}/></button>
                  </div>
                </div>
              ))}
            </div>
            <div className="pt-6 border-t border-white/10 mt-4 space-y-4">
              <div className="flex justify-between items-end">
                <p className="text-[10px] font-black uppercase opacity-40 tracking-widest">Total a Cobrar</p>
                <p className="text-4xl font-black tabular-nums tracking-tighter">{cart.reduce((a,b)=>a+b.total,0).toLocaleString()} <span className="text-xs opacity-20 font-bold">CUP</span></p>
