              <button onClick={() => processTransaction('Despachado')} disabled={cart.length === 0} className="w-full py-4 bg-[#AF6E4D] text-white rounded font-black uppercase text-xs shadow-xl active:scale-95 transition-all tracking-[0.2em] border-b-4 border-[#8D6E63] disabled:opacity-20">Confirmar y Despachar</button>
