                <p className="text-xs font-black text-[#AF6E4D] uppercase tracking-[0.3em] mt-1">Control de Operaciones PaTí</p>
              </div>
              <div className="flex items-center gap-3 p-3 bg-gray-50 border-2 rounded-lg"><Calendar size={18} className="text-[#3E2723]"/> <span className="text-sm font-black text-[#3E2723]">{today}</span></div>
