            <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-10">
              <div className="p-6 border-2 rounded-xl bg-gray-50 text-center shadow-sm">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Facturas Emitidas</p>
                <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{closureStats.count}</p>
              </div>
              <div className="p-6 border-2 rounded-xl bg-gray-50 text-center shadow-sm">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Unidades Vendidas</p>
                <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{closureStats.totalUnits}</p>
              </div>
              <div className="p-6 border-2 rounded-xl bg-gray-50 text-center shadow-sm">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Recaudación (CUP)</p>
                <p className="text-4xl font-black text-[#AF6E4D] tracking-tighter">${closureStats.recapCup.toLocaleString()}</p>
