                        <tr key={idx} className="hover:bg-gray-50">
                          <td className="p-3">{item.name}</td>
                          <td className="p-3 text-center text-lg">{item.qty}</td>
                          <td className="p-3 text-right text-emerald-600">${item.total.toLocaleString()}</td>
