            <div className="grid grid-cols-2 gap-6">
              <button onClick={() => {
                const data = { products, contacts, transactions, receptionHistory, config, date: new Date().toISOString() };
                const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = `PaTi_Maestro_Backup_${new Date().toISOString().split('T')[0]}.json`;
                link.click();
              }} className="p-6 bg-gray-50 border-2 border-gray-100 rounded-lg flex flex-col items-center gap-3 hover:bg-[#3E2723] hover:text-white transition-all shadow-sm group">
                <Download size={32}/>
                <span className="text-[10px] font-black uppercase tracking-widest">Exportar</span>
              </button>
              <button onClick={() => fileInputRef.current?.click()} className="p-6 bg-gray-50 border-2 border-gray-100 rounded-lg flex flex-col items-center gap-3 hover:bg-[#3E2723] hover:text-white transition-all shadow-sm group">
                <Upload size={32}/>
                <span className="text-[10px] font-black uppercase tracking-widest">Importar</span>
              </button>
              <input type="file" ref={fileInputRef} onChange={e => {
                const file = e.target.files?.[0]; if(!file) return;
                const r = new FileReader(); r.onload = (ev) => { try {
                  const d = JSON.parse(ev.target?.result as string);
                  if(d.products) setProducts(d.products); if(d.contacts) setContacts(d.contacts); if(d.transactions) setTransactions(d.transactions); if(d.receptionHistory) setReceptionHistory(d.receptionHistory); if(d.config) setConfig(d.config);
                  alert("Datos restaurados y sincronizados correctamente."); } catch(err) { alert("Error de formato en archivo de respaldo."); } }; r.readAsText(file);
              }} accept=".json" className="hidden" />
            </div>
          </div>
        </div>
      )}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/70 z-[500] flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded w-full max-w-4xl h-[92vh] shadow-2xl overflow-hidden flex flex-col relative border-t-[12px] border-[#3E2723]">
            <div className="p-4 border-b flex justify-between items-center bg-gray-50">
              <div className="flex items-center gap-3">
                <Package size={20} className="text-[#AF6E4D]"/>
                <h2 className="text-xs font-black uppercase text-[#3E2723] tracking-widest">{productModal.mode === 'catalog' ? 'Edición de Ficha Maestra de Producto' : 'Registro de Nueva Entrada de Inventario'}</h2>
              </div>
              <button onClick={() => setProductModal({ show: false, mode: 'catalog' })} className="text-gray-400 hover:text-rose-500 transition-colors p-2"><X size={24} /></button>
            </div>
            <ProductForm mode={productModal.mode} initialData={productModal.product} onSave={p => {
              setProducts(prev => {
                const idx = prev.findIndex(x => (x.id === p.id) || (x.name.toLowerCase() === p.name.toLowerCase()));
                let list = [...prev];
                if (idx > -1) {
                  list[idx] = { ...list[idx], ...p };
                } else {
                  list = [{ ...p, id: Math.random().toString(), sku: `PA-${Date.now().toString().slice(-4)}` }, ...list];
                }
                return list;
              });
              setProductModal({ show: false, mode: 'catalog' });
            }} onCancel={() => setProductModal({ show: false, mode: 'catalog' })} />
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

