                  <div className="flex gap-4">
                    <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value) || 0})} className="flex-1 p-4 border-2 border-[#3E2723] rounded-lg text-3xl font-black text-[#3E2723] bg-white shadow-md"/>
