                  <div className="mt-4 p-3 bg-white rounded border border-[#3E2723]/10 flex justify-between items-center">
                    <span className="text-[10px] font-black text-gray-400 uppercase">Utilidad Proyectada:</span>
                    <span className="text-lg font-black text-emerald-600 tracking-tighter">+ ${( (formData.unitPrice || 0) - (formData.costPrice || 0) ).toLocaleString()} <small className="text-[10px]">CUP/u</small></span>
                  </div>
                </div>

                <div className="p-6 bg-white border-2 border-dashed border-[#AF6E4D] rounded-xl shadow-sm">
                  <label className="block text-xs font-black text-[#AF6E4D] uppercase mb-4 tracking-widest">Añadir Escala Mayorista</label>
                  <div className="grid grid-cols-2 gap-4 mb-4">
