                      <label className="block text-[9px] font-black text-gray-400 uppercase mb-1">Unidades por Pack</label>
                      <input type="number" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 1})} className="w-full p-3 border-2 border-gray-100 rounded font-black text-sm"/>
                    </div>
                    <div className="col-span-2">
                      <label className="block text-[9px] font-black text-[#AF6E4D] uppercase mb-1">Mínimo de packs a comprar</label>
                      <input type="number" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value) || 1})} className="w-full p-3 border-2 border-[#AF6E4D]/30 rounded font-black text-sm bg-[#AF6E4D]/5"/>
