                <Package size={80} className="mx-auto text-gray-100 mb-6" />
                <p className="text-sm font-black text-gray-200 uppercase tracking-[0.4em]">Base de datos vacía</p>
              </div>
            ) : products.map(p => (
              <div key={p.id} className="bg-white border-2 border-gray-100 rounded-2xl shadow-sm p-6 hover:border-[#AF6E4D] transition-all flex flex-col justify-between group">
                <div>
                  <div className="flex justify-between items-start mb-4">
                    <span className="text-[10px] font-black text-[#3E2723] uppercase bg-[#3E2723]/5 px-3 py-1.5 rounded-full tracking-widest">{p.sku || 'REF-T01'}</span>
                    <button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="text-gray-300 hover:text-[#3E2723] transition-colors"><Edit2 size={20}/></button>
                  </div>
                  <h3 className="font-black text-[#3E2723] uppercase text-sm leading-tight mb-3 line-clamp-2">{p.name}</h3>
                  <p className="text-[11px] text-gray-500 font-medium line-clamp-3 leading-relaxed mb-6">{p.description}</p>
                </div>
                <div className="border-t-2 border-gray-50 pt-4 mt-auto flex justify-between items-end">
                  <div>
                    <p className="text-[9px] font-black text-gray-400 uppercase mb-1 tracking-widest">P. Unitario</p>
                    <p className="text-2xl font-black text-[#3E2723] tracking-tighter">${p.unitPrice} <small className="text-[10px] text-[#AF6E4D] uppercase">{p.unitCurrency}</small></p>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] font-black text-gray-400 uppercase mb-1 tracking-widest">Stock</p>
                    <p className={`text-xl font-black tracking-tighter ${p.stock <= p.minStock ? 'text-rose-500' : 'text-emerald-600'}`}>{p.stock}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-6 animate-in fade-in">
          <div className="flex justify-between items-center border-b-8 border-[#3E2723] pb-4">
            <div>
              <h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Control Centralizado</h2>
              <p className="text-xs font-bold text-[#AF6E4D] uppercase tracking-widest mt-2">Monitorización de Stock y Lotes</p>
            </div>
            <div className="bg-[#3E2723] text-white px-10 py-5 rounded-2xl text-right shadow-2xl border-l-[12px] border-[#AF6E4D]">
              <p className="text-[11px] font-black uppercase opacity-50 tracking-[0.2em] mb-1">Valorización del Capital en Almacén</p>
              <p className="text-3xl font-black tracking-tighter">${products.reduce((a,b)=>a+(b.stock*b.costPrice),0).toLocaleString()} <span className="text-sm opacity-30 font-bold ml-2">CUP</span></p>
            </div>
          </div>
          <div className="bg-white border-2 border-gray-100 rounded-3xl shadow-xl overflow-hidden">
            <table className="w-full text-left border-collapse">
              <thead className="bg-gray-50 border-b-4 border-gray-100 text-[11px] font-black text-gray-500 uppercase tracking-widest">
                <tr>
                  <th className="p-6">Descripción Producto</th>
                  <th className="p-6 text-center">Físico</th>
                  <th className="p-6 text-center">Costo Promedio</th>
                  <th className="p-6 text-center">Venta Unitario</th>
                  <th className="p-6 text-center">Rendimiento xU</th>
                  <th className="p-6 text-right">Ficha</th>
                </tr>
              </thead>
              <tbody className="divide-y-2 divide-gray-50 text-sm font-black text-[#3E2723]">
                {products.length === 0 ? (
                  <tr><td colSpan={6} className="p-32 text-center text-gray-200 uppercase tracking-[0.5em] font-black">Sistema sin datos</td></tr>
                ) : products.map(p => (
                  <tr key={p.id} className="hover:bg-gray-50/80 transition-all">
                    <td className="p-6">
                      <p className="font-black uppercase text-[#3E2723] text-base">{p.name}</p>
                      <p className="text-[10px] font-bold text-gray-400 mt-1 uppercase tracking-widest">Último Costo: ${p.costPrice}</p>
                    </td>
                    <td className={`p-6 text-center text-3xl font-black tracking-tighter ${p.stock <= p.minStock ? 'text-rose-600' : 'text-gray-800'}`}>{p.stock}</td>
                    <td className="p-6 text-center text-gray-400 font-black tabular-nums">${p.costPrice.toLocaleString()}</td>
                    <td className="p-6 text-center text-[#AF6E4D] font-black tabular-nums">${p.unitPrice.toLocaleString()}</td>
                    <td className="p-6 text-center text-emerald-600 font-black tabular-nums">+ ${(p.unitPrice - p.costPrice).toLocaleString()}</td>
                    <td className="p-6 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="p-4 text-gray-300 hover:text-[#3E2723] hover:bg-white rounded-2xl shadow-sm border border-transparent hover:border-gray-100 transition-all"><Edit2 size={22}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="max-w-3xl mx-auto py-12">
          <div className="bg-white border-4 border-[#3E2723] rounded-3xl shadow-[0_50px_100px_rgba(0,0,0,0.1)] overflow-hidden">
