                </div>
              </div>
              <div className="p-3 bg-white/10 rounded-xl">
                 <History size={24} className="text-white/40"/>
              </div>
            </div>
            <ProductForm mode="reception" onSave={p => {
              const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
              let list = [...products];
              let updatedProduct: Product;

              const newLot: ReceptionLot = {
                id: Math.random().toString(),
                date: new Date().toISOString(),
                supplierId: 'Gral',
                receptionType: 'Compra Directa',
                quantityReceived: p.stock,
                currentStock: p.stock,
                unitCost: p.costPrice,
                transportCost: p.transportCost || 0,
                totalInvestment: (p.stock * p.costPrice) + (p.transportCost || 0)
              };

              if (idx > -1) {
                updatedProduct = { 
                  ...list[idx], 
                  stock: list[idx].stock + p.stock, 
                  costPrice: p.costPrice,
                  lots: [...(list[idx].lots || []), newLot]
                };
                list[idx] = updatedProduct;
              } else {
                updatedProduct = { 
                  ...p, 
                  id: Math.random().toString(), 
                  sku: `PA-${Date.now().toString().slice(-4)}`, 
                  groupings: [], 
                  lots: [newLot] 
                } as Product;
                list = [updatedProduct, ...list];
              }

              setProducts(list);
              setReceptionHistory(prev => [{
                id: newLot.id,
                date: newLot.date,
                productName: updatedProduct.name,
                quantity: newLot.quantityReceived,
                cost: newLot.unitCost,
                transportCost: newLot.transportCost
              }, ...prev]);

              alert("Lote recibido con éxito. El inventario y gastos logísticos han sido actualizados.");
              setActiveTab('inventory');
            }} onCancel={() => setActiveTab('catalog')} />
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex h-[calc(100vh-140px)] gap-8 animate-in zoom-in-95">
          <div className="flex-1 bg-white border-2 border-gray-100 rounded-3xl shadow-sm p-8 flex flex-col">
