                <input 
                  placeholder="Filtrar por nombre o etiqueta SKU..." 
                  className="w-full pl-14 pr-6 py-3.5 border-4 border-gray-50 rounded-2xl text-base font-black bg-gray-50 focus:border-[#AF6E4D] outline-none transition-all shadow-inner" 
                  value={posSearch} 
                  onChange={e => setPosSearch(e.target.value)} 
                />
              </div>
