              {filteredProducts.map(p => (
                <div key={p.id} className="border-2 border-gray-100 rounded-2xl p-6 bg-white hover:border-[#AF6E4D] hover:shadow-xl transition-all flex flex-col justify-between group">
                  <div>
                    <h3 className="text-sm font-black text-[#3E2723] uppercase truncate leading-tight mb-2">{p.name}</h3>
                    <div className="flex justify-between items-center mb-6">
                      <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">En Stock</span>
                      <span className={`text-xs font-black px-3 py-1 rounded-full ${p.stock <= p.minStock ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>{p.stock} Unid.</span>
                    </div>
                  </div>
                  <div className="space-y-3 mt-4">
                    <button onClick={() => addToCart(p)} className="w-full py-3 bg-[#3E2723] text-white rounded-xl font-black uppercase text-[11px] shadow-lg active:scale-95 transition-all border-b-4 border-black">Unidad Suelta: ${p.unitPrice}</button>
                    {p.groupings?.map(g => (
                      <button key={g.id} onClick={() => addToCart(p, g)} className="w-full py-2.5 bg-white border-2 border-[#D7CCC8] text-[#3E2723] rounded-xl text-[10px] font-black uppercase flex justify-between px-4 hover:bg-[#3E2723] hover:text-white transition-all shadow-sm">
                        <span>{g.label}</span>
                        <span className="text-[#AF6E4D] group-hover:text-white">${g.price}/u</span>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-96 bg-[#3E2723] rounded-3xl p-8 text-white flex flex-col shadow-2xl relative border-l-8 border-[#AF6E4D]">
            <h3 className="text-[12px] font-black uppercase tracking-[0.3em] mb-8 flex items-center gap-4 border-b border-white/10 pb-6"><ShoppingCart size={24} className="text-[#AF6E4D]"/> Carrito Maestro</h3>
            <div className="flex-1 overflow-y-auto space-y-4 pr-3 custom-scrollbar">
              {cart.map(i => (
                <div key={i.id} className="bg-white/5 p-4 rounded-2xl border border-white/10 flex justify-between items-center text-[12px] animate-in slide-in-from-right-8 group">
                  <div className="flex-1 pr-4">
                    <p className="font-black uppercase truncate leading-none mb-1">{i.productName}</p>
                    <p className="text-[10px] opacity-40 font-bold uppercase tracking-widest">{i.groupingLabel} x{i.quantity}</p>
                  </div>
                  <div className="flex items-center gap-4">
                    <p className="font-black text-xl tabular-nums tracking-tighter">${i.total.toLocaleString()}</p>
                    <button onClick={() => removeFromCart(i.id)} className="text-rose-400 p-2 hover:bg-rose-400/20 rounded-full transition-all"><Trash2 size={16}/></button>
                  </div>
                </div>
              ))}
            </div>
            <div className="pt-8 border-t border-white/10 mt-6 space-y-6">
              <div className="flex justify-between items-end">
                <div>
                   <p className="text-[11px] font-black uppercase opacity-40 tracking-widest mb-1">Monto Total</p>
                   <p className="text-xs font-bold text-[#AF6E4D] uppercase">I.V.A Incluido</p>
                </div>
                <p className="text-5xl font-black tabular-nums tracking-tighter">{cart.reduce((a,b)=>a+b.total,0).toLocaleString()} <span className="text-sm opacity-20 font-bold ml-1">CUP</span></p>
              </div>
              <button onClick={() => processTransaction('Despachado')} disabled={cart.length === 0} className="w-full py-5 bg-[#AF6E4D] text-white rounded-2xl font-black uppercase text-sm shadow-[0_20px_40px_rgba(175,110,77,0.3)] active:scale-95 transition-all tracking-[0.4em] border-b-4 border-[#8D6E63] disabled:opacity-20 disabled:scale-100">Cerrar Venta</button>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'closure' && (
