            <button onClick={() => { localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config)); alert("Configuración de perfil actualizada."); }} className="w-full mt-12 py-5 bg-[#3E2723] text-white rounded-2xl font-black uppercase text-xs shadow-2xl tracking-[0.4em] border-b-8 border-black hover:bg-black transition-all">Sincronizar Cambios de Identidad</button>
