            <div className="grid grid-cols-1 gap-8">
              <button onClick={() => {
                const data = { products, contacts, transactions, receptionHistory, config, date: new Date().toISOString() };
                const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = `PaTi_Maestro_Final_${new Date().toISOString().split('T')[0]}.json`;
                link.click();
              }} className="p-8 bg-[#3E2723] border-4 border-black rounded-3xl flex items-center justify-center gap-6 text-white hover:scale-105 transition-all shadow-2xl group">
                <Download size={40}/>
                <span className="text-sm font-black uppercase tracking-[0.2em]">Copia de Seguridad</span>
              </button>
              <button onClick={() => fileInputRef.current?.click()} className="p-8 bg-white border-4 border-gray-100 rounded-3xl flex items-center justify-center gap-6 text-gray-400 hover:bg-[#AF6E4D] hover:text-white hover:border-[#AF6E4D] transition-all shadow-sm group">
                <Upload size={40}/>
                <span className="text-sm font-black uppercase tracking-[0.2em]">Restaurar Sistema</span>
              </button>
              <input type="file" ref={fileInputRef} onChange={e => {
                const file = e.target.files?.[0]; if(!file) return;
                const r = new FileReader(); r.onload = (ev) => { try {
                  const d = JSON.parse(ev.target?.result as string);
                  if(d.products) setProducts(d.products); if(d.contacts) setContacts(d.contacts); if(d.transactions) setTransactions(d.transactions); if(d.receptionHistory) setReceptionHistory(d.receptionHistory); if(d.config) setConfig(d.config);
                  alert("Integridad de datos restaurada."); } catch(err) { alert("Archivo de respaldo corrupto o incompatible."); } }; r.readAsText(file);
              }} accept=".json" className="hidden" />
            </div>
          </div>
        </div>
      )}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/80 z-[500] flex items-center justify-center p-6 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[3rem] w-full max-w-5xl h-[94vh] shadow-2xl overflow-hidden flex flex-col relative border-t-[20px] border-[#3E2723]">
            <div className="p-6 border-b-2 border-gray-100 flex justify-between items-center bg-gray-50/50">
              <div className="flex items-center gap-6">
                <div className="p-3 bg-[#3E2723] rounded-2xl"><Package size={24} className="text-white"/></div>
                <div>
                  <h2 className="text-sm font-black uppercase text-[#3E2723] tracking-[0.2em]">{productModal.mode === 'catalog' ? 'Edición Maestro' : 'Ingreso Logístico'}</h2>
                  <p className="text-[10px] font-black text-[#AF6E4D] uppercase mt-1 tracking-widest">{productModal.product?.name || 'Nuevo Registro'}</p>
                </div>
              </div>
              <button onClick={() => setProductModal({ show: false, mode: 'catalog' })} className="text-gray-300 hover:text-rose-500 hover:rotate-90 transition-all p-3"><X size={32} /></button>
            </div>
            <ProductForm mode={productModal.mode} initialData={productModal.product} onSave={p => {
              setProducts(prev => {
                const idx = prev.findIndex(x => (x.id === p.id) || (x.name.toLowerCase() === p.name.toLowerCase()));
                let list = [...prev];
                if (idx > -1) {
                  list[idx] = { ...list[idx], ...p };
                } else {
                  list = [{ ...p, id: Math.random().toString(), sku: `PA-${Date.now().toString().slice(-4)}`, lots: [] }, ...list];
                }
                return list;
              });
              setProductModal({ show: false, mode: 'catalog' });
            }} onCancel={() => setProductModal({ show: false, mode: 'catalog' })} />
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot, Offer 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  FileText, History, Info, Facebook, Instagram, Mail, Globe, Settings, Copy, TrendingUp, Percent,
  Users, Receipt, Heart, Share2, ExternalLink, Eye, BarChart, Calendar, ChevronRight,
  MoveRight,
  Navigation
} from 'lucide-react';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v12_products',
  CONTACTS: 'pati_v12_contacts',
  TRANSACTIONS: 'pati_v12_transactions',
  RECEPTIONS: 'pati_v12_receptions',
  CONFIG: 'pati_v12_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "logo.jpeg",
  storeName: "PaTí",
  aboutText: "Gestión avanzada de inventarios y control logístico de transportación.",
  address: "Calle Real #123, Habana Vieja, Cuba",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "", instagramUrl: "", websiteUrl: ""
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [receptionHistory, setReceptionHistory] = useState<any[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'catalog' | 'reception'}>({show: false, mode: 'catalog'});
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const rh = localStorage.getItem(STORAGE_KEYS.RECEPTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (rh) setReceptionHistory(JSON.parse(rh));
    if (cfg) setConfig(JSON.parse(cfg));

    setIsDataReady(true);
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.RECEPTIONS, JSON.stringify(receptionHistory));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, receptionHistory, config, isDataReady]);

  // Daily Calculations for Closure
  const today = new Date().toISOString().split('T')[0];

  const closureStats = useMemo(() => {
    const todayTransactions = transactions.filter(t => t.date.split('T')[0] === today && t.status === 'Despachado');
    const todayReceptions = receptionHistory.filter(r => r.date.split('T')[0] === today);

    const itemsSoldMap = new Map<string, { name: string, qty: number, total: number }>();
    let totalItemsSold = 0;

    todayTransactions.forEach(t => {
      t.items.forEach(item => {
        const current = itemsSoldMap.get(item.productId) || { name: item.productName, qty: 0, total: 0 };
        current.qty += item.unitQuantity;
        current.total += item.total;
        itemsSoldMap.set(item.productId, current);
        totalItemsSold += item.unitQuantity;
      });
    });

    return {
      itemsSold: Array.from(itemsSoldMap.values()),
      receptions: todayReceptions,
      totalUnits: totalItemsSold,
      recapCup: todayTransactions.reduce((a, b) => a + (b.totalCup || 0), 0),
      totalTransport: todayReceptions.reduce((a, b) => a + (b.transportCost || 0), 0),
      count: todayTransactions.length,
      inventoryValue: products.reduce((a,b) => a + ((b.stock || 0) * (b.costPrice || 0)), 0)
    };
  }, [transactions, receptionHistory, products, today]);

  const filteredProducts = useMemo(() => {
    const query = posSearch.toLowerCase().trim();
    return products.filter(p => p.name.toLowerCase().includes(query) || p.sku.toLowerCase().includes(query));
  }, [products, posSearch]);

  const addToCart = (p: Product, variant?: GroupingPrice | Offer) => {
    const isOffer = variant && 'startDate' in variant;
    const isGrouping = variant && 'quantity' in variant && !isOffer;
    const unitsPerPack = isGrouping ? (variant as GroupingPrice).quantity : 1;
    const minToBuy = isGrouping ? (variant as GroupingPrice).minOrderQuantity : 1;
    const pricePerUnit = variant ? variant.price : p.unitPrice;

    if (p.stock < unitsPerPack * minToBuy) {
      alert("No hay suficiente stock.");
      return;
    }

    const vId = variant ? variant.id : 'unit';
    const itemId = `${p.id}-${vId}`;
    const existing = cart.find(i => i.id === itemId);

    if (existing) {
      setCart(cart.map(item => item.id === itemId ? { 
        ...item, 
        quantity: item.quantity + 1, 
        unitQuantity: (item.quantity + 1) * unitsPerPack, 
        total: (item.quantity + 1) * unitsPerPack * pricePerUnit 
      } : item));
    } else {
      const initUnits = minToBuy * unitsPerPack;
      setCart([...cart, {
        id: itemId, productId: p.id, productName: p.name, groupingId: vId,
        groupingLabel: variant?.label || 'Unidad Suelta', quantity: minToBuy, price: pricePerUnit,
        total: initUnits * pricePerUnit, currency: variant?.currency || p.unitCurrency,
        unitQuantity: initUnits
      }]);
    }
  };

  const removeFromCart = (id: string) => setCart(cart.filter(item => item.id !== id));

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? (i.total || 0) : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? (i.total || 0) : 0), 0);
    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Consumidor Final',
      items: [...cart], totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'SOL' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };
    if (status === 'Despachado') {
      setProducts(prev => prev.map(p => {
        const sold = cart.filter(i => i.productId === p.id).reduce((a, b) => a + (b.unitQuantity || 0), 0);
        return { ...p, stock: Math.max(0, (p.stock || 0) - sold) };
      }));
    }
    setTransactions(prev => [newTx, ...prev]);
    setCart([]);
    setSelectedInvoice(newTx);
  };

  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'catalog' | 'reception', onSave: (p: any) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<any>(initialData || {
      name: '', description: '', stock: 0, costPrice: 0, unitPrice: 0, unitCurrency: 'CUP', groupings: [], transportCost: 0
    });
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 1, price: 0, currency: 'CUP', minOrderQuantity: 1 });

    const isCatalog = mode === 'catalog';

    const handleNameSearch = (name: string) => {
      setFormData((prev: any) => ({ ...prev, name }));
      if (mode === 'reception') {
        const match = products.find(p => p.name.toLowerCase() === name.toLowerCase());
        if (match) {
          setFormData((prev: any) => ({ 
            ...prev, 
            description: match.description, 
            sku: match.sku, 
            unitPrice: match.unitPrice, 
            costPrice: match.costPrice,
            unitCurrency: match.unitCurrency,
            groupings: match.groupings
          }));
        }
      }
    };

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div className="md:col-span-2 lg:col-span-1">
              <label className="block text-sm font-black text-[#3E2723] uppercase mb-2 tracking-wide">Nombre del Producto</label>
              <input 
                value={formData.name} 
                onChange={e => handleNameSearch(e.target.value)} 
                className="w-full p-4 border-2 border-[#D7CCC8] rounded-lg text-lg font-black text-gray-900 focus:border-[#3E2723] outline-none transition-all shadow-sm"
                placeholder="Ej: Aceite de Girasol"
                list="p-list"
              />
              <datalist id="p-list">{products.map(p => <option key={p.id} value={p.name}/>)}</datalist>
            </div>

            <div className="p-4 bg-emerald-50 border-2 border-emerald-100 rounded-lg">
              <label className="block text-xs font-black text-emerald-700 uppercase mb-2 tracking-wide">{mode === 'reception' ? 'Unidades Recibidas' : 'Stock en Sistema'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value) || 0})} className="w-full p-3 border-2 border-emerald-200 rounded-md text-xl font-black text-emerald-900 bg-white"/>
            </div>

            <div className="p-4 bg-[#F5F5DC] border-2 border-[#D7CCC8] rounded-lg">
              <label className="block text-xs font-black text-[#3E2723] uppercase mb-2 tracking-wide">Costo Unitario (CUP)</label>
