              let list = [...products];
              let updatedProduct: Product;

              const newLot: ReceptionLot = {
                id: Math.random().toString(),
                date: new Date().toISOString(),
                supplierId: 'Gral',
                receptionType: 'Compra Directa',
                quantityReceived: p.stock,
                currentStock: p.stock,
                unitCost: p.costPrice,
                transportCost: p.transportCost || 0,
                totalInvestment: (p.stock * p.costPrice) + (p.transportCost || 0)
              };

              if (idx > -1) {
                updatedProduct = { 
                  ...list[idx], 
                  stock: (list[idx].stock || 0) + p.stock, 
                  costPrice: p.costPrice,
                  lots: [...(list[idx].lots || []), newLot]
                };
                list[idx] = updatedProduct;
              } else {
                updatedProduct = { 
                  ...p, 
                  id: Math.random().toString(), 
                  sku: `PA-${Date.now().toString().slice(-4)}`, 
                  groupings: [], 
                  lots: [newLot] 
                } as Product;
                list = [updatedProduct, ...list];
              }

              setProducts(list);
              setReceptionHistory(prev => [{
                id: newLot.id,
                date: newLot.date,
                productName: updatedProduct.name,
                quantity: newLot.quantityReceived,
                cost: newLot.unitCost,
                transportCost: newLot.transportCost
              }, ...prev]);

