const Statistics: React.FC<StatisticsProps> = ({ products, transactions, contacts }) => {
  const despachadas = transactions.filter(t => t.status === 'Despachado');
  const totalSalesCup = useMemo(() => despachadas.reduce((acc, t) => acc + (t.totalCup || 0), 0), [despachadas]);

  const totalUnitsSold = useMemo(() => {
    return despachadas.reduce((acc, t) => acc + t.items.reduce((s, i) => s + (i.unitQuantity || 0), 0), 0);
  }, [despachadas]);

  const inventoryValue = useMemo(() => products.reduce((a, b) => a + ((b.stock || 0) * (b.costPrice || 0)), 0), [products]);

  return (
    <div className="space-y-6 animate-in fade-in pb-10">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-6 border rounded shadow-sm">
           <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded flex items-center justify-center mb-4"><TrendingUp size={20}/></div>
           <p className="text-[9px] font-black uppercase text-gray-400 mb-1">Caja Histórica (CUP)</p>
           <p className="text-2xl font-black text-[#3E2723]">${(totalSalesCup || 0).toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 border rounded shadow-sm">
           <div className="w-10 h-10 bg-[#3E2723] text-white rounded flex items-center justify-center mb-4"><Package size={20}/></div>
           <p className="text-[9px] font-black uppercase text-gray-400 mb-1">Unidades Vendidas</p>
           <p className="text-2xl font-black text-[#3E2723]">{(totalUnitsSold || 0).toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 border rounded shadow-sm">
           <div className="w-10 h-10 bg-amber-50 text-amber-600 rounded flex items-center justify-center mb-4"><BarChart3 size={20}/></div>
           <p className="text-[9px] font-black uppercase text-gray-400 mb-1">Valor Inventario</p>
           <p className="text-2xl font-black text-[#3E2723]">${(inventoryValue || 0).toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 border rounded shadow-sm">
           <div className="w-10 h-10 bg-[#AF6E4D] text-white rounded flex items-center justify-center mb-4"><Target size={20}/></div>
           <p className="text-[9px] font-black uppercase text-gray-400 mb-1">Productos en Catálogo</p>
           <p className="text-2xl font-black text-[#3E2723]">{(products.length || 0).toLocaleString()}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
         <div className="bg-white p-6 border rounded shadow-sm">
            <h3 className="text-xs font-black text-[#3E2723] uppercase mb-6 flex items-center gap-3 border-b pb-4"><Activity size={18} className="text-[#AF6E4D]"/> Top Productos Vendidos</h3>
            <div className="space-y-4">
               {products.map(p => {
                 const sold = despachadas.reduce((acc, t) => acc + t.items.filter(i => i.productId === p.id).reduce((s, i) => s + (i.unitQuantity || 0), 0), 0);
                 if (sold === 0) return null;
                 return (
                   <div key={p.id} className="flex justify-between items-center text-xs border-b border-gray-50 pb-2">
                      <span className="font-bold uppercase text-gray-600">{p.name}</span>
                      <span className="font-black text-[#3E2723]">{(sold || 0).toLocaleString()} Unidades</span>
                   </div>
                 );
               })}
               {totalUnitsSold === 0 && <p className="text-[10px] text-center text-gray-300 uppercase py-20">Sin datos de ventas</p>}
            </div>
         </div>

         <div className="bg-[#3E2723] p-8 rounded text-white shadow-lg">
            <h3 className="text-[10px] font-black uppercase tracking-[0.2em] mb-8 text-[#AF6E4D]">Liquidación de Proveedores</h3>
