                   <div>
                      <p className="text-xs font-black uppercase">{prov.name}</p>
                      <p className="text-[9px] text-white/40 uppercase">Pendiente de Liquidar</p>
                   </div>
                   <p className="text-xl font-black text-emerald-400">${(prov.pendingBalanceCup || 0).toLocaleString()}</p>
                </div>
              ))}
              {contacts.filter(c => c.type === 'Proveedor').length === 0 && <p className="text-[9px] opacity-30 text-center py-10">No hay proveedores registrados</p>}
            </div>
         </div>
      </div>
    </div>
  );
};

