            </div>

            <div className="p-6 bg-white border-2 border-[#2B1B17] shadow-[6px_6px_0px_#B46E2A]">
              <label className="block text-xs font-black text-[#2B1B17] uppercase mb-4 tracking-widest">Precios de Venta Público</label>
              <div className="flex gap-4">
                <div className="flex-1">
                  <span className="text-[10px] font-bold text-gray-400 block mb-1">Precio Unitario</span>
                  <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value) || 0})} className="w-full p-3 border-2 border-[#2B1B17] text-2xl font-black text-[#B46E2A]"/>
                </div>
                <div className="w-24">
                  <span className="text-[10px] font-bold text-gray-400 block mb-1">Moneda</span>
