                <div>
                  <div className="flex justify-between items-start mb-4">
                    <span className="text-[10px] font-black text-white bg-[#B46E2A] px-3 py-1 uppercase tracking-widest">{p.sku || 'SKU'}</span>
                    <button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="text-gray-400 hover:text-[#2B1B17]"><Edit2 size={18}/></button>
                  </div>
                  <h3 className="font-black text-[#2B1B17] uppercase text-sm leading-tight mb-2 line-clamp-2">{p.name}</h3>
                  <p className="text-[10px] text-gray-400 font-bold uppercase mb-4 line-clamp-2">{p.description}</p>
                </div>
                <div className="border-t-2 border-gray-100 pt-4 mt-auto flex justify-between items-end">
                  <div>
                    <p className="text-[8px] font-black text-gray-400 uppercase mb-1">P. Unitario</p>
                    <p className="text-2xl font-black text-[#2B1B17] tracking-tighter">${(p.unitPrice || 0).toLocaleString()} <span className="text-[10px] text-[#B46E2A]">{p.unitCurrency}</span></p>
                  </div>
