              <button onClick={() => setProductModal({ show: false, mode: 'catalog' })} className="text-gray-300 hover:text-red-600 p-2"><X size={32} /></button>
            </div>
            <ProductForm mode={productModal.mode} initialData={productModal.product} onSave={p => {
              setProducts(prev => {
                const idx = prev.findIndex(x => x.id === p.id || x.name.toLowerCase() === p.name.toLowerCase());
                let list = [...prev];
                if (idx > -1) list[idx] = { ...list[idx], ...p };
                else list = [{ ...p, id: Math.random().toString(), sku: `PA-${Date.now().toString().slice(-4)}`, lots: [] }, ...list];
                return list;
              });
              setProductModal({ show: false, mode: 'catalog' });
            }} onCancel={() => setProductModal({ show: false, mode: 'catalog' })} />
          </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

