  const nearingExpiry = products.filter(p => {
    if (!p.expiryDate) return false;
    const diff = new Date(p.expiryDate).getTime() - new Date().getTime();
    return (diff / (1000 * 3600 * 24)) <= 60 && diff > 0;
  });

  const totalSalesCup = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((a, b) => a + (b.totalCup || 0), 0), [transactions]);
  const totalSalesUsd = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((a, b) => a + (b.totalUsd || 0), 0), [transactions]);

  const stats = [
    { label: 'Caja (CUP)', value: totalSalesCup.toLocaleString(), icon: Wallet, color: 'text-[#B46E2A]', bg: 'bg-[#B46E2A]/10' },
    { label: 'Caja (USD)', value: totalSalesUsd.toLocaleString(), icon: DollarSign, color: 'text-[#2B1B17]', bg: 'bg-[#2B1B17]/10' },
    { label: 'Stock Crítico', value: lowStockProducts.length, icon: AlertCircle, color: 'text-red-600', bg: 'bg-red-50' },
