                  <div className="flex items-center gap-4 p-4 bg-[#FFF9F2] border-2 border-[#2B1B17]">
                    <Phone className="text-[#B46E2A]" /> <span className="font-black text-sm">{config.phone}</span>
                  </div>
                  <div className="flex items-center gap-4 p-4 bg-[#FFF9F2] border-2 border-[#2B1B17]">
                    <MapPin className="text-[#B46E2A]" /> <span className="font-black text-sm">{config.address}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
