               <Package size={40} className="text-[#B46E2A] mb-4" />
               <h4 className="font-black uppercase text-sm mb-2">Logística Directa</h4>
               <p className="text-xs text-white/60">Importación y distribución optimizada para el mercado local.</p>
            </div>
