            <div className="hidden lg:flex items-center gap-2 border-l-4 border-[#EADBC8] pl-6 h-6">
               <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
               <span className="text-[9px] font-black text-[#B46E2A] uppercase tracking-widest">En Línea</span>
            </div>
            <img src="./logo.jpeg" alt="PaTí" className="h-10 w-auto object-contain md:hidden" onError={(e) => e.currentTarget.style.display='none'} />
