        <main className="flex-1 overflow-y-auto bg-[#FFF9F2] custom-scrollbar max-w-full overflow-x-hidden">
          <div className="p-4 md:p-10 h-full">{children}</div>
        </main>
      </div>
    </div>
  );
};

