const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [receptionHistory, setReceptionHistory] = useState<any[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'catalog' | 'reception'}>({show: false, mode: 'catalog'});
  const [contactModal, setContactModal] = useState<{show: boolean, contact?: Contact}>({show: false});
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [isCartVisibleMobile, setIsCartVisibleMobile] = useState(false);

  // 1. CARGA INICIAL (Solo una vez)
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const rh = localStorage.getItem(STORAGE_KEYS.RECEPTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (rh) setReceptionHistory(JSON.parse(rh));
    if (cfg) setConfig(JSON.parse(cfg));

    // Marcamos como listo DESPUÉS de cargar todo para evitar que el primer guardado borre lo anterior
    setTimeout(() => setIsDataReady(true), 500);
  }, []);

  // 2. GUARDADO AUTOMÁTICO (Solo si isDataReady es true)
  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.RECEPTIONS, JSON.stringify(receptionHistory));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, receptionHistory, config, isDataReady]);

  // FUNCIONES DE SALVA Y RESTAURA (Mantenimiento)
  const exportAllData = () => {
    const allData = { products, contacts, transactions, receptionHistory, config };
    const blob = new Blob([JSON.stringify(allData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `backup_pati_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const importAllData = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = JSON.parse(e.target?.result as string);
        if (data.products) setProducts(data.products);
        if (data.contacts) setContacts(data.contacts);
        if (data.transactions) setTransactions(data.transactions);
        if (data.receptionHistory) setReceptionHistory(data.receptionHistory);
        if (data.config) setConfig(data.config);
        alert("¡Datos restaurados con éxito!");
      } catch (err) {
        alert("Error al procesar el archivo. Asegúrate de que es un backup válido.");
      }
    };
    reader.readAsText(file);
  };

  const filteredProducts = useMemo(() => {
    const query = posSearch.toLowerCase().trim();
    return products.filter(p => p.name.toLowerCase().includes(query) || (p.sku && p.sku.toLowerCase().includes(query)));
  }, [products, posSearch]);

  const addToCart = (p: Product) => {
    if (p.stock <= 0) {
      alert("¡Stock insuficiente!");
      return;
    }
    const existing = cart.find(i => i.productId === p.id);
    if (existing) {
      setCart(cart.map(item => item.productId === p.id ? { 
        ...item, 
        quantity: item.quantity + 1, 
        unitQuantity: item.unitQuantity + 1,
        total: (item.quantity + 1) * p.unitPrice 
      } : item));
    } else {
      setCart([...cart, {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        quantity: 1, price: p.unitPrice, total: p.unitPrice, currency: p.unitCurrency,
        unitQuantity: 1
      }]);
    }
  };

  const processSale = () => {
    if (cart.length === 0) return;
    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Público',
      items: [...cart], totalCup: cart.reduce((acc, i) => acc + i.total, 0), totalUsd: 0,
      paymentMethod: 'Efectivo', status: 'Despachado', invoiceNumber: `FA-${Date.now().toString().slice(-5)}`
    };
    setProducts(prev => prev.map(p => {
      const sold = cart.find(i => i.productId === p.id)?.unitQuantity || 0;
      return { ...p, stock: Math.max(0, p.stock - sold) };
    }));
    setTransactions(prev => [newTx, ...prev]);
    setCart([]);
    setIsCartVisibleMobile(false);
    alert("Venta procesada exitosamente.");
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={[]} onNotificationRead={() => {}}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'about' && (
        <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in py-8 px-4">
          <div className="bg-white border-4 border-[#2B1B17] shadow-[10px_10px_0px_#B46E2A] p-6 md:p-12">
            <div className="flex flex-col md:flex-row gap-12 items-center">
              <div className="w-48 h-48 p-4 bg-white border-4 border-[#2B1B17] flex items-center justify-center shrink-0 shadow-lg">
                <img src="./logo.jpeg" alt="Logo PaTí" className="max-w-full max-h-full object-contain" onError={(e) => e.currentTarget.src='https://via.placeholder.com/300?text=PaTí'} />
              </div>
              <div className="flex-1 space-y-6 text-center md:text-left">
                <h2 className="text-4xl font-black text-[#2B1B17] uppercase tracking-tighter leading-none">{config.storeName}</h2>
                <p className="text-lg font-medium text-gray-700 leading-relaxed italic border-l-0 md:border-l-8 border-[#B46E2A] md:pl-6">"{config.aboutText}"</p>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 pt-4">
                  <div className="flex items-center gap-4 p-4 bg-[#FFF9F2] border-2 border-[#2B1B17]">
                    <Phone className="text-[#B46E2A]" size={20} /> <span className="font-black text-xs">{config.phone}</span>
                  </div>
                  <div className="flex items-center gap-4 p-4 bg-[#FFF9F2] border-2 border-[#2B1B17]">
                    <MapPin className="text-[#B46E2A]" size={20} /> <span className="font-black text-xs line-clamp-1">{config.address}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'catalog' && (
        <div className="space-y-8 animate-in fade-in py-4 px-4">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end border-b-8 border-[#2B1B17] pb-6 gap-6">
            <h2 className="text-3xl md:text-5xl font-black text-[#2B1B17] uppercase tracking-tighter">Catálogo</h2>
            <button onClick={() => setProductModal({ show: true, mode: 'catalog' })} className="w-full sm:w-auto bg-[#2B1B17] text-white px-8 py-4 font-black text-xs uppercase flex items-center justify-center gap-4 shadow-[4px_4px_0px_#B46E2A] active:translate-y-1"><Plus size={20}/> Nuevo Item</button>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {products.map(p => (
              <div key={p.id} className="bg-white border-4 border-[#2B1B17] shadow-[6px_6px_0px_#EADBC8] p-5 hover:shadow-[10px_10px_0px_#B46E2A] transition-all flex flex-col group">
                <div className="flex justify-between items-start mb-4">
                  <span className="text-[9px] font-black bg-[#B46E2A] text-white px-3 py-1 uppercase">{p.sku || 'N/A'}</span>
                  <button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="p-2 border-2 border-[#2B1B17] bg-white hover:bg-black hover:text-white transition-colors"><Edit2 size={14}/></button>
                </div>
                <h3 className="font-black text-[#2B1B17] uppercase text-sm mb-2 line-clamp-1">{p.name}</h3>
                <div className="mt-auto pt-4 border-t-2 border-dashed border-[#2B1B17] flex justify-between items-end">
                  <div>
                    <p className="text-[8px] font-black text-gray-400 uppercase mb-1">Precio</p>
                    <p className="text-2xl font-black text-[#2B1B17] tracking-tighter">${p.unitPrice.toLocaleString()}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-gray-400 uppercase mb-1">Stock</p>
                    <p className={`text-xl font-black ${p.stock <= p.minStock ? 'text-red-600' : 'text-green-700'}`}>{p.stock}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in py-4 px-4 overflow-x-hidden">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end border-b-8 border-[#2B1B17] pb-6 gap-6">
            <h2 className="text-3xl md:text-5xl font-black text-[#2B1B17] uppercase tracking-tighter">Inventario</h2>
            <div className="bg-[#2B1B17] text-white p-5 shadow-[6px_6px_0px_#B46E2A] text-right w-full md:w-auto">
              <p className="text-[9px] font-black uppercase opacity-60 tracking-widest mb-1">Capital en Stock</p>
              <p className="text-3xl font-black tracking-tighter">${products.reduce((a,b) => a + (b.stock * b.costPrice), 0).toLocaleString()}</p>
            </div>
          </div>
          <div className="bg-white border-4 border-[#2B1B17] shadow-xl overflow-x-auto custom-scrollbar max-w-full">
            <table className="w-full text-left border-collapse min-w-[600px]">
              <thead className="bg-[#2B1B17] text-white text-[10px] font-black uppercase tracking-widest">
                <tr><th className="p-5">Producto</th><th className="p-5 text-center">Físico</th><th className="p-5 text-center">Costo</th><th className="p-5 text-center">Venta</th><th className="p-5 text-right">Edit</th></tr>
              </thead>
              <tbody className="divide-y-4 divide-[#FFF9F2] text-sm font-black text-[#2B1B17]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#FFF9F2]">
                    <td className="p-5"><p className="font-black uppercase">{p.name}</p></td>
                    <td className={`p-5 text-center text-3xl font-black ${p.stock <= p.minStock ? 'text-red-600' : 'text-black'}`}>{p.stock}</td>
                    <td className="p-5 text-center text-gray-400 tabular-nums">${p.costPrice.toLocaleString()}</td>
                    <td className="p-5 text-center text-[#B46E2A] tabular-nums">${p.unitPrice.toLocaleString()}</td>
                    <td className="p-5 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="p-3 border-2 border-[#2B1B17] hover:bg-black hover:text-white transition-colors"><Edit2 size={16}/></button></td>
                  </tr>
                ))}
