                 <p className="text-xs font-bold text-gray-400 uppercase">Usa estas opciones para mover tus datos a otro dispositivo o crear copias de seguridad.</p>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                 <button onClick={exportAllData} className="flex flex-col items-center gap-4 p-8 border-4 border-[#2B1B17] hover:bg-[#FFF9F2] transition-colors group">
