                 <label className="flex flex-col items-center gap-4 p-8 border-4 border-[#2B1B17] border-dashed hover:bg-[#FFF9F2] transition-colors group cursor-pointer">
                    <Upload size={32} className="text-blue-600 group-hover:scale-110 transition-transform"/>
                    <span className="font-black uppercase text-xs">Importar Backup</span>
                    <input type="file" accept=".json" onChange={importAllData} className="hidden" />
                 </label>
              </div>

              <div className="bg-amber-50 border-2 border-amber-200 p-6 flex gap-4">
                 <AlertCircle className="text-amber-600 shrink-0" size={24}/>
                 <p className="text-[10px] font-bold text-amber-800 uppercase leading-relaxed">Nota: Importar un archivo reemplazará toda la información actual (productos, ventas y contactos) con los datos del backup.</p>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'config' && (
        <div className="max-w-4xl mx-auto py-8 px-4">
           <div className="bg-white border-4 border-[#2B1B17] shadow-[10px_10px_0px_#B46E2A] p-6 md:p-10 space-y-10">
              <h2 className="text-3xl font-black text-[#2B1B17] uppercase tracking-tighter border-b-8 border-[#B46E2A] pb-4 inline-block">Ajustes PaTí</h2>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase block">Nombre de Tienda</label>
                    <input value={config.storeName} onChange={e => setConfig({...config, storeName: e.target.value})} className="w-full p-4 border-2 border-[#2B1B17] font-black" />
                 </div>
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase block">Teléfono</label>
                    <input value={config.phone} onChange={e => setConfig({...config, phone: e.target.value})} className="w-full p-4 border-2 border-[#2B1B17] font-black" />
                 </div>
                 <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase block">Misión / Acerca de</label>
                    <textarea value={config.aboutText} onChange={e => setConfig({...config, aboutText: e.target.value})} className="w-full p-4 border-2 border-[#2B1B17] font-medium h-24" />
                 </div>
              </div>
              <button onClick={() => alert("Ajustes guardados localmente.")} className="w-full py-5 bg-[#2B1B17] text-white font-black uppercase text-xs tracking-widest shadow-[6px_6px_0px_#B46E2A]">Actualizar Perfil</button>
           </div>
        </div>
      )}

      {/* MODAL DE PRODUCTO */}
      {productModal.show && (
        <div className="fixed inset-0 bg-black/95 z-[500] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl h-full md:h-[85vh] shadow-2xl overflow-hidden flex flex-col border-t-[15px] border-[#2B1B17]">
            <div className="p-6 border-b-2 border-gray-100 flex justify-between items-center bg-[#FFF9F2]">
              <h2 className="text-sm font-black uppercase text-[#2B1B17]">Detalle de Producto</h2>
              <button onClick={() => setProductModal({ show: false, mode: 'catalog' })} className="text-gray-300 hover:text-black"><X size={32} /></button>
            </div>
            <ProductForm mode={productModal.mode} initialData={productModal.product} onSave={p => {
              setProducts(prev => {
                const idx = prev.findIndex(x => x.id === p.id);
                let list = [...prev];
                if (idx > -1) list[idx] = { ...list[idx], ...p } as Product;
                else list = [{ ...p, id: Math.random().toString(), sku: `SK-${Date.now().toString().slice(-4)}` } as Product, ...list];
                return list;
              });
              setProductModal({ show: false, mode: 'catalog' });
            }} onCancel={() => setProductModal({ show: false, mode: 'catalog' })} />
          </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

