import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, SaleItem, StoreConfig, ReceptionType 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, 
  Save, Truck, ShoppingCart, Package,
  Download, Upload, Database, Tag, 
  Users, UserPlus, Phone, MapPin, AlertCircle, ChevronRight,
  TrendingUp, DollarSign, Wallet
} from 'lucide-react';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v15_products',
  CONTACTS: 'pati_v15_contacts',
  TRANSACTIONS: 'pati_v15_transactions',
  RECEPTIONS: 'pati_v15_receptions',
  CONFIG: 'pati_v15_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "logo.jpeg",
  storeName: "PaTí",
  aboutText: "Conectamos productos de calidad con familias cubanas. Gestión total de inventarios en consignación y compra directa con transparencia absoluta.",
  address: "Habana Vieja, Cuba",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "", instagramUrl: "", websiteUrl: ""
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'catalog' | 'reception'}>({show: false, mode: 'catalog'});
  const [contactModal, setContactModal] = useState<{show: boolean, contact?: Contact}>({show: false});
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [isCartVisibleMobile, setIsCartVisibleMobile] = useState(false);

  // --- PERSISTENCIA REAL ---
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (cfg) setConfig(JSON.parse(cfg));

    setTimeout(() => setIsDataReady(true), 400);
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  // --- BACKUP & RESTORE ---
  const exportData = () => {
    const data = { products, contacts, transactions, config };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.products) setProducts(data.products);
        if (data.contacts) setContacts(data.contacts);
        if (data.transactions) setTransactions(data.transactions);
        if (data.config) setConfig(data.config);
        alert("Restauración exitosa.");
      } catch {
        alert("Archivo inválido.");
      }
    };
    reader.readAsText(file);
  };

  // --- LOGICA DE VENTAS ---
  const addToCart = (p: Product) => {
    if (p.stock <= 0) return alert("Sin stock disponible.");
    const existing = cart.find(i => i.productId === p.id);
    if (existing) {
      setCart(cart.map(i => i.productId === p.id ? { ...i, quantity: i.quantity + 1, total: (i.quantity + 1) * p.unitPrice, unitQuantity: i.unitQuantity + 1 } : i));
    } else {
      setCart([...cart, { 
        id: Math.random().toString(), productId: p.id, productName: p.name, 
        quantity: 1, price: p.unitPrice, total: p.unitPrice, currency: p.unitCurrency, unitQuantity: 1 
      }]);
    }
  };

  const finalizeSale = () => {
    if (cart.length === 0) return;
    const newTx: Transaction = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      clientId: 'Gral',
      clientName: 'Público General',
      items: [...cart],
      totalCup: cart.reduce((acc, i) => acc + i.total, 0),
      totalUsd: 0,
      paymentMethod: 'Efectivo',
      status: 'Despachado',
      invoiceNumber: `FAC-${Date.now().toString().slice(-6)}`
    };

    // Descontar stock
    setProducts(prev => prev.map(p => {
      const soldItem = cart.find(i => i.productId === p.id);
      return soldItem ? { ...p, stock: p.stock - soldItem.unitQuantity } : p;
    }));

    setTransactions([newTx, ...transactions]);
    setCart([]);
    setIsCartVisibleMobile(false);
    alert("Venta realizada.");
  };

  const filteredProducts = useMemo(() => {
    return products.filter(p => p.name.toLowerCase().includes(posSearch.toLowerCase()) || p.sku.toLowerCase().includes(posSearch.toLowerCase()));
  }, [products, posSearch]);

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={[]} onNotificationRead={() => {}}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'about' && (
        <div className="max-w-5xl mx-auto py-10 px-4 space-y-12 animate-in fade-in">
          <div className="bg-white border-4 border-[#2B1B17] shadow-[15px_15px_0px_#B48D51] p-10 flex flex-col md:flex-row gap-12 items-center">
            <div className="w-56 h-56 bg-white border-4 border-[#2B1B17] p-2 shrink-0 shadow-lg">
              <img src="./logo.jpeg" alt="Logo PaTí" className="w-full h-full object-contain" onError={(e) => e.currentTarget.src='https://via.placeholder.com/300?text=PaTí'} />
            </div>
            <div className="space-y-6">
              <h2 className="text-5xl font-black text-[#2B1B17] uppercase tracking-tighter">{config.storeName}</h2>
              <p className="text-xl font-medium text-gray-700 italic border-l-8 border-[#B48D51] pl-6 leading-relaxed">"{config.aboutText}"</p>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="p-4 bg-[#FFF9F2] border-2 border-[#2B1B17] flex items-center gap-4"><Phone className="text-[#B48D51]"/><span className="font-black text-sm">{config.phone}</span></div>
                <div className="p-4 bg-[#FFF9F2] border-2 border-[#2B1B17] flex items-center gap-4"><MapPin className="text-[#B48D51]"/><span className="font-black text-sm">{config.address}</span></div>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'catalog' && (
        <div className="space-y-8 py-6 px-4">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end border-b-8 border-[#2B1B17] pb-6 gap-6">
            <div>
              <h2 className="text-4xl font-black text-[#2B1B17] uppercase tracking-tighter">Catálogo Maestro</h2>
              <p className="text-xs font-black text-[#B48D51] uppercase tracking-widest mt-2">Productos en Gestión</p>
            </div>
            <button onClick={() => setProductModal({show: true, mode: 'catalog'})} className="bg-[#2B1B17] text-white px-8 py-4 font-black text-xs uppercase shadow-[5px_5px_0px_#B48D51] flex items-center gap-3 active:translate-y-1 active:shadow-none"><Plus/> Nuevo Registro</button>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {products.map(p => (
              <div key={p.id} className="bg-white border-4 border-[#2B1B17] p-5 shadow-[6px_6px_0px_#EADBC8] hover:shadow-[10px_10px_0px_#B48D51] transition-all flex flex-col group">
                <div className="flex justify-between mb-4">
                  <span className="text-[10px] font-black bg-[#B48D51] text-white px-2 py-1 uppercase">{p.sku}</span>
                  <button onClick={() => setProductModal({show: true, product: p, mode: 'catalog'})} className="p-2 border-2 border-[#2B1B17] hover:bg-[#2B1B17] hover:text-white"><Edit2 size={14}/></button>
                </div>
                <h3 className="font-black text-lg uppercase truncate mb-1">{p.name}</h3>
                <p className="text-[10px] text-gray-400 font-bold h-8 line-clamp-2 uppercase">{p.description}</p>
                <div className="mt-auto pt-4 border-t-2 border-dashed border-gray-100 flex justify-between items-end">
                  <div><p className="text-[8px] font-black uppercase text-gray-400">Precio</p><p className="text-2xl font-black text-[#2B1B17] tracking-tighter">${p.unitPrice.toLocaleString()}</p></div>
                  <div className="text-right"><p className="text-[8px] font-black uppercase text-gray-400">Stock</p><p className={`text-xl font-black ${p.stock < p.minStock ? 'text-red-600' : 'text-green-700'}`}>{p.stock}</p></div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex flex-col lg:flex-row h-full gap-6 py-4 px-4 overflow-hidden">
          <div className="flex-1 flex flex-col gap-6 overflow-hidden">
            <div className="flex flex-col sm:flex-row justify-between items-center gap-4 border-b-4 border-[#2B1B17] pb-4">
              <h2 className="text-2xl font-black text-[#2B1B17] uppercase">Punto de Venta</h2>
              <div className="relative w-full sm:w-80">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-300" size={18}/>
                <input placeholder="BUSCAR PRODUCTO O SKU..." className="w-full pl-10 pr-4 py-3 border-4 border-[#2B1B17] font-black text-xs uppercase outline-none focus:bg-[#FFF9F2]" value={posSearch} onChange={e => setPosSearch(e.target.value)} />
              </div>
            </div>
            <div className="flex-1 overflow-y-auto grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 pr-2 custom-scrollbar">
              {filteredProducts.map(p => (
                <div key={p.id} className="bg-white border-4 border-[#2B1B17] p-4 flex flex-col justify-between hover:shadow-lg transition-all">
                  <div>
                    <h3 className="font-black text-sm uppercase truncate mb-1">{p.name}</h3>
                    <div className="flex justify-between text-[10px] font-black uppercase mb-4">
                      <span className="text-gray-400">En Almacén</span>
                      <span className={p.stock <= p.minStock ? 'text-red-600' : 'text-black'}>{p.stock} U.</span>
                    </div>
                  </div>
                  <button onClick={() => addToCart(p)} className="w-full py-3 bg-[#2B1B17] text-white font-black uppercase text-xs shadow-[3px_3px_0px_#B48D51] active:translate-y-1 active:shadow-none">${p.unitPrice.toLocaleString()} CUP</button>
                </div>
              ))}
            </div>
          </div>

          <div className={`fixed inset-0 z-[100] bg-black/80 lg:relative lg:inset-auto lg:z-auto lg:bg-transparent ${isCartVisibleMobile ? 'flex' : 'hidden'} lg:flex w-full lg:w-96 flex-col`}>
             <div className="bg-[#2B1B17] h-full lg:h-auto lg:flex-1 p-8 text-white flex flex-col shadow-2xl relative w-full max-w-lg ml-auto lg:max-w-none border-l-8 border-[#B48D51]">
                <button className="lg:hidden absolute top-4 left-4 p-2 bg-white/10" onClick={() => setIsCartVisibleMobile(false)}><X size={24}/></button>
                <h3 className="text-xs font-black uppercase tracking-[0.3em] mb-10 border-b-4 border-[#B48D51] pb-6 flex items-center gap-4">
                  <ShoppingCart size={24} className="text-[#B48D51]"/> Detalle del Pedido
                </h3>
                <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
                  {cart.length === 0 ? <div className="py-20 text-center opacity-20 uppercase font-black tracking-widest text-xs">Sin Productos</div> : cart.map(i => (
                    <div key={i.id} className="bg-white/5 p-4 border-2 border-white/10 flex justify-between items-center text-[11px]">
                      <div className="flex-1 pr-4">
                        <p className="font-black uppercase truncate">{i.productName}</p>
                        <p className="text-[9px] opacity-40 font-bold uppercase">x{i.quantity} Unidades</p>
                      </div>
                      <div className="flex items-center gap-4">
                        <p className="font-black text-lg tabular-nums">${i.total.toLocaleString()}</p>
                        <button onClick={() => setCart(cart.filter(x => x.id !== i.id))} className="text-red-400 p-2 hover:bg-red-400/20"><Trash2 size={16}/></button>
                      </div>
                    </div>
