                  <div className="md:col-span-2 space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Descripción</label><textarea id="p-desc" defaultValue={productModal.product?.description} className="w-full p-4 border-4 border-[#2B1B17] font-medium h-24" /></div>
                  <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Stock Actual</label><input id="p-stock" type="number" defaultValue={productModal.product?.stock} className="w-full p-4 border-4 border-[#2B1B17] font-black text-lg" /></div>
                  <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Costo Unitario</label><input id="p-cost" type="number" defaultValue={productModal.product?.costPrice} className="w-full p-4 border-4 border-[#2B1B17] font-black text-lg" /></div>
               </div>
               <div className="pt-10 flex flex-col sm:flex-row gap-6">
                  <button onClick={() => {
                     const name = (document.getElementById('p-name') as HTMLInputElement).value;
                     const price = Number((document.getElementById('p-price') as HTMLInputElement).value);
                     const stock = Number((document.getElementById('p-stock') as HTMLInputElement).value);
                     const cost = Number((document.getElementById('p-cost') as HTMLInputElement).value);
                     const desc = (document.getElementById('p-desc') as HTMLTextAreaElement).value;

                     if (productModal.product) {
                        setProducts(products.map(x => x.id === productModal.product?.id ? { ...x, name, unitPrice: price, stock, costPrice: cost, description: desc } : x));
                     } else {
                        setProducts([{ id: Math.random().toString(), name, unitPrice: price, stock, costPrice: cost, description: desc, sku: `SKU-${Date.now().toString().slice(-4)}`, unitCurrency: 'CUP', supplierId: '', receptionType: 'Compra Directa', categoryId: '', minStock: 5, expiryDate: '', receivedDate: new Date().toISOString(), lots: [], groupings: [], offers: [] }, ...products]);
                     }
                     setProductModal({show: false, mode: 'catalog'});
                  }} className="flex-1 py-6 bg-[#2B1B17] text-white font-black uppercase text-xs tracking-widest shadow-[8px_8px_0px_#B48D51] active:translate-y-1 active:shadow-none">Confirmar Cambios</button>
