import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, 
  SaleItem, StoreConfig, ReceptionType 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, 
  Truck, ShoppingCart, Package,
  Download, Upload, Database, Tag, 
  Users, UserPlus, Phone, MapPin, AlertCircle,
  DollarSign, Wallet, ArrowDownCircle, History,
  TrendingUp, BarChart3
} from 'lucide-react';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v16_products',
  CONTACTS: 'pati_v16_contacts',
  TRANSACTIONS: 'pati_v16_transactions',
  CONFIG: 'pati_v16_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: "logo.jpeg",
  storeName: "PaTí",
  aboutText: "Gestión integral de inventarios y ventas con transparencia absoluta para consignatarios.",
  address: "La Habana, Cuba",
  phone: "+53 5 123 4567",
  email: "ventas@pati.cu",
  facebookUrl: "", instagramUrl: "", websiteUrl: ""
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isDataReady, setIsDataReady] = useState(false);

  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product}>({show: false});
  const [receptionModal, setReceptionModal] = useState<{show: boolean, product?: Product}>({show: false});
  const [contactModal, setContactModal] = useState<{show: boolean, contact?: Contact}>({show: false});
  const [posSearch, setPosSearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [isCartVisibleMobile, setIsCartVisibleMobile] = useState(false);

  // --- PERSISTENCIA ---
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (cfg) setConfig(JSON.parse(cfg));

    setTimeout(() => setIsDataReady(true), 300);
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  // --- BACKUP ---
  const handleExport = () => {
    const data = { products, contacts, transactions, config };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `pati_data_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        setProducts(data.products || []);
        setContacts(data.contacts || []);
        setTransactions(data.transactions || []);
        setConfig(data.config || DEFAULT_CONFIG);
        alert("Sincronización completa.");
      } catch { alert("Error en archivo."); }
    };
    reader.readAsText(file);
  };

  // --- VENTAS ---
  const addToCart = (p: Product) => {
    if (p.stock <= 0) return alert("Stock agotado.");
    const existing = cart.find(i => i.productId === p.id);
    if (existing) {
      setCart(cart.map(i => i.productId === p.id ? { ...i, quantity: i.quantity + 1, total: (i.quantity + 1) * p.unitPrice, unitQuantity: i.unitQuantity + 1 } : i));
    } else {
      setCart([...cart, { 
        id: Math.random().toString(), productId: p.id, productName: p.name, 
        quantity: 1, price: p.unitPrice, total: p.unitPrice, currency: p.unitCurrency, unitQuantity: 1 
      }]);
    }
  };

  const finalizeSale = () => {
    if (cart.length === 0) return;
    const total = cart.reduce((acc, i) => acc + i.total, 0);
    const newTx: Transaction = {
      id: Math.random().toString(),
      date: new Date().toISOString(),
      clientId: 'Gral',
      clientName: 'Venta Mostrador',
      items: [...cart],
      totalCup: total,
      totalUsd: 0,
      paymentMethod: 'Efectivo',
      status: 'Despachado',
      invoiceNumber: `POS-${Date.now().toString().slice(-6)}`
    };

    setProducts(prev => prev.map(p => {
      const sold = cart.find(i => i.productId === p.id);
      return sold ? { ...p, stock: p.stock - sold.unitQuantity } : p;
    }));

    setTransactions([newTx, ...transactions]);
    setCart([]);
    setIsCartVisibleMobile(false);
    alert("Operación completada.");
  };

  // --- FILTROS ---
  const filteredProducts = useMemo(() => 
    products.filter(p => p.name.toLowerCase().includes(posSearch.toLowerCase()) || p.sku.toLowerCase().includes(posSearch.toLowerCase())), 
    [products, posSearch]
  );

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={[]} onNotificationRead={() => {}}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'catalog' && (
        <div className="space-y-8 py-6 px-4 animate-in fade-in">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end border-b-8 border-[#2B1B17] pb-8 gap-6">
            <div>
              <h2 className="text-5xl font-black text-[#2B1B17] uppercase tracking-tighter">Catálogo</h2>
              <p className="text-xs font-black text-[#B48D51] uppercase tracking-[0.3em] mt-2">Maestro de Productos</p>
            </div>
            <div className="flex gap-4 w-full sm:w-auto">
              <button onClick={() => setProductModal({show: true})} className="flex-1 sm:flex-none bg-[#2B1B17] text-white px-8 py-4 font-black text-xs uppercase shadow-[6px_6px_0px_#B48D51] hover:translate-y-1 hover:shadow-none transition-all flex items-center justify-center gap-2"><Plus size={18}/> Nuevo Producto</button>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
            {products.map(p => (
              <div key={p.id} className="bg-white border-4 border-[#2B1B17] p-6 shadow-[8px_8px_0px_#EADBC8] hover:shadow-[12px_12px_0px_#B48D51] transition-all flex flex-col group relative">
                <div className="flex justify-between items-start mb-6">
                  <span className="text-[10px] font-black bg-[#B48D51] text-white px-3 py-1 uppercase border-2 border-[#2B1B17]">{p.sku}</span>
                  <div className="flex gap-2">
                    <button onClick={() => setReceptionModal({show: true, product: p})} title="Recibir Stock" className="p-2 border-2 border-[#2B1B17] bg-[#FFF9F2] hover:bg-[#B48D51] hover:text-white"><ArrowDownCircle size={14}/></button>
                    <button onClick={() => setProductModal({show: true, product: p})} className="p-2 border-2 border-[#2B1B17] bg-[#FFF9F2] hover:bg-[#2B1B17] hover:text-white"><Edit2 size={14}/></button>
                  </div>
                </div>
                <h3 className="font-black text-xl text-[#2B1B17] uppercase truncate mb-2">{p.name}</h3>
                <div className="mt-auto pt-6 border-t-4 border-dashed border-[#FFF9F2] flex justify-between items-end">
                  <div>
                    <p className="text-[9px] font-black text-gray-400 uppercase mb-1">P. Venta</p>
                    <p className="text-3xl font-black text-[#2B1B17] tracking-tighter">${p.unitPrice.toLocaleString()}</p>
                  </div>
                  <div className="text-right">
