                <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Vínculo</label>
                  <select id="c-type" defaultValue={contactModal.contact?.type || 'Proveedor'} className="w-full p-4 border-4 border-[#2B1B17] font-black uppercase">
