                <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Dirección</label><input id="c-addr" defaultValue={contactModal.contact?.address} className="w-full p-4 border-4 border-[#2B1B17] font-black uppercase" /></div>
