                if (contactModal.contact) {
                  setContacts(contacts.map(x => x.id === contactModal.contact?.id ? { ...x, name, type, phone, address } : x));
                } else {
                  setContacts([{ id: Math.random().toString(), name, type, phone, address, contactName: '', email: '', pendingBalanceCup: 0, pendingBalanceUsd: 0 }, ...contacts]);
