               <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Costo Base (CUP)</label><input id="p-cost" type="number" defaultValue={productModal.product?.costPrice} className="w-full p-4 border-4 border-[#2B1B17] font-black text-2xl" /></div>
               <div className="md:col-span-2 space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Descripción / Observaciones</label><textarea id="p-desc" defaultValue={productModal.product?.description} className="w-full p-6 border-4 border-[#2B1B17] font-medium h-32" /></div>
            </div>
            <button onClick={() => {
              const name = (document.getElementById('p-name') as HTMLInputElement).value;
              const sku = (document.getElementById('p-sku') as HTMLInputElement).value;
              const price = Number((document.getElementById('p-price') as HTMLInputElement).value);
              const cost = Number((document.getElementById('p-cost') as HTMLInputElement).value);
              const desc = (document.getElementById('p-desc') as HTMLTextAreaElement).value;

              if (productModal.product) {
                setProducts(products.map(x => x.id === productModal.product?.id ? { ...x, name, sku, unitPrice: price, costPrice: cost, description: desc } : x));
              } else {
                setProducts([{ id: Math.random().toString(), name, sku, unitPrice: price, costPrice: cost, description: desc, stock: 0, minStock: 5, unitCurrency: 'CUP', supplierId: '', receptionType: 'Compra Directa', categoryId: '1', expiryDate: '', receivedDate: new Date().toISOString(), lots: [], groupings: [], offers: [] }, ...products]);
              }
              setProductModal({show: false});
            }} className="w-full mt-10 py-8 bg-[#2B1B17] text-white font-black uppercase text-xl shadow-[10px_10px_0px_#B48D51]">Guardar Cambios en Maestro</button>
          </div>
        </div>
      )}

      {/* Modal Recepción de Mercancía */}
      {receptionModal.show && (
        <div className="fixed inset-0 bg-black/95 z-[600] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl border-t-[20px] border-[#B48D51] shadow-2xl p-12 space-y-10 animate-in slide-in-from-bottom-10">
            <div className="flex justify-between items-center">
               <h3 className="text-4xl font-black uppercase text-[#2B1B17] tracking-tighter">Entrada de Mercancía</h3>
               <button onClick={() => setReceptionModal({show: false})} className="text-gray-300 hover:text-black"><X size={48}/></button>
            </div>
            <p className="font-black uppercase text-lg bg-[#FFF9F2] p-4 border-2 border-[#2B1B17]">Producto: {receptionModal.product?.name}</p>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
               <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Cantidad a Ingresar</label><input id="r-qty" type="number" className="w-full p-5 border-4 border-[#2B1B17] font-black text-3xl" /></div>
               <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Tipo de Recepción</label>
                 <select id="r-type" className="w-full p-5 border-4 border-[#2B1B17] font-black uppercase text-lg">
                   <option>Consignación</option>
                   <option>Compra Directa</option>
                 </select>
               </div>
               <div className="md:col-span-2 space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Proveedor / Consignatario</label>
                 <select id="r-prov" className="w-full p-5 border-4 border-[#2B1B17] font-black uppercase text-lg">
                   {contacts.filter(c => c.type === 'Proveedor').map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                   {contacts.filter(c => c.type === 'Proveedor').length === 0 && <option>Registrar Proveedor Primero</option>}
                 </select>
               </div>
            </div>
            <button onClick={() => {
              const qty = Number((document.getElementById('r-qty') as HTMLInputElement).value);
              const type = (document.getElementById('r-type') as HTMLSelectElement).value as ReceptionType;
              const provId = (document.getElementById('r-prov') as HTMLSelectElement).value;

              if (!receptionModal.product || qty <= 0) return;

              setProducts(products.map(p => p.id === receptionModal.product?.id ? { ...p, stock: p.stock + qty, receptionType: type } : p));

              if (type === 'Consignación') {
                 setContacts(contacts.map(c => c.id === provId ? { ...c, pendingBalanceCup: c.pendingBalanceCup + (qty * (receptionModal.product?.costPrice || 0)) } : c));
              }

              alert("Stock actualizado con éxito.");
              setReceptionModal({show: false});
            }} className="w-full py-8 bg-[#B48D51] text-white font-black uppercase text-xl shadow-[10px_10px_0px_#000] tracking-widest active:translate-y-2">Confirmar Recepción</button>
          </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

